INSERT INTO subjects (slug, name, icon, description) VALUES
  ('ab900', 'AB-900', '🏢', 'Microsoft 365 Copilot & Agent Administration'),
  ('lvn', 'LVN NCLEX-PN', '🩺', 'Licensed Vocational Nurse Exam Prep'),
  ('shrm', 'SHRM-CP', '👥', 'HR Certified Professional')
INSERT INTO questions (subject_slug, domain, question_text, options, correct_index, explanation) VALUES
  ('ab900', 'M365 Core', 'What is required to use Microsoft 365 Copilot?', '["A qualifying base M365 license (E3, E5, Business Standard, or Business Premium) PLUS the Microsoft 365 Copilot add-on license", "Any Microsoft 365 license, including Personal and Family plans", "A standalone Copilot license \u2014 no base M365 subscription is required", "A Microsoft 365 E5 license automatically includes Copilot at no extra cost"]', 0, 'Copilot requires TWO things: a qualifying base M365 plan AND the Copilot add-on (assigned per user). Personal and Family plans do NOT qualify. E5 qualifies as a base, but Copilot is still a separate add-on.'),
  ('ab900', 'M365 Core', 'Which service provides authentication, single sign-on, and conditional access for Microsoft 365 services including Copilot?', '["Microsoft Intune", "Microsoft Purview", "Microsoft Entra ID", "Microsoft Defender for Cloud"]', 2, 'Microsoft Entra ID (formerly Azure Active Directory) is the identity platform for M365. It handles authentication, MFA, SSO, and Conditional Access policies that control who can access Copilot and under what conditions.'),
  ('ab900', 'M365 Core', 'Which Microsoft 365 service hosts cloud-based email, shared calendars, and global address lists?', '["SharePoint in Microsoft 365", "Microsoft Teams", "OneDrive for Business", "Exchange Online"]', 3, 'Exchange Online is Microsoft''s cloud email service. It replaces on-premises Exchange servers and is a core M365 workload. Copilot reads and summarizes emails through Exchange Online via Microsoft Graph.'),
  ('ab900', 'M365 Core', 'An administrator needs to manage users, assign licenses, and access all Microsoft 365 admin centers from one place. Which URL should they visit?', '["portal.azure.com", "compliance.microsoft.com", "admin.microsoft.com", "copilot.cloud.microsoft"]', 2, 'admin.microsoft.com is the Microsoft 365 Admin Center — the central hub for user management, license assignment, and navigation to specialized admin centers for Exchange, Teams, SharePoint, Purview, and Copilot.'),
  ('ab900', 'M365 Core', 'What does Microsoft Graph provide to Microsoft 365 Copilot?', '["A data visualization dashboard for admin reports", "A unified API enabling Copilot to access organizational data (emails, files, meetings) while enforcing existing user permissions", "A security scanning service for SharePoint documents", "A graphing tool for creating org charts in Teams"]', 1, 'Microsoft Graph is the gateway to all M365 data. Copilot queries it in real-time to retrieve emails, files, calendar events, and Teams messages — always respecting the signed-in user''s existing permissions.'),
  ('ab900', 'M365 Core', 'A user wants their personal work files accessible from any device and available to Copilot. Which service stores these files?', '["SharePoint team sites", "Exchange Online", "OneDrive for Business", "Microsoft Teams file tabs"]', 2, 'OneDrive for Business is the per-user cloud storage included in M365. Copilot can access and reference OneDrive files when answering questions, respecting the file owner''s sharing settings.'),
  ('ab900', 'M365 Core', 'What is a Microsoft 365 tenant?', '["A temporary workspace created for individual project collaborators", "A dedicated, isolated instance of Microsoft 365 services for one organization", "A shared cloud environment used by multiple organizations simultaneously", "A licensing agreement between Microsoft and an individual user"]', 1, 'A tenant is your organization''s private, isolated slice of Microsoft 365 — its own users, data, configuration, and apps. Copilot interactions are bounded within the tenant and never cross into another organization''s data.'),
  ('ab900', 'M365 Core', 'An organization has 2,000 users who need Microsoft 365 Copilot licenses. What is the most efficient assignment method?', '["Manually assign the license to each user in the Admin Center", "Submit a support ticket to Microsoft for bulk assignment", "Use group-based licensing in Microsoft Entra ID to assign the license to a security group", "Ask each user to self-purchase the Copilot add-on"]', 2, 'Group-based licensing in Entra ID is the scalable approach — add users to a security group and the license assignment happens automatically. This scales to thousands of users and handles joiners/leavers dynamically.'),
  ('ab900', 'M365 Core', 'Which service manages and secures the devices employees use to access Microsoft 365 and Copilot?', '["Microsoft Purview", "Microsoft Entra ID", "Microsoft Intune", "Microsoft Defender XDR"]', 2, 'Microsoft Intune (part of Microsoft Endpoint Manager) manages device compliance — ensuring devices are encrypted, patched, and compliant before accessing M365 resources. Intune compliance status can gate Copilot access via Conditional Access.'),
  ('ab900', 'M365 Core', 'Which platform provides Copilot adoption analytics and usage reports to administrators?', '["Microsoft Defender for Cloud Apps", "Microsoft Viva Insights and the M365 Admin Center reports", "Microsoft Purview Audit Premium", "Microsoft Entra ID Sign-in logs"]', 1, 'Copilot usage data (active users, features used, prompts sent) is available in the M365 Admin Center under Reports → Usage, and deeper insights are available through Viva Insights for admins to track ROI and adoption.'),
  ('ab900', 'M365 Core', 'Copilot is embedded in Microsoft Teams to help users with which tasks?', '["Managing Teams Admin Center policies on behalf of admins", "Summarizing meetings, recapping missed chat messages, and assisting during live calls", "Configuring DLP policies for Teams channels", "Deploying agents to Teams users across the organization"]', 1, 'Copilot in Teams surfaces in meetings (real-time notes, action items), in chat (summarize a thread you missed), and in the Teams compose box. It''s one of the highest-adoption Copilot entry points for most organizations.'),
  ('ab900', 'M365 Core', 'An organization uses SharePoint team sites to store project files. How does this relate to Microsoft 365 Copilot?', '["SharePoint files cannot be accessed by Copilot due to security restrictions", "SharePoint is one of Copilot''s primary data sources \u2014 it indexes SharePoint content via Microsoft Graph to ground responses in organizational documents", "Copilot only uses OneDrive files, not SharePoint sites", "SharePoint must be replaced by Dataverse before Copilot can access documents"]', 1, 'SharePoint is a primary knowledge source for Copilot. When a user asks Copilot to ''find the Q3 project proposal,'' Copilot searches SharePoint (and other M365 sources) via Microsoft Graph, subject to the user''s existing permissions.'),
  ('ab900', 'M365 Core', 'What does the Microsoft Purview compliance solution govern in relation to Microsoft 365?', '["Device management and endpoint security", "Identity verification and multi-factor authentication policies", "Data governance including information protection, DLP, eDiscovery, records management, and audit", "Application deployment and update management for M365 apps"]', 2, 'Microsoft Purview is the umbrella compliance platform covering everything data-governance related: sensitivity labels, DLP policies, retention, eDiscovery, communication compliance, insider risk, and audit logs — all of which apply to Copilot interactions.'),
  ('ab900', 'M365 Core', 'Which Microsoft 365 admin center is specifically designed to manage Copilot settings, configure web search access, and view Copilot adoption data?', '["admin.microsoft.com (M365 Admin Center) only", "compliance.microsoft.com (Purview portal)", "copilot.cloud.microsoft (Copilot admin center)", "security.microsoft.com (Microsoft Defender portal)"]', 2, 'copilot.cloud.microsoft is the dedicated Copilot admin center. While the M365 Admin Center also has Copilot settings under Settings → Copilot, the dedicated portal at copilot.cloud.microsoft is the primary Copilot management experience.'),
  ('ab900', 'Data & Governance', 'A company wants to prevent employees from sharing credit card numbers or SSNs via email or Copilot responses. Which Purview feature should be configured?', '["Sensitivity labels", "Retention policies", "Data Loss Prevention (DLP) policies", "Information barriers"]', 2, 'DLP policies detect and block specific sensitive information types (credit cards, SSNs, health records). They apply across Exchange, Teams, SharePoint, and Copilot outputs — if Copilot would include sensitive data in a response, DLP can block or warn.'),
  ('ab900', 'Data & Governance', 'A document labeled ''Highly Confidential'' with encryption is in SharePoint. A user without access asks Copilot about its contents. What happens?', '["Copilot ignores sensitivity labels and reads all content by default", "Copilot decrypts the document temporarily to provide a summary", "Copilot respects existing permissions \u2014 the user cannot receive content from documents they are not authorized to access", "Copilot asks the document owner for permission before responding"]', 2, 'Copilot strictly respects M365 permissions and sensitivity labels. It acts on behalf of the signed-in user and can only surface content that user is already authorized to see. Sensitivity labels and SharePoint permissions are the source of truth.'),
  ('ab900', 'Data & Governance', 'An EU-based organization must ensure Microsoft 365 and Copilot interaction data is stored only in European data centers. What should be configured?', '["Conditional Access policies with geographic restrictions", "DLP policies with EU-specific templates", "Data residency commitments or Microsoft 365 Multi-Geo configuration", "Sensitivity labels with geographic metadata"]', 2, 'Data residency commitments and Multi-Geo allow organizations to specify where M365 data (including Copilot logs) is stored at rest. This is critical for GDPR compliance and data sovereignty requirements.'),
  ('ab900', 'Data & Governance', 'An investment bank must ensure its investment banking team and trading desk cannot communicate with each other in Teams, and Copilot must not surface content across these groups. Which feature handles this?', '["Sensitivity labels", "Retention policies", "Data Loss Prevention policies", "Information barriers"]', 3, 'Information barriers (IB) restrict communication between defined user segments for regulatory compliance (e.g., preventing insider trading conflicts). IB policies apply in Teams, SharePoint, and Copilot — Copilot won''t surface content across IB-restricted boundaries.'),
  ('ab900', 'Data & Governance', 'How long does Microsoft Purview Audit Standard retain audit logs by default?', '["30 days", "90 days", "180 days", "1 year"]', 1, 'Audit Standard provides 90-day log retention for user and admin activity — including Copilot interactions. Audit Premium extends this to 1 year (or 10 years with add-on) and adds intelligent insights for security investigations.'),
  ('ab900', 'Data & Governance', 'A legal team needs to search all Teams messages, emails, and Copilot interaction logs related to a pending lawsuit and preserve them from deletion. Which Purview feature should they use?', '["Communication compliance", "eDiscovery with legal hold", "Insider risk management", "Retention policies"]', 1, 'eDiscovery allows legal and compliance teams to search across M365 services (Exchange, Teams, SharePoint, Copilot logs) and place content on legal hold to prevent deletion. This is the primary tool for responding to litigation or regulatory requests.'),
  ('ab900', 'Data & Governance', 'Does Microsoft use prompts and responses from Microsoft 365 Copilot to train its foundation AI models?', '["Yes \u2014 all prompts and responses are used", "Yes \u2014 but only with explicit customer opt-in", "No \u2014 Microsoft does not use customer tenant content to train foundation AI models", "Only anonymized data is used, with no way to opt out"]', 2, 'Microsoft''s enterprise data protection commitments explicitly state that customer content (prompts, responses, documents) from M365 Copilot is not used to train foundation models. This is a key governance and privacy assurance for enterprise customers.'),
  ('ab900', 'Data & Governance', 'An employee is resigning and mass-downloading SharePoint files and emailing them externally. Which Purview feature is designed to detect this risky behavior?', '["eDiscovery", "Communication compliance", "Insider risk management", "Information barriers"]', 2, 'Insider risk management uses ML to detect potentially risky user behaviors like mass downloads, unusual data exfiltration, or sensitive file access patterns before resignation. It can also flag anomalous Copilot usage that suggests data aggregation risk.'),
  ('ab900', 'Data & Governance', 'An admin wants to ensure a Microsoft support engineer cannot access organizational content without explicit customer approval. Which feature provides this?', '["Conditional Access", "Customer Lockbox", "Privileged Identity Management", "Sensitivity labels"]', 1, 'Customer Lockbox requires organizations to explicitly approve any Microsoft engineer access to their content during support cases. All requests are logged in the audit trail, providing full accountability and customer control.'),
  ('ab900', 'Data & Governance', 'Copilot generates a document drawing content from a file labeled ''Confidential'' and another labeled ''General''. What sensitivity label will the output carry?', '["General \u2014 the least restrictive label is applied", "A new label created dynamically by Copilot", "Confidential \u2014 Copilot applies the most restrictive label from the source content", "No label \u2014 Copilot-generated content cannot inherit sensitivity labels"]', 2, 'Copilot inherits the most restrictive sensitivity label from the source content it references. If a response draws from a ''Confidential'' document, the output is treated as Confidential. This prevents label downgrade and maintains data protection.'),
  ('ab900', 'Data & Governance', 'An admin configures a policy to require MFA and a compliant device before any user can access Copilot. Which feature implements this?', '["Sensitivity labels in Microsoft Purview", "Data Loss Prevention policies", "Conditional Access in Microsoft Entra ID", "Insider risk management policies"]', 2, 'Conditional Access evaluates identity and device signals before granting access to resources. Policies can specifically target the Microsoft 365 Copilot app, requiring MFA, device compliance (Intune), or specific locations — making it the key security layer for Copilot access.'),
  ('ab900', 'Data & Governance', 'Which Purview feature monitors Teams messages and Copilot-generated communications for policy violations like discriminatory language or regulatory breaches?', '["Insider risk management", "Audit Premium", "Communication compliance", "Information barriers"]', 2, 'Communication compliance monitors communications for policy violations using ML classifiers. It can be configured to monitor Copilot prompts and responses — important for financial services firms and healthcare organizations with strict communication regulations.'),
  ('ab900', 'Data & Governance', 'What is the purpose of configuring retention policies for Copilot interaction logs?', '["To prevent Copilot from referencing documents older than a defined period", "To define how long Copilot prompt and response logs are retained or deleted for legal and compliance purposes", "To limit the size of documents Copilot can process in a session", "To archive Copilot conversations automatically to a SharePoint library"]', 1, 'Retention policies for Copilot interactions govern how long prompt/response logs are kept (for compliance) or deleted (for privacy). Organizations can configure Copilot interaction retention independently from email or file retention policies.'),
  ('ab900', 'Data & Governance', 'Which of Microsoft''s six responsible AI principles specifically addresses ensuring AI systems work fairly across all demographics and user groups?', '["Accountability", "Transparency", "Fairness", "Inclusiveness"]', 2, 'Fairness ensures AI systems don''t produce biased outputs that disadvantage certain groups. Know all six principles: Fairness, Reliability & Safety, Privacy & Security, Inclusiveness, Transparency, and Accountability.'),
  ('ab900', 'Data & Governance', 'Before a Copilot rollout, an admin is concerned that broadly shared SharePoint files could be surfaced to users who shouldn''t see them. What should be done FIRST?', '["Disable Copilot for all users until SharePoint is rebuilt", "Configure DLP policies to block all Copilot file access", "Audit SharePoint permissions and apply sensitivity labels to reduce oversharing risk", "Enable information barriers for all users as a precaution"]', 2, 'Oversharing is the #1 governance concern before a Copilot rollout. Copilot surfaces content based on existing permissions — if files are over-permissioned, Copilot makes that content easily discoverable. Auditing permissions and applying sensitivity labels is the recommended first step.'),
  ('ab900', 'Data & Governance', 'What is Privileged Identity Management (PIM) in Microsoft Entra ID primarily used for?', '["Managing sensitivity labels for documents accessed by privileged users", "Providing just-in-time, time-bound admin role activation to reduce permanent privilege exposure", "Monitoring all admin interactions with Copilot for audit purposes", "Restricting Copilot access exclusively to users with admin roles"]', 1, 'PIM implements just-in-time privilege — admin roles are activated only when needed, for a limited time, often requiring approval. This reduces the blast radius if an admin account is compromised, and is a best practice for securing Copilot admin roles.'),
  ('ab900', 'Data & Governance', 'Which Microsoft Purview audit solution provides extended log retention beyond 90 days and intelligent insights for security investigations?', '["Audit Standard", "Insider risk management", "Audit Premium", "Communication compliance"]', 2, 'Audit Premium extends retention to 1 year (or longer with add-on) and uses AI-driven intelligent insights to identify critical events. It''s recommended for organizations with regulatory requirements or active security investigations involving Copilot or M365 data.'),
  ('ab900', 'Data & Governance', 'Which responsible AI principle ensures users and stakeholders can understand how AI systems reach their outputs?', '["Fairness", "Transparency", "Reliability & Safety", "Accountability"]', 1, 'Transparency means AI systems should be understandable — users should know they''re interacting with AI, and outputs should include citations so users can verify information. Copilot cites the sources it references in responses, directly implementing this principle.'),
  ('ab900', 'Copilot', 'An admin wants to prevent Microsoft 365 Copilot from incorporating public internet search results in its responses. Where is this setting configured?', '["Microsoft Entra Admin Center \u2192 Security \u2192 Authentication methods", "Microsoft Purview \u2192 DLP policies \u2192 Copilot template", "Microsoft 365 Admin Center or Copilot admin center \u2014 toggle off ''Web search for Copilot''", "Teams Admin Center \u2192 Meeting policies \u2192 AI features"]', 2, 'Web content access for Copilot is toggled in Settings → Copilot in the M365 Admin Center, or in copilot.cloud.microsoft. Disabling it limits Copilot to only organizational data, which some regulated industries require.'),
  ('ab900', 'Copilot', 'What is ''grounding'' in Microsoft 365 Copilot?', '["The process of retraining the AI model on organizational-specific data", "Connecting Copilot''s LLM outputs to real, current organizational data from Microsoft Graph to produce relevant, accurate responses", "A security process that restricts Copilot to verified file types only", "The mechanism by which Copilot re-authenticates users before each response"]', 1, 'Grounding is what makes Copilot useful vs. a generic chatbot. Instead of relying solely on LLM training data, Copilot retrieves your actual emails, files, and chats via Microsoft Graph to ground its responses in real organizational context.'),
  ('ab900', 'Copilot', 'Where should an admin go to view which M365 apps Copilot is being used in and how many prompts employees are sending?', '["Microsoft Entra Admin Center \u2192 Sign-in logs", "Microsoft 365 Admin Center \u2192 Reports \u2192 Usage \u2192 Microsoft 365 Copilot", "Microsoft Purview \u2192 Audit search", "Copilot Studio \u2192 Analytics"]', 1, 'Copilot usage reports are in the M365 Admin Center under Reports → Usage. They show active users, feature adoption by app (Outlook, Teams, Word, etc.), and prompt volume. Viva Insights provides deeper analytics for business decision-making.'),
  ('ab900', 'Copilot', 'What adoption strategy does Microsoft recommend as the FIRST step when rolling out Microsoft 365 Copilot?', '["Deploy to all licensed users simultaneously to maximize impact", "Identify champion users in each department to drive organic adoption and share use cases", "Require all users to complete mandatory certification before access", "Begin deployment with C-suite executives only, then cascade down"]', 1, 'Champion-led adoption is Microsoft''s proven playbook for Copilot. Champions become internal experts and advocates in their departments, share real use cases, and create peer-to-peer learning — far more effective than top-down mandates.'),
  ('ab900', 'Copilot', 'How does Microsoft 365 Copilot access organizational data, and what ensures it only returns information the user is authorized to see?', '["Copilot has a master admin account that can access all organizational data, filtered by admin-configured rules", "Copilot uses Microsoft Graph, which enforces the signed-in user''s existing M365 permissions when retrieving data", "Copilot creates a temporary cached copy of all accessible content at the start of each session", "Copilot uses AI to predict which content the user should see based on their role"]', 1, 'Microsoft Graph enforces permissions — Copilot can only access data the signed-in user is already authorized to see. No elevation of privilege occurs. This means Copilot is only as powerful as the user''s existing access.'),
  ('ab900', 'Copilot', 'How does Microsoft Copilot for Security differ from Microsoft 365 Copilot?', '["They are identical products with different branding", "M365 Copilot is for productivity in M365 apps; Copilot for Security is a separate product for SOC analysts using Defender and Sentinel signals \u2014 requiring a separate license", "M365 Copilot includes all Copilot for Security features at no extra cost in E5 plans", "Copilot for Security is an agent built inside Copilot Studio for IT administrators"]', 1, 'These are two distinct products. M365 Copilot = productivity AI in Word/Excel/Teams/Outlook. Copilot for Security = SOC/analyst AI for threat hunting and incident response. They have separate licensing, separate data sources, and separate admin centers.'),
  ('ab900', 'Copilot', 'What is prompt governance for Microsoft 365 Copilot?', '["A training program that teaches users how to write effective prompts", "Administrative and policy controls (DLP, communication compliance) that govern what Copilot can be asked and what it can return", "A feature that auto-corrects poorly worded prompts before sending them to the AI model", "A Microsoft certification for users who demonstrate Copilot proficiency"]', 1, 'Prompt governance encompasses the admin controls — DLP policies (block sensitive data in Copilot outputs), communication compliance policies (monitor prompts/responses for violations) — that ensure Copilot is used within organizational and regulatory boundaries.'),
  ('ab900', 'Copilot', 'What is the purpose of prompt engineering training during a Copilot rollout?', '["To train the Copilot AI model on company-specific terminology", "To help administrators configure prompt governance and DLP policies", "To teach users how to write effective queries so Copilot returns accurate, relevant, and useful responses", "To certify users before they are allowed to access Copilot features"]', 2, 'Copilot''s output quality is directly tied to the quality of the prompt. Prompt engineering training teaches users to provide context, specify desired format/length, and use natural language effectively — turning Copilot from a novelty into a productivity multiplier.'),
  ('ab900', 'Copilot', 'An organization suspects an employee is using Copilot to aggregate and export sensitive HR records. Which feature provides the audit trail to investigate this?', '["Sensitivity labels \u2014 review which labels were applied to exported files", "Data residency logs from Microsoft''s data center", "Microsoft Purview Audit \u2014 search Copilot interaction logs for the user''s activity", "Conditional Access sign-in logs from Entra ID"]', 2, 'Microsoft Purview Audit captures Copilot prompts and responses (the queries a user sent and what data Copilot returned). Audit Premium provides longer retention and intelligent insights, making it the right tool for investigating potential misuse.'),
  ('ab900', 'Copilot', 'What does the Copilot admin center at copilot.cloud.microsoft primarily allow administrators to do?', '["Build and deploy custom Copilot agents using a drag-and-drop interface", "Manage Copilot settings (web search, pinned features), view usage analytics, and configure governance settings specific to Copilot", "Create sensitivity labels and DLP policies for Copilot interactions", "Manage user licenses and assign Copilot add-ons to individuals"]', 1, 'The Copilot admin center (copilot.cloud.microsoft) is the dedicated interface for Copilot configuration — enabling/disabling features, web content access, and viewing Copilot adoption analytics. License management stays in the M365 Admin Center; agent building is in Copilot Studio.'),
  ('ab900', 'Agents', 'What is Microsoft Copilot Studio?', '["The admin portal for managing Microsoft 365 Copilot licenses and settings", "A low-code platform for building, testing, and deploying custom AI agents that connect to specific data sources and can be deployed in Teams and other channels", "A developer SDK for writing Python scripts that extend Copilot", "A Microsoft product for creating PowerPoint presentations with AI assistance"]', 1, 'Copilot Studio is the low-code/no-code platform for building custom agents. Business users can create agents that answer questions from SharePoint sites or databases, trigger Power Automate workflows, and deploy to Teams — no developer required for basic scenarios.'),
  ('ab900', 'Agents', 'What is the key difference between a declarative agent and a custom engine agent?', '["Declarative agents can only be deployed to Teams; custom engine agents can be deployed to any channel", "Declarative agents extend M365 Copilot with a custom persona and knowledge sources, using Copilot''s LLM; custom engine agents use their own AI model for more complex scenarios", "Declarative agents require professional developers; custom engine agents are fully no-code", "Custom engine agents are free; declarative agents require a premium Copilot Studio license"]', 1, 'Declarative agents are the simpler option — they inherit M365 Copilot''s infrastructure and just add focused instructions and knowledge sources. Custom engine agents are for complex scenarios requiring custom AI models and orchestration, and are built by developers.'),
  ('ab900', 'Agents', 'After building and testing a custom agent in Copilot Studio, what step is required before it can be deployed organization-wide in Microsoft Teams?', '["Publish the agent to the public Microsoft App Store", "Email the agent package to all employees for manual sideloading", "A Teams administrator must approve the agent in the Teams Admin Center", "Submit the agent to Microsoft for independent certification"]', 2, 'Enterprise app governance requires Teams admin approval for org-wide agent deployments. This appears in Teams Admin Center → Manage Apps, where the admin can approve, block, or configure the agent for deployment to specific user groups.'),
  ('ab900', 'Agents', 'An agent in Copilot Studio is connected to a confidential SharePoint site. A user who does NOT have access asks the agent a question about its contents. What does the agent do?', '["The agent uses its admin service account credentials to access the site and answer", "The agent cannot surface content the user is not authorized to see", "The agent temporarily elevates the user''s permissions to retrieve the requested information", "The agent asks the user to log in with elevated credentials before proceeding"]', 1, 'This is a critical security principle: agents operate under the signed-in user''s permissions. No privilege elevation occurs. The agent cannot surface content from a SharePoint site the user doesn''t have access to — the same M365 security model applies.'),
  ('ab900', 'Agents', 'What makes an agent ''agentic'' — able to take actions rather than just answer questions?', '["Configuring sensitivity labels to allow the agent write access to M365 data", "Integrating the agent with Power Automate cloud flows to trigger automated workflows", "Publishing the agent to the Teams Admin Center for org-wide deployment", "Connecting the agent to Microsoft Graph for real-time data retrieval"]', 1, 'Power Automate is the action engine for Copilot Studio agents. By connecting a cloud flow, the agent can create tickets in ServiceNow, send approval emails, update Dataverse records, or post Teams messages — transforming a Q&A bot into an automated workflow assistant.'),
  ('ab900', 'Agents', 'An admin wants to block a specific third-party agent from being used across the entire organization in Teams. Where should they go?', '["Microsoft Purview Compliance Portal \u2192 Communication compliance", "Copilot Studio \u2192 Agent settings \u2192 Disable for tenant", "Microsoft 365 Admin Center \u2192 Integrated Apps or Teams Admin Center \u2192 Manage Apps", "Microsoft Entra Admin Center \u2192 Enterprise Applications \u2192 Disable sign-on"]', 2, 'Agent governance for Teams deployment goes through the Teams Admin Center (Manage Apps) and the M365 Admin Center (Integrated Apps). Admins can allow, block, or restrict agents to specific user groups from these locations.'),
  ('ab900', 'Agents', 'What is a knowledge source in a Copilot Studio agent?', '["A training dataset used to fine-tune the agent''s underlying AI model", "A connected data repository \u2014 such as a SharePoint site, website, or Dataverse table \u2014 that the agent uses to generate grounded, accurate responses", "A library of pre-written responses the agent selects from based on keyword matching", "A Microsoft-provided database of general business and industry knowledge"]', 1, 'Knowledge sources are what give agents their domain expertise. Instead of relying on general LLM knowledge, the agent retrieves content from connected sources (SharePoint, websites, files) to answer questions accurately. This is distinct from model training — the source data isn''t used to train the model.'),
  ('ab900', 'Agents', 'An organization wants to control which employees are allowed to create agents in Copilot Studio. Where should an admin configure this?', '["Microsoft 365 Admin Center \u2192 Integrated Apps \u2192 Copilot Studio permissions", "Teams Admin Center \u2192 App permission policies \u2192 Copilot Studio", "Power Platform Admin Center \u2192 Tenant settings for Copilot Studio (enable/disable by security group)", "Microsoft Purview \u2192 Insider risk policies \u2192 Agent creation monitoring"]', 2, 'Copilot Studio is part of the Power Platform ecosystem. The Power Platform Admin Center (admin.powerplatform.microsoft.com) is where admins control tenant-level settings including who can create and publish agents — by environment, security group, or user role.'),
  ('ab900', 'M365 Core', 'What is a Microsoft 365 Group and what resources does creating one automatically provision?', '["A security group used only to control SharePoint library permissions", "A unified membership object that automatically provisions a shared mailbox, shared calendar, SharePoint team site, Planner board, and Teams workspace \u2014 all governed by one group membership", "A distribution list for email routing that can later be upgraded to a Teams channel", "A group policy object that enforces Office desktop application settings"]', 1, 'Microsoft 365 Groups are the foundational membership layer for M365 collaboration. Creating a Team automatically provisions an M365 Group. Managing group membership controls access to ALL linked resources simultaneously — mailbox, site, Planner, and Teams.'),
  ('ab900', 'M365 Core', 'Which Microsoft Viva module aggregates learning content from LinkedIn Learning, Microsoft Learn, and third-party LMS platforms directly inside Microsoft Teams?', '["Viva Connections", "Viva Insights", "Viva Learning", "Viva Engage"]', 2, 'Viva Learning brings curated learning content into the flow of work within Teams. Managers can recommend courses, employees track completions, and Copilot can suggest relevant learning based on role and skill gaps.'),
  ('ab900', 'M365 Core', 'What tool is used to configure which Microsoft 365 Apps are installed, which update channel is used, and how updates are delivered across thousands of devices?', '["Windows Update for Business", "Office Deployment Tool (ODT) with a configuration XML \u2014 deployed via Intune or Configuration Manager", "The Microsoft 365 Admin Center Apps section only", "Microsoft Intune app protection policies"]', 1, 'The Office Deployment Tool (ODT) uses XML configuration files to specify install scope, update channel (Current, Monthly Enterprise, Semi-Annual Enterprise), and excluded apps. Intune or Configuration Manager deploys the ODT config at scale across the organization.'),
  ('ab900', 'M365 Core', 'At a high level, what does a Microsoft 365 E5 license add beyond what is included in E3?', '["More OneDrive storage and longer email retention only \u2014 no additional security features", "Advanced security via Microsoft Defender XDR, premium compliance via Purview Audit Premium, Microsoft Teams Phone System, and Microsoft Entra ID P2", "E5 adds the Microsoft 365 Copilot add-on license at no extra cost", "E5 is identical to E3 but removes the 300-user cap on Teams channels"]', 1, 'E3 covers full productivity apps plus Entra ID P1 and basic compliance. E5 adds Defender XDR (advanced threat protection), Purview Audit Premium, Entra ID P2 (PIM, Identity Protection), and Teams Phone System — making it the full-security, full-compliance enterprise tier.'),
  ('ab900', 'M365 Core', 'An administrator needs to prevent users from recording Teams meetings and transcribing calls. Where is this setting managed?', '["Microsoft Purview Compliance portal under Communication Compliance", "Teams Admin Center \u2014 Meeting policies (disable recording and transcription per user or org-wide)", "Microsoft Entra ID Conditional Access policies", "Microsoft 365 Admin Center \u2014 Settings \u2014 Org settings"]', 1, 'Meeting policies in the Teams Admin Center control per-user or global capabilities including cloud recording, live transcription, meeting scheduling, and lobby settings. Disabling recording and transcription in the meeting policy prevents users from exercising those features.'),
  ('ab900', 'M365 Core', 'What is the primary function of Exchange Online Protection (EOP) included with all Microsoft 365 email plans?', '["Encrypts all email at rest and in transit using S/MIME certificates", "Filters inbound and outbound email for spam, malware, and phishing before delivery or receipt", "Manages email retention schedules and applies litigation holds", "Provides unlimited email archiving via In-Place Archive mailboxes"]', 1, 'EOP is the baseline email security gateway included with every M365 mail plan. It provides anti-spam, anti-malware, and anti-phishing filtering. Microsoft Defender for Office 365 Plan 1 and Plan 2 layer additional advanced threat protection on top of EOP.'),
  ('ab900', 'M365 Core', 'An organization wants external vendors to access a specific SharePoint site by signing in with their work accounts, but the vendors should not be able to reshare content to others. Which combination of settings achieves this?', '["Set site sharing to Anyone (no sign-in required) and train vendors on resharing policy", "Set site sharing to New and existing guests (requires sign-in) and disable the option allowing guests to share items they do not own", "Set site sharing to Only people in your organization \u2014 vendors must be added as full employees", "Set site sharing to Existing guests only and block all external access at the tenant level"]', 1, 'New and existing guests requires authentication. Additionally disabling guest resharing (available in SharePoint site settings) prevents vendors from forwarding or sharing content to unauthorized parties — combining authentication with resharing control.'),
  ('ab900', 'M365 Core', 'Where does an M365 administrator go to view real-time and historical status for Exchange Online, Teams, and SharePoint services?', '["Azure Portal \u2014 Resource health blade", "Microsoft 365 Admin Center \u2014 Health \u2014 Service health", "Microsoft Defender portal \u2014 Incidents and alerts", "Microsoft Secure Score dashboard"]', 1, 'The Service Health dashboard in admin.microsoft.com shows active incidents, advisories, and post-incident reports for all M365 services. Administrators can configure email notifications for degradations, helping IT communicate proactively with the organization.'),
  ('ab900', 'M365 Core', 'What type of information does an administrator find in the Microsoft 365 Message Center?', '["Real-time security alerts about active threats targeting the tenant", "Advance notices about upcoming feature rollouts, service changes, and required admin actions from Microsoft", "End-user notifications about password expiration and mailbox quota warnings", "Live performance metrics and latency dashboards for M365 services"]', 1, 'The Message Center (admin.microsoft.com — Health — Message Center) is where Microsoft communicates planned changes, new feature releases, and any action administrators must take. Reviewing it regularly prevents surprise rollouts and compliance gaps.'),
  ('ab900', 'M365 Core', 'An administrator wants to govern who can create Power Automate flows and Copilot Studio agents within the organization. Which admin center handles these tenant-level controls?', '["Microsoft 365 Admin Center \u2014 Integrated Apps", "Teams Admin Center \u2014 Apps \u2014 Permission policies", "Power Platform Admin Center \u2014 tenant settings, environments, and DLP policies", "Microsoft Entra Admin Center \u2014 App registrations"]', 1, 'The Power Platform Admin Center (admin.powerplatform.microsoft.com) governs all low-code platform settings: which users can create environments, DLP connector policies for Power Automate flows, and Copilot Studio agent creation — all independent of Teams or M365 admin centers.'),
  ('ab900', 'M365 Core', 'What distinguishes Teams shared channels from standard or private channels?', '["Shared channels have no message history retention \u2014 all messages are deleted after 30 days", "Shared channels can include external users from other Microsoft 365 tenants without requiring them to switch tenants or log in as a guest", "Shared channels are only visible to members with the Teams Administrator role", "Shared channels replace SharePoint team sites with a dedicated file storage system"]', 1, 'Shared channels (Teams Connect) allow collaboration with people in other organizations directly from within your own Teams tenant. External collaborators appear as themselves — no guest account or tenant-switching required. The shared channel has its own SharePoint site.'),
  ('ab900', 'M365 Core', 'Microsoft 365 Lighthouse is designed for which type of administrator?', '["A single large enterprise managing thousands of users in one M365 tenant", "Managed Service Providers and IT partners managing multiple small and medium business M365 tenants from a single unified portal", "Microsoft Support engineers who manage global service health across all tenants", "Independent software vendors who publish integrations to the Microsoft 365 Marketplace"]', 1, 'Lighthouse lets MSP partners view security alerts, compliance status, user sign-in activity, and device health across all their customer tenants simultaneously. It enables proactive management at scale without logging into each tenant individually.'),
  ('ab900', 'M365 Core', 'A company wants external partners to collaborate in Teams without requiring them to create personal Microsoft accounts or be added as full employees. Which Microsoft Entra feature governs this?', '["Entra ID Privileged Identity Management (PIM)", "Microsoft Entra External ID \u2014 B2B collaboration, allowing partners to sign in with their own organizational identities", "Microsoft Intune device enrollment for contractor devices", "Microsoft Entra ID Conditional Access requiring corporate-issued certificates"]', 1, 'Entra External ID B2B collaboration allows external users to be invited as guests and authenticate with their own organizational accounts. They appear in your directory as guest users. Access can be governed by Conditional Access, expiring access reviews, and cross-tenant access settings.'),
  ('ab900', 'M365 Core', 'What is the purpose of Microsoft Intune device compliance policies in relation to Microsoft 365 Copilot access?', '["Compliance policies govern which sensitivity labels are applied to files accessed from enrolled devices", "Compliance policies define the minimum security requirements a device must meet (encryption, OS version, passcode) \u2014 Conditional Access can then block M365 and Copilot access from non-compliant devices", "Compliance policies set the maximum number of M365 licenses that can be activated per device", "Compliance policies replace the need for Entra ID user authentication when a compliant device is detected"]', 1, 'Intune compliance policies assess device health. Conditional Access in Entra ID checks the compliance result as a condition before granting access. This ensures users cannot reach Copilot or other M365 resources from unmanaged, unpatched, or non-encrypted devices.'),
  ('ab900', 'M365 Core', 'What additional threat protection does Microsoft Defender for Office 365 Plan 1 add on top of Exchange Online Protection?', '["Anti-spam and anti-malware filtering \u2014 identical to EOP with a different name", "Safe Links (real-time URL detonation), Safe Attachments (sandboxing of email attachments), and anti-phishing impersonation protection for domains and users", "Full endpoint detection and response (EDR) for Windows devices across the organization", "Unlimited email archiving and eDiscovery hold capabilities for all mailboxes"]', 1, 'Defender for Office 365 Plan 1 adds Safe Links (scans URLs at click-time, not just delivery), Safe Attachments (detonates attachments in a sandbox before delivery), and advanced anti-phishing (impersonation and spoof intelligence). Plan 2 adds Threat Explorer, attack simulation, and automated investigation.'),
  ('ab900', 'M365 Core', 'An organization has 800 users who need Microsoft 365 Copilot licenses. Licenses should be automatically assigned when users join the designated security group. What is the most scalable method?', '["Manually assign each Copilot add-on license in the M365 Admin Center user list", "Use group-based licensing in Microsoft Entra ID \u2014 assign the Copilot license to a security group and membership drives automatic assignment", "Ask each user to request a Copilot license via the Microsoft Store for Business self-service portal", "Submit a Microsoft support ticket requesting bulk license assignment for all 800 users"]', 1, 'Group-based licensing in Entra ID is the correct scalable approach. Add users to the security group and the Copilot add-on license is assigned automatically. Remove from the group and the license is reclaimed. This handles joiners and leavers dynamically without manual intervention.'),
  ('ab900', 'M365 Core', 'Which Microsoft 365 admin center is the correct destination for managing Teams app permission policies, dial plans, and call queues?', '["Microsoft Entra Admin Center", "Microsoft 365 Admin Center \u2014 Settings \u2014 Org settings", "Teams Admin Center (admin.teams.microsoft.com)", "Microsoft Purview Compliance portal"]', 1, 'The Teams Admin Center is the dedicated portal for all Teams-specific configuration: app permission and setup policies, meeting policies, voice (call queues, auto attendants, dial plans), messaging policies, and Teams lifecycle management. Each workload has its own specialized admin center.'),
  ('ab900', 'M365 Core', 'An organization wants to set an expiration policy so Microsoft 365 Groups (and their linked Teams, SharePoint sites, and mailboxes) are reviewed and renewed or deleted after 180 days of inactivity. Where is this configured?', '["SharePoint Admin Center \u2014 Site lifecycle management", "Microsoft 365 Admin Center \u2014 Groups \u2014 Expiration settings", "Microsoft Entra ID \u2014 Groups \u2014 Expiration policy", "Teams Admin Center \u2014 Teams lifecycle policies"]', 1, 'M365 Group expiration policies are configured in Microsoft Entra ID under Groups — Expiration. Owners receive renewal notifications before expiration. If not renewed, the group and all associated resources (Teams, SharePoint site, mailbox) are soft-deleted, reducing sprawl.'),
  ('ab900', 'M365 Core', 'What is the primary benefit of SharePoint hub sites in a Microsoft 365 deployment?', '["Hub sites provide isolated storage containers that prevent content from one department being indexed by search", "Hub sites connect related SharePoint team sites so navigation, branding, and search are unified across the hub \u2014 enabling org-wide content discovery without merging site permissions", "Hub sites replace Microsoft Teams team sites for organizations with more than 500 users", "Hub sites automatically apply sensitivity labels to all documents uploaded to connected team sites"]', 1, 'Hub sites aggregate related sites (department sites, project sites) under a shared navigation and search scope. Users searching from the hub find content across all connected sites. Permissions remain independent — hub association does not change who can access what on individual sites.'),
  ('ab900', 'Data & Governance', 'What is the key difference between a sensitivity label and a retention label in Microsoft Purview?', '["They are interchangeable \u2014 both protect content and govern how long it is kept", "Sensitivity labels classify and protect content (encryption, access restrictions, visual markings) based on confidentiality; retention labels govern content lifecycle (keep for N years, auto-delete, declare as a record)", "Retention labels are applied by users manually; sensitivity labels are always applied by automated policies", "Sensitivity labels apply only to email; retention labels apply only to SharePoint documents"]', 1, 'These serve entirely different purposes. Sensitivity = protection (who can see and use the content). Retention = lifecycle (how long the content must be kept or when it must be deleted). Both can coexist on the same document to address both protection and compliance requirements simultaneously.'),
  ('ab900', 'Data & Governance', 'An organization wants the Purview system to automatically apply a Confidential sensitivity label to any SharePoint document containing passport numbers — without relying on users to label manually. Which feature enables this?', '["Manually applied labels enforced through a mandatory labeling policy requiring user selection", "Auto-labeling policies configured with sensitive information types that scan and label content in SharePoint, OneDrive, and Exchange automatically", "DLP policies that apply sensitivity labels as a remediation action when violations are detected", "Trainable classifiers that flag content for an admin to review and label in bulk"]', 1, 'Auto-labeling policies use sensitive information types (like passport number patterns) to scan and automatically apply labels to content in SharePoint, OneDrive, and Exchange — no user action required. Simulation mode lets admins preview which content would be labeled before turning the policy on.'),
  ('ab900', 'Data & Governance', 'Microsoft Purview Compliance Manager provides which primary capability to help organizations meet compliance obligations?', '["A real-time stream of active security incidents and threat actors targeting the tenant", "A compliance score with recommended improvement actions mapped to regulatory frameworks such as GDPR, HIPAA, and ISO 27001 \u2014 helping organizations prioritize and track their compliance posture", "A low-code interface for building DLP policies across Exchange, SharePoint, and Teams", "An automated audit log that submits compliance evidence to regulatory bodies on behalf of the organization"]', 1, 'Compliance Manager quantifies compliance posture as a score, maps existing configurations to regulatory controls, and recommends specific actions to improve the score. It covers dozens of frameworks and helps organizations systematically close compliance gaps.'),
  ('ab900', 'Data & Governance', 'An admin wants to understand how much content labeled Highly Confidential exists across SharePoint and OneDrive without reading the actual files. Which Purview tool provides this?', '["eDiscovery content search \u2014 run a query filtered by sensitivity label", "Content Explorer \u2014 shows a snapshot of labeled and sensitive content locations and volumes without exposing file contents", "Activity Explorer \u2014 shows who applied or changed labels and when", "Compliance Manager \u2014 provides a breakdown of sensitive content by regulatory framework"]', 1, 'Content Explorer provides a read-only catalog view: how many files carry each sensitivity label, which sensitive information types appear where, and which workloads contain the most sensitive content. It gives a data landscape overview without opening or revealing individual file contents.'),
  ('ab900', 'Data & Governance', 'A healthcare organization must locate all documents containing patient names combined with medical record numbers across M365 to comply with HIPAA. Which Purview capability performs this automated classification?', '["Manual review by the compliance team using SharePoint search with custom KQL queries", "Sensitive information types built into Purview data classification \u2014 scanned across SharePoint, OneDrive, and Exchange via auto-labeling policy simulation", "eDiscovery legal hold applied to all SharePoint document libraries", "Communication compliance policies monitoring internal messaging for PHI patterns"]', 1, 'Purview includes built-in sensitive information types for HIPAA-relevant data patterns (medical record numbers, SSNs, patient names in context). Auto-labeling policy simulation identifies where this content lives without requiring manual review — forming the foundation of a HIPAA data inventory.'),
  ('ab900', 'Data & Governance', 'A financial firm must retain all employee email for 7 years per SEC Rule 17a-4. Which Purview feature should be configured?', '["Sensitivity labels with a 7-year expiration set on all email encryption policies", "A retention policy targeting Exchange Online mailboxes with a 7-year retention period set to preserve and then delete content", "eDiscovery legal holds applied to all Exchange mailboxes \u2014 holds have no expiration", "Communication compliance policies that archive copies of all emails for 7 years"]', 1, 'Retention policies define how long content is kept (preserve) and what happens after that period (delete or allow deletion). A 7-year retention policy for Exchange Online satisfies SEC retention requirements and ensures emails cannot be deleted prematurely while also enabling automatic cleanup after the period expires.'),
  ('ab900', 'Data & Governance', 'What does Microsoft Purview eDiscovery Premium add beyond the capabilities in eDiscovery Standard?', '["Premium adds the ability to apply legal holds \u2014 Standard only searches without preserving content", "Premium adds custodian tracking, review sets, near-duplicate and email thread analysis, predictive coding, and attorney-client privilege detection \u2014 designed for complex, large-scale litigation", "Premium adds real-time Copilot interaction logging; Standard does not capture Copilot prompts", "Premium can search Teams messages; Standard is limited to Exchange email only"]', 1, 'eDiscovery Standard provides case management, content search, and hold. Premium adds sophisticated litigation support: managing custodians (people of interest), collecting their data into review sets, AI-powered analytics (near-duplicate grouping, email threading), and predictive coding to reduce review volume by 70-90%.'),
  ('ab900', 'Data & Governance', 'Microsoft Secure Score is best described as:', '["The average response time for Microsoft support tickets over the past 90 days", "A quantified measure of an organization''s security posture based on implemented security controls, with prioritized recommendations to improve the score", "A compliance score calculated by Purview Compliance Manager based on regulatory framework adherence", "A performance benchmark comparing M365 service uptime against Microsoft''s SLA commitments"]', 1, 'Secure Score assigns points for implementing security controls (enabling MFA, configuring DLP policies, enabling risky sign-in detection). Higher score = stronger security stance. The portal provides prioritized recommendations ranked by impact and implementation difficulty, helping admins focus security investments.'),
  ('ab900', 'Data & Governance', 'What is the core principle of Zero Trust security architecture as applied to Microsoft 365?', '["Users on the corporate network are trusted by default; only external connections must be verified", "No implicit trust is granted to any user, device, or network location \u2014 every access request must be explicitly verified using identity signals, device health, and contextual conditions", "Zero Trust requires all users to use hardware security keys (FIDO2) \u2014 password authentication is not permitted", "Zero Trust applies only to privileged administrator accounts; regular users follow standard trust models"]', 1, 'Zero Trust replaces perimeter-based trust with continuous verification. In M365, this is implemented via Conditional Access: every sign-in request is evaluated against identity (who), device compliance (what), location (where), and risk (how risky) before access is granted — even for internal users on corporate networks.'),
  ('ab900', 'Data & Governance', 'A user attempts to save a document with a Confidential label as a draft with a General label (lower classification). The system prompts them for a justification. Which Purview capability produces this behavior?', '["Retention label immutability settings that prevent any label changes on classified documents", "Sensitivity label policy settings requiring a business justification when a user attempts to remove or downgrade a label to a less protective classification", "DLP policies that block document saves when the label changes", "Insider risk management policies that flag label downgrades as risky activity for review"]', 1, 'Sensitivity label policies can be configured to require justification for label removal or downgrade. The user must enter a reason (which is logged in the audit trail) before the change is allowed. This creates accountability, enables audit review, and discourages casual label downgrading.'),
  ('ab900', 'Data & Governance', 'Which Microsoft Purview feature uses machine learning to identify content categories such as resumes, contracts, and source code — content that cannot be reliably detected by regex pattern matching alone?', '["Keyword dictionaries applied to Exchange transport rules", "Trainable classifiers \u2014 ML models that understand content context and categorize documents based on characteristics learned from training examples", "Exact data match (EDM) using a custom sensitive data table", "Fingerprinting applied to standardized document templates"]', 1, 'Trainable classifiers go beyond pattern matching. Microsoft provides built-in classifiers (Resume, Project Documents, Source Code, Financial Statements, etc.) and organizations can train custom classifiers using their own labeled content samples to detect proprietary document types.'),
  ('ab900', 'Data & Governance', 'What is Exact Data Match (EDM) classification and when is it most appropriate?', '["A feature that performs exact-phrase full-text search across all SharePoint document libraries", "A classification method that matches content against a customer-provided sensitive data table (such as a patient SSN roster), producing near-zero false positives for highly specific sensitive records", "A sensitivity label type that applies bit-for-bit encryption matching the source document hash", "A DLP rule that only triggers when the exact filename of a known sensitive document is detected"]', 1, 'EDM creates sensitive information types based on YOUR actual data. Instead of matching all SSN patterns, it matches only the specific SSNs in your patient database. This eliminates false positives common with regex-based SITs. It is most appropriate for healthcare (patient records) and financial services (customer data).'),
  ('ab900', 'Data & Governance', 'Which Microsoft Purview feature is specifically designed to detect when an employee begins mass-downloading SharePoint files and sending them to personal email shortly before their resignation date?', '["eDiscovery with a custom search query for large file transfers", "Communication compliance policy monitoring for data exfiltration language", "Insider Risk Management \u2014 using behavioral analytics to detect data theft and exfiltration indicators", "Microsoft Defender for Cloud Apps \u2014 session policy blocking large downloads"]', 1, 'Insider Risk Management correlates signals across M365 (file downloads, email forwarding, Teams messages, endpoint activity) against behavioral baselines. Pre-resignation data exfiltration is a specific built-in policy template. It generates risk scores and alerts for security teams to investigate.'),
  ('ab900', 'Data & Governance', 'An organization uses a sensitivity label with Rights Management encryption on a document marked Confidential. A user forwards the document to an external party who is not authorized. What happens when the external party tries to open it?', '["The document opens normally since it was sent by an authorized internal user", "The external party cannot open the document \u2014 encryption enforces that only authorized users can decrypt and view the content, regardless of where the file travels", "The document opens in read-only mode, allowing the external party to view but not edit", "The file is automatically deleted from the external party''s mailbox by Exchange Online"]', 1, 'Rights Management encryption travels with the file. Authorization is checked at open-time against the Azure Rights Management service — not at delivery time. If the external recipient is not in the authorized list for that label, the decryption key is denied and the document cannot be opened, regardless of how it was received.'),
  ('ab900', 'Data & Governance', 'Which Purview feature monitors Microsoft Teams messages and Copilot-generated communications for policy violations such as discriminatory language, financial fraud indicators, or regulatory breaches?', '["Insider risk management \u2014 detects behavioral anomalies across M365 workloads", "Communication compliance \u2014 uses classifiers and keyword policies to monitor Teams, email, and Copilot interactions for policy violations", "eDiscovery Premium \u2014 provides litigation support and review sets for attorney review", "Audit Premium \u2014 captures all user and admin activity across M365 workloads"]', 1, 'Communication compliance applies policy rules (built-in classifiers for harassment, financial misconduct, etc. or custom keywords) to monitor communications. For regulated industries like financial services, this is required for FINRA and SEC compliance. It can be configured to specifically monitor Copilot prompts and responses.'),
  ('ab900', 'Data & Governance', 'What does the unified audit log in Microsoft 365 capture, and why is it relevant for Copilot governance?', '["Only administrator actions in M365 admin centers \u2014 user activity is not included in the unified audit log", "User and administrator actions across M365 services including Exchange, SharePoint, Teams, and Copilot interactions (prompts and responses) \u2014 providing a searchable record for security investigations and compliance reviews", "Only sign-in events from Microsoft Entra ID \u2014 file and application activity is tracked separately in Defender", "Audit logs are only available for the 90 days before the date of a compliance review request"]', 1, 'The unified audit log captures activity across all M365 services including Copilot interaction records (prompts, referenced sources, responses) with Audit Standard providing 90-day retention and Audit Premium extending to 1 year. This is the primary tool for investigating Copilot misuse or responding to regulatory inquiries.'),
  ('ab900', 'Data & Governance', 'An organization must ensure all Microsoft 365 and Copilot data for EU employees is stored exclusively in European Union data centers. Which mechanism addresses this?', '["Conditional Access policy restricting M365 access to EU IP address ranges only", "Microsoft 365 data residency commitments (Advanced Data Residency or Multi-Geo) specifying that tenant data is stored at rest in designated geographic regions", "Sensitivity labels with geographic metadata preventing non-EU users from accessing the data", "Azure Policy applied to the M365 tenant requiring EU region selection for all services"]', 1, 'Data residency commitments and Multi-Geo allow organizations to specify data-at-rest locations for M365 workloads. This is critical for GDPR compliance and data sovereignty regulations that require personal data to remain within specific geographic boundaries.'),
  ('ab900', 'Data & Governance', 'Which of Microsoft''s six Responsible AI principles addresses the requirement that AI systems should be understandable and that users should know how outputs are generated?', '["Fairness \u2014 ensuring AI outputs are unbiased across demographic groups", "Transparency \u2014 AI systems should be open about their nature and provide explainability about how they reach conclusions", "Accountability \u2014 humans should remain responsible for AI decisions", "Reliability and Safety \u2014 AI should perform consistently and as intended"]', 1, 'Transparency means users know they are interacting with AI, and outputs include citations so responses can be verified. Copilot''s practice of citing sources in responses directly implements the Transparency principle, enabling users to validate information rather than blindly trusting AI output.'),
  ('ab900', 'Data & Governance', 'Before a Copilot rollout, a governance team is concerned that ''Everyone'' sharing permissions on legacy SharePoint files could expose sensitive content to all Copilot users. What is the recommended FIRST governance step?', '["Disable Copilot for all users until every SharePoint file is relabeled", "Enable information barriers for all users as a precaution", "Run a SharePoint permissions audit, remediate oversharing, and apply sensitivity labels to high-value content \u2014 before Copilot goes live", "Configure DLP policies that block Copilot from accessing any SharePoint content"]', 1, 'Oversharing is the top governance risk before Copilot deployment. Copilot surfaces content based on existing permissions — if files are accessible to Everyone, Copilot makes that content trivially discoverable. Auditing and tightening SharePoint permissions is the required first step in Microsoft''s pre-deployment governance guidance.'),
  ('ab900', 'Copilot', 'What is the key difference between Microsoft Copilot Chat (with commercial data protection) and Microsoft 365 Copilot?', '["They are identical products \u2014 Copilot Chat is simply the new name for M365 Copilot as of 2024", "Copilot Chat provides a commercially protected AI chat experience but does not access M365 organizational data via Graph; M365 Copilot adds the Graph-grounded in-app experiences in Outlook, Teams, Word, Excel, and PowerPoint that require the paid add-on license", "Copilot Chat requires a premium license; M365 Copilot is included with all M365 Business plans at no extra cost", "Copilot Chat is only available on mobile devices; M365 Copilot is desktop-only"]', 1, 'Copilot Chat (included with qualifying M365 plans) provides commercial data protection but has no access to your organizational emails, files, or meetings. M365 Copilot (paid add-on) adds Graph-grounded in-app Copilot that references your actual work data — emails, Teams chats, SharePoint files — making it contextually aware of your organizational content.'),
  ('ab900', 'Copilot', 'A user asks Copilot in Word to draft a report based on a SharePoint document they have never opened. Can Copilot include content from that document?', '["Yes \u2014 Copilot has elevated access to all SharePoint content in the organization to maximize helpfulness", "Only if an administrator has explicitly granted Copilot read access to that specific document library", "No \u2014 Copilot operates under the signed-in user''s existing M365 permissions and cannot surface content the user is not authorized to access", "Yes, but Copilot will include a compliance warning noting the document requires additional review"]', 1, 'Copilot enforces the signed-in user''s existing permissions through Microsoft Graph. No privilege elevation occurs. If the user cannot open the document in SharePoint, Copilot cannot reference it. This is a fundamental security guarantee — Copilot is permission-bounded to the user''s current access.'),
  ('ab900', 'Copilot', 'What is Copilot Pages, and what productivity scenario does it support?', '["A SharePoint feature for building intranet pages using AI-generated content layouts", "A persistent, multiplayer canvas built on Microsoft Loop where Copilot Chat responses can be edited collaboratively, extended by team members, and shared as a living document", "A Copilot Studio feature for creating paginated FAQ pages in custom agents", "A Word template type optimized for Copilot-generated reports with automatic formatting"]', 1, 'Copilot Pages extends Copilot Chat output into a collaborative artifact. Send a Copilot response to a Page, invite teammates, and co-edit the AI-generated content in real time. Pages persist in Loop and are accessible across M365, turning ephemeral Copilot answers into ongoing team work products.'),
  ('ab900', 'Copilot', 'Microsoft''s Copilot adoption framework defines three phases. What are they and what does each phase focus on?', '["Plan, Deploy, Optimize \u2014 IT-centric phases focused on technical rollout and performance tuning", "Aware (leadership alignment and use case identification), Onboard (champion programs, initial deployment, and training), Drive Value (measuring business impact and expanding use cases)", "Pilot, Scale, Retire \u2014 a standard software lifecycle applied to Copilot deployment", "Buy, Enable, Train \u2014 phases focused on licensing procurement, technical enablement, and end-user certification"]', 1, 'Microsoft''s official Copilot Adoption Framework is Aware → Onboard → Drive Value. Aware gets stakeholder buy-in and identifies where Copilot solves real problems. Onboard deploys to early adopters with champion-led training. Drive Value measures ROI and expands use cases. This framework appears directly in AB-900 exam content.'),
  ('ab900', 'Copilot', 'An IT manager wants to know which Microsoft 365 applications Copilot is being actively used in and how many prompts are being sent per week. Where is this information found?', '["Microsoft Defender portal \u2014 Advanced hunting using custom KQL queries against Copilot activity tables", "Microsoft 365 Admin Center \u2014 Reports \u2014 Usage \u2014 Microsoft 365 Copilot report", "Microsoft Purview Audit \u2014 search for CopilotInteraction activity type", "Copilot Studio \u2014 Analytics dashboard for org-wide Copilot usage"]', 1, 'The M365 Copilot Usage report (admin.microsoft.com — Reports — Usage) shows active users over time, Copilot engagement by app (Teams, Outlook, Word, etc.), and feature usage rates. This data supports adoption tracking, ROI reporting to leadership, and identifying user groups that need additional training.'),
  ('ab900', 'Agents', 'What is a topic in Microsoft Copilot Studio, and why is it central to agent design?', '["A document or SharePoint page that has been added as a knowledge source to the agent", "A conversation flow triggered by matching user phrases, consisting of conditions, messages, and action nodes that define how the agent handles a specific type of user request", "A classification tag applied to agent responses for content moderation and audit logging", "A Microsoft-defined intent category used to route conversations to different agent instances"]', 1, 'Topics are the building blocks of Copilot Studio agents. Each topic has trigger phrases (what the user says) and a flow (what the agent does — responds, asks questions, takes actions). System topics handle fallback and escalation; custom topics handle your specific use cases.'),
  ('ab900', 'Agents', 'An agent built in Copilot Studio needs to look up live inventory data from a proprietary REST API when a user asks about product availability. How should this be implemented?', '["The agent cannot connect to external APIs \u2014 only Microsoft first-party data sources are supported in Copilot Studio", "Configure a Power Automate cloud flow that calls the REST API and returns the result; then call the flow as an action from within the agent topic", "Write a custom API connector directly in the topic editor using the built-in JavaScript code node", "Connect the REST API endpoint as a knowledge source in the agent configuration settings"]', 1, 'Power Automate is the action engine for Copilot Studio agents. The flow makes the API call, handles authentication, parses the response, and returns structured data back to the agent topic. This pattern supports any REST API, database, or external service without requiring pro-code development.'),
  ('ab900', 'Agents', 'What happens when a user''s question does not match any topic in a Copilot Studio agent and no knowledge source can answer it?', '["The agent displays a generic error message and terminates the conversation", "The agent silently ignores the query and waits for the user to rephrase", "The fallback system topic is triggered \u2014 the agent can offer a graceful message, search generative answers from knowledge sources, and optionally escalate to a human agent via live agent handoff", "The agent automatically creates a new topic based on the unmatched query and adds it to the topic list for future use"]', 2, 'The Fallback system topic handles queries that match no custom topic. Combined with generative answers enabled on a knowledge source, the agent can still attempt to answer dynamically. If it cannot, the Escalate system topic can transfer the user to a human agent via configured handoff channels.'),
  ('ab900', 'Agents', 'What is the generative answers feature in Copilot Studio, and how does it reduce the topic-authoring burden?', '["A feature that uses GPT to auto-generate new topics based on historical user conversation logs", "A capability allowing the agent to dynamically generate responses from connected knowledge sources (SharePoint, websites, uploaded files) for questions that do not match any pre-authored topic \u2014 without requiring a topic for every possible question", "A Microsoft-managed FAQ library that agents draw from when user queries match common IT support scenarios", "An auto-translation feature that answers user questions in their detected language using the knowledge source content"]', 1, 'With generative answers enabled, the agent uses the LLM to search connected knowledge sources and synthesize an answer in natural language — even for questions no topic was written to handle. This means builders can focus on authoring topics for complex workflows while the knowledge source handles informational FAQs automatically.'),
  ('ab900', 'Agents', 'What does the Test agent pane in Microsoft Copilot Studio allow a builder to do?', '["Publish the agent to a restricted group of 10 pilot users before organization-wide deployment", "Simulate conversations with the agent in real time, see exactly which topics and nodes are triggered at each step, and diagnose flow issues before publishing", "Run automated load testing to verify the agent handles 1,000 concurrent user sessions", "Validate that all knowledge source documents have been successfully indexed and are returning expected results"]', 1, 'The Test pane provides an interactive simulation of the agent in the same interface used to build it. Builders can type messages, see which topics fire, trace the conversation path node-by-node, and identify where flows break — all without publishing. The Track between topics toggle helps debug multi-topic handoffs.'),
  ('ab900', 'Agents', 'In Copilot Studio agent configuration, what does setting authentication to Microsoft (Entra ID) enable?', '["It requires the agent builder to have Global Administrator credentials before saving any changes", "It allows the agent to verify the identity of users interacting with it via their Entra ID sign-in, enabling user-specific responses, role-based data access, and personalized experiences", "It locks the agent to Microsoft-only data sources and prevents connecting to third-party APIs", "It automatically configures MFA for all users before they can start a conversation with the agent"]', 1, 'When authentication is set to Microsoft (Entra ID), the agent authenticates users via their M365 sign-in before the conversation starts. This enables the agent to identify who is asking, apply role-based logic, access data on behalf of the signed-in user, and provide personalized responses — essential for HR self-service or IT helpdesk agents.'),
  ('ab900', 'Agents', 'A healthcare IT team wants to deploy a Copilot Studio agent that answers staff questions about patient appointment schedules retrieved from an EMR system. What is the MOST critical pre-deployment consideration?', '["Ensuring the agent icon and greeting match the hospital branding guidelines", "Verifying that the EMR API integration uses authenticated connections, only authorized clinical staff can access the agent, all queries are logged in an audit trail, and data handling aligns with HIPAA Security Rule requirements", "Confirming the agent can handle at least 500 simultaneous conversations before go-live", "Checking that the agent has been reviewed and approved by Microsoft before any healthcare deployment"]', 1, 'Healthcare agents handling PHI must satisfy HIPAA Security Rule requirements: authenticated access controls (only authorized staff), encrypted data in transit (HTTPS/OAuth), comprehensive audit logging of all queries referencing PHI, and a Business Associate Agreement with Microsoft. These must be confirmed before any clinical deployment.'),
  ('lvn', 'Safe Care', 'A nurse receives a verbal order from a physician over the phone. What is the FIRST action the nurse should take?', '["Administer the medication immediately while documenting later", "Repeat the order back to the physician to confirm accuracy before documenting", "Ask a second nurse to verify the order before proceeding", "Refuse to accept verbal orders as they are not permitted"]', 1, 'Read-back verification is the standard for verbal/telephone orders. The nurse must repeat the order back to the prescriber and receive confirmation before acting. This prevents transcription errors and is a Joint Commission requirement.'),
  ('lvn', 'Safe Care', 'Which nursing action demonstrates proper implementation of the ''rights'' of medication administration?', '["Administering a medication prepared by a colleague to save time", "Checking the patient''s armband against the MAR and asking the patient to state their name and date of birth", "Crushing all oral medications together for ease of administration", "Delegating medication verification to unlicensed assistive personnel"]', 1, 'The rights of medication administration (right patient, right drug, right dose, right route, right time, right documentation, right reason) require the nurse to verify patient identity using at least two identifiers — armband plus verbal confirmation.'),
  ('lvn', 'Safe Care', 'A patient refuses a prescribed medication. What is the appropriate nursing response?', '["Administer the medication anyway since it is prescribed", "Crush the medication and hide it in food to ensure the patient receives it", "Document the refusal, notify the provider, and respect the patient''s right to refuse treatment", "Restrain the patient and administer the medication"]', 2, 'Competent adults have the legal and ethical right to refuse any treatment. The nurse must document the refusal, notify the prescriber, educate the patient about consequences, and chart the interaction. Administering medication without consent is assault and battery.'),
  ('lvn', 'Safe Care', 'Which action best demonstrates correct hand hygiene technique per CDC guidelines?', '["Using hand sanitizer for all situations including when hands are visibly soiled", "Washing hands with soap and water for at least 20 seconds, or using alcohol-based sanitizer when hands are not visibly soiled", "Wearing gloves eliminates the need for hand hygiene", "Rinsing hands with water alone is sufficient for routine patient care"]', 1, 'Hand hygiene is the single most effective infection prevention measure. Soap and water for 20 seconds is required when hands are visibly soiled or after C. diff exposure (spores resist alcohol). Alcohol-based sanitizer is acceptable otherwise.'),
  ('lvn', 'Safe Care', 'A nurse is preparing to delegate blood pressure monitoring to an unlicensed assistive personnel (UAP). Which patient would be INAPPROPRIATE to delegate this task to?', '["A 65-year-old stable post-surgical patient on day 2", "A patient who had their blood pressure checked 1 hour ago and it was normal", "A patient with a new order for IV vasopressors due to hemodynamic instability", "A patient with hypertension who is stable and awaiting discharge"]', 2, 'Delegation requires the ''5 Rights of Delegation'' — the task must be appropriate for delegation. A hemodynamically unstable patient receiving vasopressors requires ongoing nursing assessment, not just measurement. Unstable patients require RN/LVN direct assessment, not delegation.'),
  ('lvn', 'Safe Care', 'A client signs a consent form for surgery but later tells the nurse they want to change their mind. What should the nurse do?', '["Inform the client that signing the form is legally binding and they cannot withdraw consent", "Notify the surgeon immediately and document the client''s wishes", "Continue with the surgical preparation since the consent is already signed", "Convince the client to proceed since the surgery is medically necessary"]', 1, 'Informed consent is an ongoing process, not a one-time signature. Patients have the right to withdraw consent at any time. The nurse must immediately notify the surgeon and the surgical team and document the patient''s change of mind.'),
  ('lvn', 'Safe Care', 'Which Standard Precaution practice is required for ALL patient care, regardless of diagnosis?', '["Wearing a surgical mask for all patient interactions", "Donning an N95 respirator before entering any patient room", "Performing hand hygiene and using gloves when contact with blood or body fluids is anticipated", "Placing all patients in private rooms to prevent transmission"]', 2, 'Standard Precautions apply to all patients regardless of diagnosis, treating blood and all body fluids as potentially infectious. Hand hygiene plus gloves when contact with blood/body fluids is anticipated is the foundational practice.'),
  ('lvn', 'Safe Care', 'A nurse notes a discrepancy in the medication count at the beginning of a shift. What is the correct action?', '["Assume it was a counting error and proceed with the shift", "Document the count as correct to avoid paperwork", "Report the discrepancy to the charge nurse and pharmacy immediately, and complete an incident report", "Ask a colleague to recount and proceed if they agree"]', 2, 'Controlled substance discrepancies must be reported immediately per facility policy to the charge nurse and pharmacy. An incident report is required. Failure to report could imply diversion and is a license violation.'),
  ('lvn', 'Physiological Care', 'A nurse is caring for a post-operative patient who begins to show signs of hemorrhage. Which assessment finding is MOST indicative of early hemorrhage?', '["Systolic BP of 88 mmHg", "Urine output of 10 mL/hour", "Increasing heart rate (tachycardia) with restlessness and anxiety", "Decreased respiratory rate"]', 2, 'Tachycardia is the FIRST compensatory response to blood loss — the body increases heart rate to maintain cardiac output. Blood pressure drops LATER when compensation fails. Restlessness/anxiety from tissue hypoperfusion also appears early. Never wait for hypotension to suspect hemorrhage.'),
  ('lvn', 'Physiological Care', 'A patient with a hip fracture is placed in Buck''s traction. Which nursing intervention is the PRIORITY?', '["Ensuring the weights are resting on the floor for patient comfort", "Assessing skin integrity under the traction boot every 4 hours", "Removing the traction device for bathing every shift", "Positioning the patient in high Fowler''s position"]', 1, 'Buck''s traction is a skin traction used temporarily before hip surgery. The weights must hang freely (never rest on the floor) to maintain pull. Skin integrity assessment is the priority nursing action — the traction boot can cause skin breakdown and pressure injuries.'),
  ('lvn', 'Physiological Care', 'A patient has a nasogastric tube (NGT) for feeding. Before initiating each feeding, which action should the nurse perform FIRST?', '["Aspirate gastric contents and check pH to verify placement", "Flush the tube with 30 mL of water to clear any residue", "Begin the feeding at the prescribed rate", "Place the patient in supine position to prevent aspiration"]', 0, 'Verifying NGT placement before EVERY feeding is mandatory. Aspiration of gastric contents with pH testing (pH ≤ 5.5 confirms gastric placement) and/or X-ray confirmation is required. Undetected tube displacement into the lung and feeding can be fatal.'),
  ('lvn', 'Physiological Care', 'A patient with a urinary catheter develops a fever of 38.8°C, suprapubic pain, and cloudy, foul-smelling urine. The nurse suspects catheter-associated urinary tract infection (CAUTI). What is the PRIORITY intervention?', '["Irrigate the catheter with normal saline to clear the cloudy urine", "Notify the provider and anticipate an order to change or remove the catheter", "Increase the patient''s fluid intake to 3 liters per day", "Apply a heating pad to the suprapubic area"]', 1, 'The first priority for a suspected CAUTI is to notify the provider. The catheter should be removed as soon as it is no longer needed (or changed if still required) since the catheter is the source of infection. Urine culture should be obtained.'),
  ('lvn', 'Physiological Care', 'A nurse is caring for a patient with increased intracranial pressure (ICP). Which position should the nurse maintain?', '["Trendelenburg position (head down 15-30 degrees)", "Head of bed elevated 30 degrees with neck in neutral alignment", "Prone position to reduce posterior fossa pressure", "Flat supine to maximize cerebral perfusion pressure"]', 1, 'HOB 30 degrees with neutral neck alignment promotes venous drainage from the brain, reducing ICP. Trendelenburg and flat supine increase ICP by impeding venous return. Avoid extreme neck flexion or rotation which also increases ICP.'),
  ('lvn', 'Physiological Care', 'A patient receiving IV heparin has an activated partial thromboplastin time (aPTT) of 180 seconds (therapeutic range: 60-100 seconds). What is the priority nursing action?', '["Continue the infusion \u2014 this level is within range for deep vein thrombosis", "Increase the infusion rate to maintain therapeutic anticoagulation", "Stop the heparin infusion and notify the provider immediately", "Administer protamine sulfate 1 mg per 100 units of heparin without a provider order"]', 2, 'An aPTT of 180 seconds is supratherapeutic (3x the upper limit) indicating dangerous over-anticoagulation with high bleeding risk. STOP the infusion and notify the provider immediately. Protamine sulfate (heparin reversal) may be ordered but requires a physician order.'),
  ('lvn', 'Physiological Care', 'A patient with a new colostomy expresses disgust about the stoma and refuses to look at it. The nurse recognizes this as which stage in the adaptation process?', '["Denial", "Anger", "Bargaining", "Acceptance"]', 0, 'Refusing to look at the stoma and expressing disgust represents denial — the first stage of grief/adaptation (Kübler-Ross). The nurse should allow the patient time to adjust, provide emotional support, and gradually involve the patient in ostomy care when they are ready.'),
  ('lvn', 'Physiological Care', 'A patient returns from a thyroidectomy. Which assessment finding requires IMMEDIATE intervention?', '["Voice hoarseness", "Serum calcium of 9.2 mg/dL", "Positive Chvostek''s sign (facial twitching when tapping the facial nerve)", "Temperature of 37.2\u00b0C"]', 2, 'A positive Chvostek''s sign indicates hypocalcemia from inadvertent parathyroid removal or damage during thyroidectomy. Hypocalcemia can progress to laryngospasm and tetany, a life-threatening airway emergency. Trousseau''s sign is another indicator. IV calcium gluconate must be immediately available.'),
  ('lvn', 'Physiological Care', 'Which instruction should the nurse include when teaching a patient with iron-deficiency anemia to take oral iron supplements?', '["Take iron with milk to reduce gastrointestinal side effects", "Take iron on an empty stomach or with orange juice (Vitamin C) to enhance absorption", "Take iron with calcium supplements for synergistic effect", "Iron supplements can be taken at any time without regard for other foods or medications"]', 1, 'Vitamin C (ascorbic acid) converts ferric iron to ferrous iron, dramatically enhancing GI absorption. Calcium, antacids, milk, and coffee all inhibit iron absorption. Iron should ideally be taken on an empty stomach, though GI upset may require taking it with a small amount of food.'),
  ('lvn', 'Physiological Care', 'A patient is being discharged with a prescription for warfarin. Which statement by the patient indicates a need for further teaching?', '["''I will get my INR checked regularly as scheduled''", "''I will eat consistent amounts of leafy green vegetables rather than eliminating them''", "''I can take ibuprofen for pain since it''s over-the-counter and doesn''t interact with warfarin''", "''I will notify my dentist that I am taking warfarin before any procedures''"]', 2, 'NSAIDs like ibuprofen potentiate warfarin''s anticoagulant effect AND cause GI bleeding, creating dangerous compounded bleeding risk. Patients on warfarin must use acetaminophen for pain. Consistent (not eliminated) vitamin K intake is correct advice.'),
  ('lvn', 'Physiological Care', 'A patient reports cramping abdominal pain, abdominal distention, and hasn''t had a bowel movement in 5 days. Bowel sounds are hypoactive. What is the priority nursing action?', '["Administer a Fleet enema immediately", "Perform digital disimpaction", "Assess the abdomen and notify the provider \u2014 suspect ileus or obstruction", "Encourage the patient to ambulate to stimulate peristalsis"]', 2, 'Hypoactive bowel sounds plus 5 days without BM plus distention could indicate paralytic ileus or mechanical obstruction — both require medical evaluation before any enemas or laxatives are given. Administering enemas to an obstruction can cause perforation.'),
  ('lvn', 'Physiological Care', 'A patient on continuous cardiac monitoring develops sudden onset of irregular rhythm with no discernible P waves and an irregular ventricular rate of 90-130 bpm. The nurse recognizes this as:', '["Normal sinus rhythm", "Atrial fibrillation", "Second-degree AV block (Mobitz Type II)", "Ventricular fibrillation"]', 1, 'Atrial fibrillation is characterized by irregularly irregular rhythm, absence of distinct P waves (replaced by fibrillatory baseline), and variable ventricular rate. It is the most common sustained cardiac arrhythmia. Key concern: thrombus formation and stroke risk from blood pooling in the atria.'),
  ('lvn', 'Pharmacology', 'A patient with type 2 diabetes is prescribed metformin. Which lab value should the nurse assess BEFORE administration and periodically thereafter?', '["Liver function tests (AST, ALT)", "Serum creatinine and GFR (kidney function)", "Serum potassium", "Platelet count"]', 1, 'Metformin is renally cleared, and if kidney function is impaired (GFR <30 mL/min), it accumulates and can cause life-threatening lactic acidosis. Baseline and periodic renal function assessment is mandatory. Metformin should be held before contrast dye procedures.'),
  ('lvn', 'Pharmacology', 'A patient is receiving morphine PCA (patient-controlled analgesia). Which assessment finding requires immediate nursing intervention?', '["Pain score of 4/10", "Respiratory rate of 8 breaths per minute with pinpoint pupils", "Mild nausea", "Request for crackers because of hunger"]', 1, 'Respiratory rate of 8 (bradypnea) with pinpoint pupils (miosis) are classic signs of opioid toxicity/overdose. This is a life-threatening emergency requiring immediate intervention: stop the PCA, apply O2, stimulate the patient, notify the provider, and prepare naloxone (Narcan) administration.'),
  ('lvn', 'Pharmacology', 'The nurse is teaching a patient about taking digoxin. Which instruction is MOST important?', '["Take the medication with an antacid to prevent GI upset", "Take the medication only when you feel your heart beating irregularly", "Count your pulse for one full minute before each dose; hold if less than 60 bpm and call your provider", "Double the next dose if you miss one"]', 2, 'Digoxin has a narrow therapeutic index. A pulse below 60 indicates the drug may be causing bradycardia and the dose should be held. Doubling doses risks toxicity. Never take with antacids — they reduce absorption. Hypokalemia potentiates digoxin toxicity.'),
  ('lvn', 'Pharmacology', 'A patient allergic to penicillin is prescribed amoxicillin-clavulanate (Augmentin). What should the nurse do?', '["Administer the medication since amoxicillin is different from penicillin", "Hold the medication, notify the provider, and document the allergy \u2014 amoxicillin is a penicillin-class antibiotic", "Ask the patient if they''ve had amoxicillin before without a reaction, then proceed if yes", "Administer a test dose and observe for 30 minutes before giving the full dose"]', 1, 'Amoxicillin IS a penicillin. Administering amoxicillin to a penicillin-allergic patient risks a potentially fatal allergic reaction. The nurse must hold the drug, notify the provider, and ensure the allergy is documented. The provider can prescribe a non-penicillin alternative.'),
  ('lvn', 'Pharmacology', 'Which electrolyte imbalance is a nurse MOST concerned about when administering furosemide (Lasix) to a patient also taking digoxin?', '["Hypernatremia", "Hypokalemia", "Hypercalcemia", "Hyperphosphatemia"]', 1, 'Furosemide is a loop diuretic that wastes potassium. Hypokalemia potentiates digoxin toxicity by increasing the drug''s binding to cardiac cells — even at therapeutic digoxin levels, low potassium can cause fatal arrhythmias. Monitor potassium and supplement as ordered.'),
  ('lvn', 'Psychosocial', 'A patient diagnosed with terminal cancer tells the nurse, ''I''ve been praying and I believe God will cure me. I don''t think I need chemotherapy.'' How should the nurse respond?', '["Inform the patient that faith alone cannot cure cancer and insist on chemotherapy", "Tell the patient their beliefs are foolish and could lead to faster death", "Acknowledge the patient''s faith and values, explore their understanding of the prognosis, and notify the provider", "Schedule an appointment with the hospital chaplain without discussing the situation further"]', 2, 'The nurse must respect the patient''s autonomy, cultural/spiritual beliefs, and right to make their own healthcare decisions. The appropriate response is therapeutic communication — acknowledge beliefs, assess understanding, ensure informed consent is in place — and notify the provider. Judgment or coercion is inappropriate.'),
  ('lvn', 'Psychosocial', 'A nurse is caring for a patient in the anger stage of grief following a terminal diagnosis. The patient shouts, ''You don''t care about any of us! You''re all just waiting for me to die!'' What is the BEST response?', '["Explain calmly that the healthcare team does care and leave the room to give the patient privacy", "''It sounds like you''re feeling very angry and frustrated right now. I''m here to listen.''", "Document the outburst as combative behavior and request a psychiatric consult", "Ask the patient''s family to speak with the patient about their attitude"]', 1, 'Therapeutic communication during the anger stage means acknowledging feelings without defensiveness or abandonment. Reflecting the patient''s emotion validates their experience and maintains the therapeutic relationship. Leaving or dismissing the anger is non-therapeutic.'),
  ('lvn', 'Psychosocial', 'A patient who survived a myocardial infarction tells the nurse, ''I know I''m supposed to quit smoking, but I''ve been doing it for 30 years. It''s who I am.'' Using motivational interviewing principles, what is the best nursing response?', '["''You need to stop smoking or you will have another heart attack and die.''", "''What do you think could be different in your life if you did decide to quit?''", "''Many people quit cold turkey and it works fine. Just stop.''", "''Smoking is your choice, so we won''t discuss it further.''"]', 1, 'Motivational interviewing (MI) uses open-ended questions to evoke the patient''s own reasons for change. Asking ''what could be different'' invites the patient to articulate their own values and motivations — far more effective than lecturing or threatening.'),
  ('lvn', 'Psychosocial', 'A patient discloses to the nurse that they are experiencing domestic violence at home. Which response BEST demonstrates therapeutic communication and appropriate nursing action?', '["Advise the patient to leave the abusive relationship immediately", "Reassure the patient that the situation will improve on its own", "Listen non-judgmentally, assess immediate safety, provide information about resources and hotlines, and document findings", "Report the abuser to police without the patient''s knowledge"]', 2, 'The nurse''s role in domestic violence situations is to provide a safe, non-judgmental space, assess immediate safety risk, provide resource information (hotlines, shelters), and document using objective language. Mandating specific actions can endanger the patient further.'),
  ('lvn', 'Psychosocial', 'A nurse is assigned to a patient from a cultural background unfamiliar to the nurse. To provide culturally competent care, what is the MOST important initial action?', '["Treat the patient exactly as the nurse would treat all other patients to avoid bias", "Ask the patient about their health beliefs, practices, and preferences", "Assign the care to a nurse from the same cultural background", "Assume the patient shares the cultural practices typically associated with their ethnic group"]', 1, 'Cultural competence begins with assessing the individual — not assuming all members of a culture share the same beliefs. Asking open-ended questions about health beliefs, dietary practices, traditional remedies, and language needs is the most important first step in culturally sensitive care.'),
  ('lvn', 'Safe Care', 'A nurse is preparing to hand off patient care at the end of a shift. Which communication framework ensures critical information is conveyed in a structured, consistent manner?', '["ADPIE \u2014 the nursing process used to organize care plans", "SBAR (Situation, Background, Assessment, Recommendation) \u2014 a standardized communication tool used during handoffs, phone calls to providers, and escalations", "HIPAA \u2014 a privacy framework that governs what information can be shared during handoff", "READ-BACK \u2014 a verification technique used only for telephone medication orders"]', 1, 'SBAR structures critical communications: Situation (what is happening), Background (relevant history), Assessment (what the nurse thinks is wrong), Recommendation (what the nurse needs). It reduces communication failures — a leading cause of sentinel events — by ensuring all relevant information is conveyed concisely.'),
  ('lvn', 'Safe Care', 'A patient is admitted with suspected tuberculosis. Which transmission-based precaution is required in addition to standard precautions?', '["Contact precautions \u2014 gloves and gown upon room entry", "Droplet precautions \u2014 surgical mask within 3 feet of the patient", "Airborne precautions \u2014 negative pressure room and N95 respirator for healthcare workers entering the room", "Protective isolation \u2014 positive pressure room to protect the immunocompromised patient"]', 2, 'TB is transmitted via airborne particles (droplet nuclei less than 5 microns) that remain suspended in the air. Airborne precautions require a negative pressure private room and an N95 (or higher) respirator for anyone entering. A surgical mask is insufficient for TB. Measles and varicella also require airborne precautions.'),
  ('lvn', 'Safe Care', 'A patient is diagnosed with Clostridioides difficile (C. diff). In addition to standard precautions, what specific requirement applies to hand hygiene for C. diff?', '["Alcohol-based hand sanitizer is preferred because it kills C. diff spores more effectively", "Gloves alone are sufficient \u2014 hand hygiene is not required when gloves are worn", "Soap and water handwashing is required because alcohol-based sanitizers do not kill C. diff spores", "N95 respirator is required in addition to gloves and gown for C. diff rooms"]', 2, 'C. diff produces spores that resist alcohol. Soap and water mechanically removes spores from the hands; alcohol does not kill them. This is a critical exception to the general rule that alcohol-based sanitizer is equivalent to soap and water. Contact precautions (gown and gloves) are also required for C. diff.'),
  ('lvn', 'Safe Care', 'Which nursing intervention is MOST effective in preventing patient falls in an inpatient setting?', '["Restraining patients who are confused at night", "Placing a bed alarm and leaving it as the only intervention", "Performing hourly rounding, keeping the call light within reach, ensuring non-slip footwear, and communicating fall risk status to all care team members", "Instructing the patient to call for help and assuming they will comply"]', 2, 'Fall prevention requires a bundle approach: hourly rounding (anticipates needs before patients attempt to get up alone), bed in lowest position, call light within reach, non-slip footwear, fall risk armband/sign, and bed alarm. No single intervention alone is sufficient — the bundle is the evidence-based standard.'),
  ('lvn', 'Safe Care', 'A patient''s adult child arrives and asks the nurse to share the patient''s diagnosis and medication list. The patient is awake and alert. What is the correct nursing action?', '["Share all information freely \u2014 family members automatically have access to a patient''s health information", "Provide a general update only \u2014 specific diagnoses and medications are never shared with family", "Ask the patient for permission to share information with the family member before disclosing anything", "Contact the attending physician before speaking with any family member"]', 2, 'HIPAA requires patient authorization before disclosing PHI to family members, unless the patient is incapacitated or has previously designated the person as authorized. Even an adult child does not automatically have access. The nurse must ask the alert, competent patient first.'),
  ('lvn', 'Safe Care', 'A patient unexpectedly dies in the emergency department after receiving the wrong medication. This event must be reported as which type of patient safety occurrence?', '["A near miss \u2014 the error was made but the patient survived the initial administration", "A sentinel event \u2014 an unexpected death or serious physical harm resulting from a healthcare error, requiring root cause analysis", "A variance \u2014 a minor deviation from protocol that does not require formal reporting", "An adverse drug reaction \u2014 reported to the FDA MedWatch program only"]', 1, 'A sentinel event is an unexpected death, permanent harm, or severe temporary harm resulting from a care process — not from the patient''s underlying condition. The Joint Commission requires sentinel events to undergo root cause analysis (RCA) to identify contributing factors and implement systemic process improvements.'),
  ('lvn', 'Safe Care', 'Before applying physical restraints to a patient, which nursing action is MOST important?', '["Document the restraint order and apply restraints immediately to ensure patient safety", "Attempt all less restrictive alternatives first (reorientation, de-escalation, family presence, bed alarm, distraction) before restraints are considered", "Ask the family for permission since they have authority over all patient care decisions", "Apply restraints based on nursing judgment alone \u2014 no physician order is required in emergencies"]', 1, 'Restraints are a last resort after all alternatives have been exhausted. The nurse must first try repositioning, toileting, reorientation, music, call light access, and family involvement. A physician order is required. Restraints must be released, circulation assessed, and patient repositioned every 2 hours.'),
  ('lvn', 'Safe Care', 'When transferring a bariatric patient from the bed to a wheelchair, which approach best demonstrates safe patient handling principles?', '["Two nurses performing a manual lift using a draw sheet under the patient", "One nurse assisting the patient using a gait belt while the patient bears full weight", "Using a mechanical lift (Hoyer lift) or sit-to-stand device as appropriate for the patient''s mobility level", "Asking the patient to transfer themselves to reduce injury risk to the nurse"]', 2, 'Safe patient handling requires using mechanical lift equipment (full-body Hoyer lift for non-weight-bearing; sit-to-stand for partial weight-bearing) to eliminate manual lifting. Manual lifts by nurses cause the highest rate of musculoskeletal injuries in healthcare. Gait belts alone are insufficient for bariatric patients.'),
  ('lvn', 'Safe Care', 'A patient is admitted with a completed advance directive stating they do not want cardiopulmonary resuscitation (DNR). The family insists the patient be resuscitated. What does the nurse do?', '["Follow the family''s wishes \u2014 next of kin override an advance directive when the patient cannot speak for themselves", "Honor the patient''s advance directive \u2014 it represents the patient''s expressed wishes when they had capacity and legally supersedes family preferences", "Contact the physician and document the family''s request \u2014 await the physician''s decision", "Resuscitate the patient and address the legal issue afterward"]', 1, 'Advance directives are legally binding documents that express a competent patient''s healthcare wishes for when they can no longer speak for themselves. The patient''s documented wishes take precedence over family preferences. The nurse should communicate compassionately with the family and involve the healthcare team, chaplain, and ethics committee as needed.'),
  ('lvn', 'Safe Care', 'Which clinical task falls outside the scope of practice for an LVN/LPN in most states?', '["Administering oral and subcutaneous medications per provider order", "Performing a complete initial nursing assessment, formulating a nursing diagnosis, and developing the independent nursing care plan", "Monitoring vital signs and reporting changes to the charge RN", "Providing patient education on medication side effects under RN supervision"]', 1, 'LVN/LPN scope of practice is supervised, directed care. RNs hold the independent scope for initial comprehensive assessment, independent nursing diagnosis, and developing the care plan. LVNs contribute data, implement the plan, and report changes — but the cognitive independent judgment functions belong to the RN.'),
  ('lvn', 'Safe Care', 'A nurse performs hand hygiene with an alcohol-based hand rub (ABHR). When is soap and water REQUIRED instead of ABHR?', '["Before and after every patient contact \u2014 ABHR is never acceptable in clinical settings", "When gloves will be worn immediately after hand hygiene, making soap and water necessary first", "When hands are visibly soiled with blood or body fluids, after caring for a patient with C. diff, and after using the restroom", "When caring for any patient on contact precautions, regardless of visible soil"]', 2, 'CDC guidelines require soap and water (not ABHR) when: hands are visibly soiled, after C. diff contact (alcohol does not kill spores), and after using the restroom. In all other situations, ABHR is preferred because it is faster, more accessible, and less damaging to skin with repeated use.'),
  ('lvn', 'Safe Care', 'A nurse accidentally sustains a needlestick injury from a needle used on an HIV-positive patient. What is the FIRST nursing action?', '["Complete an incident report and notify the charge nurse", "Squeeze the wound to express blood, then immediately wash the site with soap and water for several minutes", "Apply a bandage and wait until the end of the shift to report the exposure", "Immediately go to the emergency department for HIV testing"]', 1, 'The first action for any needlestick is to squeeze the wound to encourage bleeding, then wash thoroughly with soap and water. Do NOT use bleach or caustic agents. After first aid, immediately report the exposure to the charge nurse and occupational health/employee health for post-exposure prophylaxis (PEP) assessment. PEP must start within 72 hours.'),
  ('lvn', 'Safe Care', 'The surgical team is about to perform a right hip replacement. The nurse notices the surgeon has not yet performed the pre-incision timeout. What is the appropriate nursing action?', '["Proceed \u2014 the surgeon is responsible for initiating the timeout, not nursing", "Pause the procedure and initiate the timeout \u2014 confirming patient identity, procedure, correct site, and correct side before incision", "Document that the timeout was waived due to time constraints", "Ask the circulating nurse to perform the timeout independently while the surgeon continues preparation"]', 1, 'The Universal Protocol requires a timeout immediately before incision involving the entire team — surgeon, anesthesia, nursing. Any team member can and must halt the procedure to complete the timeout if it has not occurred. This is the primary prevention strategy for wrong-site, wrong-procedure surgery.'),
  ('lvn', 'Safe Care', 'Insulin is classified as a high-alert medication. Which safety practice is REQUIRED when administering insulin?', '["Insulin can be drawn up by any available staff member and administered without verification", "A second licensed nurse must independently verify the insulin type, dose, concentration, patient identity, and blood glucose result before administration", "Insulin doses of less than 10 units do not require double verification", "The pharmacist must personally prepare and deliver all insulin doses to the bedside"]', 1, 'Insulin is a high-alert medication with a narrow therapeutic index and high error rate. Most organizations require independent double-check by a second licensed nurse before administration. This catches name confusion errors (regular vs NPH), dose calculation errors, and pump programming errors — all of which can cause life-threatening hypoglycemia.'),
  ('lvn', 'Safe Care', 'A patient is transferred from the ICU to a medical-surgical floor. Which nursing action prevents medication errors at the transition of care?', '["Assume the ICU medication record is accurate and begin administering medications without review", "Perform medication reconciliation \u2014 comparing the ICU medication list with new admission orders to identify omissions, duplications, or dose discrepancies", "Ask the patient to recite their medications from memory", "Wait for the physician to update the medication list during rounds before administering anything"]', 1, 'Medication reconciliation at every care transition compares the current medication list with new orders to identify unintended discrepancies. The Joint Commission''s National Patient Safety Goals designate medication reconciliation at transitions as a required safety practice. Up to 70% of hospital medication errors occur at transitions of care.'),
  ('lvn', 'Safe Care', 'A nurse expresses concern to the charge nurse that a physician''s order appears unsafe, but the charge nurse dismisses the concern. The order has not been changed. What is the nurse''s next action?', '["Administer the medication as ordered since the charge nurse reviewed it", "Follow the chain of command \u2014 escalate to the supervisor, nursing director, or on-call attending above the original physician until the concern is addressed", "Document the concern and proceed, as the responsibility now lies with the charge nurse", "Refuse all care for this patient until the order is reviewed by a second physician"]', 1, 'The chain of command exists for exactly this situation. The nurse has an independent professional and legal obligation to advocate for patient safety. If immediate superiors do not respond, the nurse must escalate to the next level — nursing supervisor, department director, or the attending''s supervisor. Patient advocacy is a core nursing responsibility.'),
  ('lvn', 'Safe Care', 'When communicating a patient status change to a physician via telephone using SBAR, which component contains the nurse''s clinical judgment and interpretation of the data?', '["Situation \u2014 the brief opening statement of what is happening now", "Background \u2014 the patient''s relevant clinical history", "Assessment \u2014 the nurse''s interpretation of the problem based on data gathered", "Recommendation \u2014 the specific action or order the nurse is requesting"]', 2, 'Assessment in SBAR is where the nurse synthesizes the data: ''I think this patient may be going into septic shock.'' It requires clinical judgment, not just data recitation. This component separates SBAR from a simple data dump and conveys the nurse''s professional evaluation to the provider.'),
  ('lvn', 'Safe Care', 'Before initiating a blood transfusion, two licensed nurses must verify which information at the bedside?', '["Only the blood bag expiration date and infusion rate", "Patient name, medical record number, blood type and Rh factor, unit number, and expiration date \u2014 matched against the patient''s armband and the blood bank paperwork \u2014 with both nurses independently reviewing", "One nurse may verify alone if the second nurse is busy \u2014 solo verification is acceptable in an emergency", "The physician''s verbal order is sufficient for verification \u2014 no paperwork review is required"]', 1, 'Blood product transfusion requires a two-nurse independent verification to prevent wrong-blood transfusion events, which are potentially fatal. Both nurses verify patient identity (two identifiers), ABO/Rh compatibility, unit number, and expiration date at the bedside immediately before infusion. Any discrepancy requires the blood to be returned to the blood bank.'),
  ('lvn', 'Safe Care', 'A nurse catches a medication error before it reaches the patient and reports it. Why is reporting near misses important in patient safety culture?', '["Near misses do not need to be reported because the patient was not harmed", "Near miss reporting identifies system vulnerabilities and process failures before they cause patient harm, enabling proactive improvements without waiting for an adverse event", "Near miss reports go directly into the nurse''s personnel file and may result in disciplinary action", "Only errors that actually reach the patient are subject to quality improvement review"]', 1, 'Near miss reporting is foundational to a culture of safety. Near misses reveal the same system failures as actual errors — inadequate labeling, look-alike medications, distracting environments. Analyzing them proactively allows systems to be fixed before a patient is harmed. High near-miss reporting rates indicate a healthy safety culture, not a dangerous one.'),
  ('lvn', 'Safe Care', 'A patient in restraints reports that their hand feels numb and they cannot wiggle their fingers. What is the priority nursing action?', '["Reassure the patient that numbness is expected with restraints and document the finding", "Immediately release or reposition the restraint and assess neurovascular status \u2014 circulation, sensation, and movement \u2014 and notify the provider", "Tighten the restraint to prevent the patient from working it loose", "Document the complaint and reassess in 30 minutes"]', 1, 'Neurovascular compromise from restraints is a medical emergency. Numbness and inability to move fingers indicate potential vascular or nerve compromise. Release the restraint immediately, assess CMS (circulation, motion, sensation), and notify the provider. Restraints must never impair circulation, and neurovascular checks must be performed every 2 hours minimum.'),
  ('lvn', 'Safe Care', 'A nurse is about to enter a room requiring contact precautions. In what order should PPE be donned?', '["Gloves, then gown, then mask", "Gown first, then mask/eye protection if required, then gloves last", "Mask first, then gown, then gloves", "Gloves first to protect hands during gowning, then gown, then mask"]', 1, 'CDC donning sequence: gown first (protects clothing and skin), then mask and eye protection if needed, then gloves last (gloves over gown cuffs to prevent gaps). Doffing order is reversed: gloves first (most contaminated), then goggles/face shield, then gown, then mask — each removed without contaminating bare hands.'),
  ('lvn', 'Safe Care', 'Which nursing intervention is MOST evidence-based for preventing pressure injuries in bedridden patients?', '["Massaging bony prominences with lotion to stimulate circulation", "Repositioning the patient at least every 2 hours, using pressure-redistribution mattresses, and maintaining skin integrity through moisture management", "Applying oxygen to affected skin areas to promote healing", "Keeping the head of the bed at 90 degrees to prevent skin shear"]', 1, 'Pressure injury prevention requires offloading pressure via regular repositioning (at least every 2 hours), pressure-redistribution surfaces (specialty mattresses), moisture management (prevent incontinence exposure), and nutrition support. Massaging bony prominences is contraindicated as it increases tissue damage. HOB should generally be kept at 30 degrees or less to minimize shear.'),
  ('lvn', 'Physiological Care', 'A patient with type 1 diabetes presents with rapid deep breathing (Kussmaul respirations), fruity breath odor, blood glucose of 480 mg/dL, and serum bicarbonate of 10 mEq/L. The nurse recognizes these as signs of:', '["Hyperglycemic hyperosmolar state (HHS)", "Hypoglycemia \u2014 the fruity breath indicates acetonemia from poor nutrition", "Diabetic ketoacidosis (DKA) \u2014 the combination of hyperglycemia, metabolic acidosis, and ketonemia produces these classic findings", "Somogyi effect \u2014 a rebound hyperglycemia following nocturnal hypoglycemia"]', 2, 'DKA triad: hyperglycemia (usually 250-800 mg/dL), ketoacidosis (pH below 7.3, low bicarbonate), and ketonemia/ketonuria. Kussmaul breathing is respiratory compensation for metabolic acidosis. Fruity breath results from exhaled acetone. Priority interventions: IV fluids, insulin infusion, and electrolyte replacement (especially potassium before insulin).'),
  ('lvn', 'Physiological Care', 'A patient with type 2 diabetes reports feeling shaky, sweaty, and confused. Blood glucose is 52 mg/dL. The patient is conscious and able to swallow. Using the 15-15 rule, what is the correct initial intervention?', '["Administer IV dextrose (D50) immediately regardless of ability to swallow", "Give 15 grams of fast-acting carbohydrate (4 oz juice, glucose tablets), wait 15 minutes, and recheck blood glucose \u2014 repeat if still below 70 mg/dL", "Give a full meal immediately to rapidly normalize blood glucose", "Administer glucagon IM and transfer to the emergency department"]', 1, 'The 15-15 rule: 15g of fast-acting carbohydrate, wait 15 minutes, recheck. Repeat until glucose is at or above 70 mg/dL, then give a snack with complex carbohydrate and protein to prevent recurrence. IV dextrose and IM glucagon are for unconscious or unable-to-swallow patients. A full meal delays absorption and is not the immediate intervention.'),
  ('lvn', 'Physiological Care', 'A patient with COPD on supplemental oxygen has an order for 2 L/min via nasal cannula. The nurse''s aide asks why the oxygen is set so low. What is the best explanation?', '["COPD patients cannot absorb oxygen efficiently, so high flow is wasted", "Patients with COPD may rely on low oxygen levels (hypoxic drive) as their stimulus to breathe; high-flow oxygen can reduce respiratory drive and cause carbon dioxide retention in some patients", "Low-flow oxygen prevents oxygen toxicity from forming free radicals in lung tissue", "COPD patients must breathe room air to build respiratory muscle strength"]', 1, 'In advanced COPD with chronic CO2 retention, the hypercapnic respiratory drive may be blunted, and low oxygen levels can become the primary stimulus to breathe (hypoxic drive). Administering high-flow oxygen can raise SpO2 too quickly, reduce the hypoxic drive, and cause hypoventilation with CO2 retention. Target SpO2 is typically 88-92% for these patients.'),
  ('lvn', 'Physiological Care', 'A patient experiencing an acute asthma attack is in respiratory distress. Which position should the nurse place the patient in immediately?', '["Supine \u2014 lying flat allows maximum diaphragm excursion", "Trendelenburg (feet elevated) to increase venous return and reduce dyspnea", "Sitting upright (high Fowler''s) and leaning slightly forward with arms supported \u2014 the tripod position", "Prone \u2014 improves ventilation-perfusion matching during respiratory distress"]', 2, 'The tripod position (sitting upright, leaning forward, arms propped) optimizes diaphragm position and maximizes lung expansion during acute airway obstruction. Supine and Trendelenburg worsen dyspnea in obstructive respiratory conditions. Priority interventions also include bronchodilator (albuterol) administration and supplemental oxygen.'),
  ('lvn', 'Physiological Care', 'A patient with heart failure is admitted. Which assessment finding indicates worsening fluid overload requiring priority intervention?', '["Weight gain of 0.5 kg over the past week with mild ankle swelling", "Bilateral crackles at lung bases, jugular venous distention, sudden 2 kg weight gain in 24 hours, and dyspnea at rest", "Mild dependent edema in the ankles at end of day with normal breath sounds", "Heart rate of 78 with no respiratory symptoms"]', 1, 'Rapid weight gain (greater than 1-2 kg/day) combined with dyspnea at rest, crackles, and JVD indicates acute decompensated heart failure. Pulmonary edema can develop rapidly. Priority interventions: notify provider, elevate HOB, prepare for diuretic administration (furosemide), apply oxygen, and monitor respiratory status closely.'),
  ('lvn', 'Physiological Care', 'A patient with severe hyponatremia (serum sodium 118 mEq/L) is at GREATEST risk for which complication?', '["Tetany and muscle spasms from low serum calcium", "Cardiac arrhythmias from QT prolongation", "Seizures and cerebral edema \u2014 the brain swells when serum sodium drops rapidly", "Peripheral neuropathy from chronic sodium deficiency"]', 2, 'Acute severe hyponatremia causes water to shift into brain cells, leading to cerebral edema, increased intracranial pressure, seizures, and herniation. The nurse must institute seizure precautions, monitor neuro status, and administer hypertonic saline (3% NaCl) as ordered — but correction must be slow (no more than 6-8 mEq/L per 24 hours) to prevent osmotic demyelination syndrome.'),
  ('lvn', 'Physiological Care', 'A patient''s ECG shows tall, peaked T-waves with a widening QRS complex. Serum potassium is 6.8 mEq/L. What is the priority nursing action?', '["Encourage the patient to eat a low-potassium diet and recheck potassium in the morning", "Place the patient on continuous cardiac monitoring and notify the provider immediately \u2014 hyperkalemia at this level causes life-threatening cardiac arrhythmias", "Administer oral Kayexalate as prescribed and continue routine monitoring", "Reassure the patient \u2014 serum potassium up to 7.0 mEq/L is within the normal range for most adults"]', 1, 'Hyperkalemia with ECG changes (peaked T-waves, widened QRS, sine wave pattern) is a medical emergency. Life-threatening ventricular fibrillation can occur without warning. Continuous cardiac monitoring is immediate priority. The provider will order IV calcium gluconate (membrane stabilization), insulin/dextrose, sodium bicarbonate, and dialysis in severe cases.'),
  ('lvn', 'Physiological Care', 'A patient has a wet-to-dry dressing ordered for a wound with necrotic tissue. What is the intended therapeutic mechanism of this dressing?', '["The wet layer keeps the wound moist to promote healing of granulating tissue", "The dressing is purely for absorption \u2014 no therapeutic debridement occurs", "The wet gauze dries and adheres to necrotic tissue; when removed, it mechanically debrids the wound by pulling away dead tissue", "The dressing prevents all moisture from reaching the wound bed to kill bacteria through desiccation"]', 2, 'Wet-to-dry dressing is a form of non-selective mechanical debridement. The moistened gauze is placed over necrotic tissue, allowed to dry, and the gauze adheres. Upon removal, necrotic tissue is pulled away. Note: this method is considered by some as non-selective (removes healthy granulation too) and has largely been replaced by moisture-retentive dressings for wounds with healthy tissue.'),
  ('lvn', 'Physiological Care', 'A post-operative patient who had abdominal surgery 6 hours ago has been sitting in bed. Which intervention is HIGHEST priority for preventing deep vein thrombosis (DVT)?', '["Keep the patient on strict bed rest for 24 hours to protect the surgical site", "Elevate both legs on pillows above the level of the heart", "Early ambulation and application of sequential compression devices (SCDs) when in bed", "Apply warm compresses to the lower extremities to improve circulation"]', 2, 'DVT prevention post-surgery requires a bundle: early ambulation (reduces venous stasis, most effective intervention), SCDs while in bed, anticoagulant prophylaxis per order, and adequate hydration. Prolonged immobility is the primary DVT risk factor post-operatively. Pillows under knees can restrict popliteal vein flow and are generally avoided.'),
  ('lvn', 'Physiological Care', 'A patient presents with sudden onset of facial drooping on the right side, right arm weakness, and slurred speech. Which action reflects correct stroke response using the FAST acronym?', '["Administer aspirin 325 mg immediately and call the family", "Assess Face drooping, Arm weakness, Speech difficulty, and Time of symptom onset \u2014 then activate the stroke team immediately", "Reorient the patient, check for hypoglycemia, and document the findings for the morning team", "Start IV fluids and prepare for a CT of the abdomen"]', 1, 'FAST: Face drooping, Arm weakness, Speech difficulty, Time to call 9-1-1 (or activate stroke code). Time is brain — every minute of untreated ischemic stroke destroys 1.9 million neurons. The nurse must note the exact time of symptom onset (or last known well time) because tPA eligibility depends on it (within 3-4.5 hours of onset).'),
  ('lvn', 'Physiological Care', 'A patient begins having a generalized tonic-clonic seizure. What is the PRIORITY nursing action during the seizure?', '["Restrain the patient to prevent injury and insert a bite block between the teeth", "Time the seizure, protect the patient from injury (lower to floor if possible, pad surroundings), turn to side after convulsions end, and do NOT put anything in the mouth", "Give a benzodiazepine injection immediately without waiting for a physician order", "Perform a sternal rub to awaken the patient and stop the seizure"]', 1, 'During a seizure: time it, protect from injury, do NOT restrain limbs or put anything in the mouth (bite block myth — adults do not swallow their tongues; oral objects cause dental fractures). After convulsions end, position on side (recovery position) to prevent aspiration. Supplemental oxygen and IV access are priorities post-ictal. Notify provider and document.'),
  ('lvn', 'Physiological Care', 'An adult patient has burns over the entire right arm (front and back), right leg (front and back), and the anterior trunk. Using the Rule of Nines, what percentage of total body surface area (TBSA) is burned?', '["18%", "27%", "36%", "45%"]', 2, 'Rule of Nines: each arm = 9%, each leg = 18%, anterior trunk = 18%, posterior trunk = 18%, head = 9%, perineum = 1%. Right arm = 9%, right leg = 18%, anterior trunk = 18% = 45% TBSA. Fluid resuscitation using the Parkland formula (4 mL x kg x %TBSA burned) is calculated based on TBSA percentage.'),
  ('lvn', 'Physiological Care', 'A patient with acute kidney injury (AKI) has a urine output of 18 mL over the past hour. The nurse recognizes this as:', '["Normal \u2014 urine output of 15-20 mL/hour is expected in adults at rest", "Polyuria \u2014 the kidneys are producing too much urine, indicating renal hyperperfusion", "Oliguria \u2014 urine output below 30 mL/hour indicates inadequate renal perfusion and must be reported to the provider", "Anuria \u2014 no urine output, indicating complete renal shutdown"]', 2, 'Normal urine output is at least 30 mL/hour (0.5 mL/kg/hour) in adults. Output below 30 mL/hour is oliguria — a critical sign of inadequate renal perfusion, reduced cardiac output, dehydration, or AKI. This must be reported to the provider immediately. The nurse should also assess for fluid deficit, low BP, and medication nephrotoxins.'),
  ('lvn', 'Physiological Care', 'A patient with liver failure is prescribed lactulose. Which patient statement indicates they understand the purpose of this medication?', '["Lactulose will strengthen my liver and help it regenerate damaged cells", "The lactulose will prevent constipation from my other medications", "Lactulose causes loose stools, which removes ammonia from my intestines and prevents hepatic encephalopathy", "Lactulose lowers my blood sugar, which is important because liver disease causes diabetes"]', 2, 'In liver failure, the liver cannot convert ammonia to urea. Ammonia accumulates and crosses the blood-brain barrier, causing hepatic encephalopathy. Lactulose creates an acidic environment in the colon that traps ammonia as ammonium (cannot be absorbed) and increases stool frequency — purging ammonia from the body. Goal: 2-3 soft stools per day.'),
  ('lvn', 'Physiological Care', 'A patient 2 hours post-fasciotomy for compartment syndrome reports pain that is OUT OF PROPORTION to the expected post-operative level and worsens with passive stretch of the fingers. What does this indicate?', '["Expected post-operative pain \u2014 no intervention required", "Phantom limb pain \u2014 a neurological complication from the procedure", "Possible recurrence of compartment syndrome \u2014 the nurse must immediately assess the 6 Ps and notify the provider", "Deep vein thrombosis developing in the operative extremity"]', 2, 'The 6 Ps of compartment syndrome: Pain out of proportion, Pain with passive stretch (pathognomonic sign), Paresthesia, Pallor, Paralysis, Pulselessness (late sign). Recurrence post-fasciotomy is possible. Pain out of proportion and pain with passive stretch are the earliest and most important signs. Immediate provider notification is required — compartment syndrome causes permanent nerve and muscle damage within 6-8 hours.'),
  ('lvn', 'Physiological Care', 'When performing tracheostomy care, which action is CORRECT for cleaning the inner cannula?', '["Remove the outer cannula for cleaning \u2014 the inner cannula is never removed", "Remove the inner cannula and clean it with hydrogen peroxide solution, then rinse with normal saline, and replace with a clean or sterile inner cannula", "Clean around the tracheostomy stoma only \u2014 the cannulas do not require cleaning", "Use povidone-iodine to clean both the inner and outer cannulas daily"]', 1, 'The inner cannula (removable lining) is removed and cleaned per facility protocol — typically with hydrogen peroxide to loosen secretions, followed by saline rinse (peroxide can damage tissue if left in place). Some facilities use pre-packaged sterile inner cannulas for replacement. The outer cannula is NOT removed by nursing (only by the provider). Stoma site care prevents skin breakdown.'),
  ('lvn', 'Physiological Care', 'A patient has a chest tube connected to a water-seal drainage system. The nurse observes that the water in the water-seal chamber fluctuates (tidals) with each breath. What does this indicate?', '["A clot is obstructing the chest tube \u2014 the nurse must milk the tube to dislodge it", "An air leak is present in the drainage system", "The chest tube is patent and functioning correctly \u2014 fluctuation confirms it is not obstructed", "The lung has fully re-expanded and the tube is ready to be removed"]', 2, 'Tidaling (fluctuation in the water-seal chamber with respirations) is NORMAL and indicates the tube is patent and communicating with the pleural space. Absence of tidaling may indicate tube obstruction or kinking. Continuous bubbling in the water-seal chamber (not the suction control chamber) indicates an air leak.'),
  ('lvn', 'Physiological Care', 'A patient in acute respiratory distress is on a non-rebreather mask at 15 L/min. SpO2 remains at 82%. What is the priority nursing action?', '["Decrease flow to 10 L/min to prevent oxygen toxicity", "Document the finding and report to the provider at the next scheduled check-in", "Notify the provider immediately and prepare for possible escalation to BiPAP, high-flow nasal cannula, or intubation", "Switch to a simple face mask \u2014 non-rebreather masks are not appropriate for SpO2 below 90%"]', 2, 'An SpO2 of 82% despite maximal non-rebreather flow is a critical deterioration. This patient is failing conventional supplemental oxygen. Immediate provider notification is required. Respiratory failure may require non-invasive positive pressure ventilation (BiPAP) or endotracheal intubation. The nurse should prepare for rapid escalation of care.'),
  ('lvn', 'Physiological Care', 'A patient is non-verbal and cannot self-report pain. Which tool is appropriate for assessing pain in a non-verbal adult?', '["Assume the patient has no pain if they do not display behavioral signs", "Use the numeric pain scale 0-10, pointing to each number and asking the patient to nod", "Use the CPOT (Critical Care Pain Observation Tool) or FLACC scale, assessing behavioral indicators such as facial expression, body movement, muscle tension, and ventilator compliance", "Administer a standing order for pain medication on a scheduled basis regardless of behavioral signs"]', 2, 'Behavioral pain assessment tools like CPOT (for ICU patients) or FLACC (Faces, Legs, Activity, Cry, Consolability — also used in pediatrics) assess observable indicators when self-report is impossible. These tools standardize observation of pain-related behaviors and provide a consistent, documented pain score for non-verbal patients.'),
  ('lvn', 'Physiological Care', 'A 3-year-old is brought to the ED with suspected dehydration. Which assessment finding is MOST indicative of moderate dehydration?', '["Brisk capillary refill under 2 seconds with moist mucous membranes", "Sunken anterior fontanel, dry mucous membranes, decreased skin turgor (tenting), and decreased urine output", "Weight gain of 0.5 kg compared to last visit", "Heart rate of 98 beats per minute with strong peripheral pulses"]', 1, 'Moderate dehydration (5-9% body weight loss): sunken fontanel (infants), sunken eyes, dry mucous membranes, decreased skin turgor, decreased urine output, and tachycardia. Capillary refill greater than 2 seconds indicates moderate-severe dehydration. Infants show irritability; older children show lethargy as dehydration worsens.'),
  ('lvn', 'Physiological Care', 'A postpartum patient is assessed 30 minutes after delivery and found to have a uterine fundus that is boggy, displaced to the right, and above the umbilicus. Lochia is heavy. What is the priority nursing action?', '["Administer oxytocin (Pitocin) IM immediately per standing order", "Firmly massage the fundus and encourage the patient to void \u2014 a distended bladder displaces the uterus and inhibits contraction, causing atony and hemorrhage", "Apply ice packs to the perineum and elevate the legs", "Prepare for emergent hysterectomy"]', 1, 'A displaced, boggy fundus above the umbilicus strongly suggests bladder distension preventing uterine contraction (uterine atony with bladder displacement). The first intervention is bladder emptying (encourage voiding or catheterize if unable) followed by fundal massage. If the uterus remains boggy after emptying the bladder, administer uterotonic medications per order.'),
  ('lvn', 'Physiological Care', 'A patient with GERD is being discharged. Which lifestyle modification instruction should the nurse include?', '["Lie down for 30 minutes after meals to allow gravity to assist digestion", "Eat large meals twice daily to reduce the frequency of acid exposure", "Elevate the head of the bed 6-8 inches and avoid eating within 2-3 hours of bedtime", "Increase dietary fat intake to slow gastric emptying and reduce acid secretion"]', 2, 'GERD management: elevate HOB (not just extra pillows — raises the entire head section), avoid eating 2-3 hours before lying down, eat smaller more frequent meals, avoid triggers (caffeine, alcohol, spicy foods, mint, citrus, chocolate), lose weight if overweight, and avoid tight clothing. These measures reduce reflux episodes before or instead of medication.'),
  ('lvn', 'Physiological Care', 'A patient presents with sudden onset right lower quadrant pain that was initially periumbilical, nausea, low-grade fever, and rebound tenderness at McBurney''s point. The nurse anticipates which diagnosis and priority intervention?', '["Kidney stone \u2014 priority is IV fluid hydration and ketorolac for pain", "Acute appendicitis \u2014 priority is NPO status, IV access, pain management, and preparation for surgical consult", "Ovarian cyst \u2014 priority is warm compresses and oral analgesics", "Diverticulitis \u2014 priority is high-fiber diet and oral antibiotics"]', 1, 'Classic appendicitis presentation: periumbilical pain migrating to RLQ, nausea/vomiting, low-grade fever, rebound tenderness at McBurney''s point (two-thirds from umbilicus to anterior iliac spine). Nursing priorities: NPO (surgery likely), IV access, monitor for rupture signs (sudden pain relief followed by diffuse rigidity = peritonitis). Do NOT apply heat.'),
  ('lvn', 'Physiological Care', 'A patient develops a reddened area over the sacrum that does not blanch when pressed. The surrounding skin is intact. How should this wound be staged?', '["Stage I pressure injury \u2014 intact skin with non-blanchable redness", "Stage II pressure injury \u2014 partial thickness skin loss with exposed dermis", "Unstageable pressure injury \u2014 full-thickness skin loss with wound bed obscured by eschar", "Deep tissue pressure injury \u2014 purple or maroon discoloration of intact skin"]', 0, 'Stage I: intact skin with non-blanchable erythema. Non-blanchable means the redness does NOT turn white when pressed (blanching would indicate normal reactive hyperemia). Stage I represents early pressure injury — the skin is still intact but the tissue is at risk. Intervention: relieve pressure immediately, increase repositioning frequency, and protect the skin.'),
  ('lvn', 'Physiological Care', 'A patient with a nasogastric tube for tube feeding becomes suddenly agitated and begins coughing violently during a feeding. What does the nurse suspect and what is the immediate action?', '["The patient is anxious \u2014 reassure them and continue the feeding at the prescribed rate", "Tube displacement into the trachea or lungs \u2014 stop the feeding immediately, clamp the tube, and notify the provider for confirmation of placement", "The tube is clogged \u2014 flush with 30 mL warm water and resume feeding", "The feeding formula is too concentrated \u2014 dilute it and reduce the rate"]', 1, 'Coughing, gagging, choking, or respiratory distress during tube feeding indicates possible tube displacement into the airway. STOP feeding immediately — continuing instillation into a misplaced tube can cause aspiration pneumonia or death. Clamp the tube, leave it in place, and notify the provider. Placement must be confirmed by X-ray (gold standard) before feeding resumes.'),
  ('lvn', 'Physiological Care', 'When assessing the abdomen, in what order should the nurse perform the assessment techniques?', '["Inspection, palpation, percussion, auscultation", "Inspection, auscultation, percussion, palpation", "Palpation, percussion, auscultation, inspection", "Auscultation, inspection, palpation, percussion"]', 1, 'Abdominal assessment deviates from the standard IPPA sequence. Auscultation comes BEFORE percussion and palpation because manipulating the abdomen can alter bowel sounds. Correct sequence: Inspection (contour, scars, distension) → Auscultation (bowel sounds, bruits) → Percussion (tympany vs dullness) → Palpation (light then deep, tenderness, masses).'),
  ('lvn', 'Physiological Care', 'A patient''s serum potassium result is 6.5 mEq/L. The nurse places the patient on continuous cardiac monitoring and notifies the provider. The provider asks the nurse to prepare interventions. Which intervention acts FASTEST to stabilize the cardiac membrane?', '["Sodium polystyrene sulfonate (Kayexalate) \u2014 removes potassium from the body over several hours", "Dietary restriction of potassium-containing foods", "IV calcium gluconate \u2014 stabilizes the cardiac membrane within minutes without lowering potassium levels", "Furosemide (Lasix) IV \u2014 promotes urinary potassium excretion"]', 2, 'IV calcium gluconate stabilizes the cardiac cell membrane against the effects of hyperkalemia within 1-3 minutes. It does NOT lower serum potassium — it simply protects the heart while other measures (insulin/dextrose, sodium bicarbonate, Kayexalate, dialysis) lower the potassium level. It is always the FIRST intervention when ECG changes are present.'),
  ('lvn', 'Physiological Care', 'A patient with type 2 diabetes is learning to monitor blood glucose at home. Which instruction regarding site rotation is CORRECT?', '["Always use the same fingertip site to compare readings over time", "Rotate among all fingers and vary the puncture site on each fingertip to prevent callus formation and ensure accurate readings", "The earlobe is preferred over the fingertips for home glucose monitoring", "Use the dominant hand only \u2014 non-dominant hand readings are less accurate"]', 1, 'Rotating finger-stick sites prevents callus formation (which can alter readings) and reduces pain and desensitization. All 10 fingers should be rotated. The sides of fingertips are less painful than the pads. Alternate site testing (forearm) is less accurate during rapid glucose changes (post-meal, hypoglycemia) and is generally discouraged for routine monitoring.'),
  ('lvn', 'Physiological Care', 'A patient on IV fluids has intake of 2,800 mL and output of 900 mL urine, 400 mL wound drainage, and 200 mL nasogastric output in 24 hours. What is the fluid balance?', '["-500 mL (negative balance)", "+ 500 mL (positive balance)", "+ 1,300 mL (positive balance)", "- 1,500 mL (negative balance)"]', 2, 'Total output = 900 + 400 + 200 = 1,500 mL. Fluid balance = intake minus output = 2,800 - 1,500 = +1,300 mL positive balance. Fluid overload is a concern with sustained positive balance. Note: insensible losses (breathing, sweating, ~800-1000 mL/day) are not directly measured but should be considered in clinical interpretation.'),
  ('lvn', 'Physiological Care', 'A patient with chronic heart failure reports they must sleep on three pillows or they cannot breathe. The nurse documents this as:', '["Paroxysmal nocturnal dyspnea (PND) \u2014 sudden dyspnea during sleep", "Orthopnea \u2014 difficulty breathing when lying flat, quantified by the number of pillows needed to sleep comfortably", "Tachypnea \u2014 an abnormally rapid respiratory rate at night", "Cheyne-Stokes respiration \u2014 a pattern of cyclically increasing and decreasing respiratory effort"]', 1, 'Orthopnea (from Greek: upright breathing) is dyspnea that occurs in the recumbent position and is relieved by elevating the upper body. In heart failure, lying flat redistributes fluid from the lower extremities into the pulmonary circulation, increasing preload and causing dyspnea. It is quantified by number of pillows. It is a classic symptom of left-sided heart failure.'),
  ('lvn', 'Physiological Care', 'Before performing nasotracheal suctioning, which action is required to prevent hypoxia during the procedure?', '["Administer a sedative to reduce the patient''s gag reflex", "Pre-oxygenate the patient with 100% oxygen for 30 seconds to 1 minute before each suction pass", "Suction the oropharynx before the nasotracheal route to reduce contamination", "Hyperventilate the patient with 20 breaths per minute to build up oxygen reserves"]', 1, 'Pre-oxygenation is mandatory before suctioning because the procedure removes oxygen along with secretions. Without pre-oxygenation, suctioning can cause hypoxia, cardiac arrhythmias, or bronchospasm. Apply suction only during withdrawal (not insertion) and limit each suction pass to 10-15 seconds.'),
  ('lvn', 'Physiological Care', 'A patient requires supplemental oxygen and their SpO2 is 89%. The provider orders 40% FiO2. Which oxygen delivery device should the nurse use?', '["Nasal cannula at 4 L/min (delivers approximately 36-40% FiO2)", "Simple face mask at 6 L/min (delivers approximately 35-50% FiO2)", "Venturi mask \u2014 delivers precise, controlled FiO2 (24%, 28%, 31%, 35%, 40%, etc.) regardless of respiratory pattern", "Non-rebreather mask \u2014 delivers 60-90% FiO2 for maximum oxygen delivery"]', 2, 'Venturi masks (air-entrainment masks) deliver precise, consistent FiO2 using calibrated color-coded adaptors. They are ideal when exact FiO2 is ordered (as with COPD patients where hypercapnic drive is a concern). Nasal cannulas and simple masks deliver variable FiO2 based on the patient''s respiratory rate and depth.'),
  ('lvn', 'Physiological Care', 'A wound is draining fluid that is pale pink and watery with a slightly blood-tinged appearance. The nurse correctly documents this drainage as:', '["Purulent \u2014 indicating active bacterial infection", "Serous \u2014 clear, thin fluid indicating normal wound healing", "Serosanguineous \u2014 a mixture of serum and blood, typically seen in the first 48-72 hours of wound healing", "Sanguineous \u2014 bright red blood from active bleeding in the wound bed"]', 2, 'Serosanguineous drainage (pale pink, watery, blood-tinged) is normal in early wound healing. Serous = clear/straw-colored. Sanguineous = frank bright red blood. Serosanguineous = mix of both. Purulent drainage (thick, cloudy, yellow/green, foul-smelling) indicates infection and must be reported.'),
  ('lvn', 'Pharmacology', 'A patient taking metoprolol (a beta-1 blocker) has a resting heart rate of 54 beats per minute before the morning dose is due. What should the nurse do?', '["Administer the medication as scheduled \u2014 beta blockers are designed to lower heart rate", "Hold the medication and notify the provider \u2014 a resting heart rate below 60 bpm is typically the parameter for withholding a beta blocker", "Double the dose to ensure therapeutic beta blockade is maintained", "Administer the medication and monitor the patient for the next hour"]', 1, 'Beta blockers slow heart rate. Most facilities use a hold parameter of HR below 60 bpm for beta blockers. The nurse must hold the dose, notify the provider, and document the assessment. The provider may adjust the dose, lower the hold parameter, or discontinue based on the patient''s clinical condition.'),
  ('lvn', 'Pharmacology', 'A patient newly prescribed lisinopril (an ACE inhibitor) for hypertension calls the clinic reporting a persistent dry, hacking cough for the past two weeks. What is the most appropriate nursing response?', '["Reassure the patient \u2014 this cough is a sign the medication is working and will resolve in a few days", "Advise the patient to take the medication with food to reduce the cough", "Document the complaint and notify the provider \u2014 ACE inhibitor-induced cough is a class effect from bradykinin accumulation and may require switching to an ARB", "Tell the patient to stop the medication immediately and go to the emergency department"]', 2, 'ACE inhibitor-induced dry cough is caused by bradykinin accumulation (ACE also breaks down bradykinin). It is a class effect — all ACE inhibitors can cause it. It is NOT dose-related. The provider must be notified so the medication can be switched to an ARB (angiotensin receptor blocker) which does not cause this side effect. Never advise stopping a cardiac medication without provider guidance.'),
  ('lvn', 'Pharmacology', 'A patient is prescribed NPH insulin for basal coverage. The nurse knows this insulin has a peak effect at approximately which time after administration?', '["30-60 minutes (rapid onset)", "2-4 hours \u2014 and is therefore not associated with hypoglycemia risk", "4-12 hours after subcutaneous injection \u2014 hypoglycemia risk peaks during this window", "24 hours \u2014 NPH provides a flat, peakless basal coverage similar to insulin glargine"]', 2, 'NPH (intermediate-acting) insulin onset: 1-2 hours; peak: 4-12 hours; duration: 12-18 hours. The peak is when hypoglycemia risk is highest — typically mid-morning for breakfast-time NPH. Nurses must know insulin onset, peak, and duration to anticipate hypoglycemia. Insulin glargine (Lantus) and detemir are long-acting peakless basals — very different from NPH.'),
  ('lvn', 'Pharmacology', 'A patient is prescribed enoxaparin (Lovenox), a low-molecular-weight heparin (LMWH). Which statement about monitoring LMWH is correct?', '["aPTT must be monitored every 6 hours to titrate the dose, just like unfractionated heparin", "Anti-Xa levels can be used to monitor LMWH effect in special populations (obesity, renal impairment, pregnancy) but routine aPTT monitoring is NOT required for LMWH", "PT/INR is the appropriate monitoring test for LMWH", "No laboratory monitoring is ever needed for LMWH in any patient population"]', 1, 'Unlike unfractionated heparin (which requires aPTT monitoring for dose titration), standard LMWH doses use weight-based fixed dosing and do NOT require routine aPTT monitoring. In special populations (extreme obesity, renal insufficiency, pregnancy), anti-Xa levels may be drawn to ensure adequate levels. The reversal agent for LMWH is protamine sulfate (partial reversal).'),
  ('lvn', 'Pharmacology', 'A patient on long-term prednisone therapy is at risk for which pair of adverse effects the nurse should monitor?', '["Hypoglycemia and osteoporosis", "Hyperglycemia (corticosteroid-induced diabetes) and increased infection risk from immunosuppression", "Bradycardia and fluid loss from diuretic effect", "Thrombocytopenia and prolonged bleeding time"]', 1, 'Corticosteroids cause hyperglycemia (stimulate gluconeogenesis and insulin resistance), immunosuppression (impair neutrophil and lymphocyte function), fluid retention, weight gain, osteoporosis (long-term), adrenal suppression, and mood changes. Blood glucose monitoring is critical, especially in diabetics. Never stop corticosteroids abruptly — taper to prevent adrenal crisis.'),
  ('lvn', 'Pharmacology', 'A patient taking lithium for bipolar disorder presents with coarse hand tremors, nausea, vomiting, and drowsiness. Lithium level is 1.9 mEq/L. The nurse recognizes this as:', '["Normal therapeutic range \u2014 lithium levels of 1.8-2.0 mEq/L are optimal for maintenance therapy", "Mild toxicity \u2014 the therapeutic range is 0.6-1.2 mEq/L for maintenance; levels above 1.5 mEq/L indicate toxicity", "Subtherapeutic level \u2014 the dose should be increased and the patient reassured", "A lithium allergic reaction \u2014 the medication should be discontinued immediately and Benadryl administered"]', 1, 'Lithium therapeutic range: 0.6-1.2 mEq/L (maintenance); up to 1.5 mEq/L (acute mania). Levels above 1.5 mEq/L indicate toxicity. Early toxicity signs: coarse tremor, nausea, vomiting, drowsiness, diarrhea. Severe toxicity (greater than 2.5 mEq/L): seizures, coma, death. Hold lithium, notify provider, ensure adequate hydration. Lithium has no reversal agent — dialysis is used for severe toxicity.'),
  ('lvn', 'Pharmacology', 'A patient taking sertraline (an SSRI) begins a new prescription for tramadol. The nurse should assess for which serious drug interaction?', '["Stevens-Johnson syndrome \u2014 a hypersensitivity reaction requiring immediate hospitalization", "Serotonin syndrome \u2014 excess serotonergic activity causing hyperthermia, agitation, diaphoresis, tachycardia, tremor, hyperreflexia, and clonus", "Anticholinergic toxidrome \u2014 caused by combining two anticholinergic agents", "Neuroleptic malignant syndrome \u2014 from combining serotonergic and dopaminergic agents"]', 1, 'Tramadol inhibits serotonin reuptake, and combined with an SSRI, this creates excess serotonin activity (serotonin syndrome). Classic triad: altered mental status (agitation, confusion), autonomic instability (hyperthermia, tachycardia, diaphoresis), and neuromuscular abnormalities (clonus, hyperreflexia, tremor). Management: stop offending agents, supportive care, cyproheptadine for severe cases.'),
  ('lvn', 'Pharmacology', 'A patient with acetaminophen overdose presents 3 hours after ingestion. Which medication is the SPECIFIC antidote?', '["Flumazenil \u2014 used for benzodiazepine reversal", "N-acetylcysteine (NAC) \u2014 replenishes glutathione and prevents liver failure", "Naloxone \u2014 reverses opioid-induced respiratory depression", "Vitamin K \u2014 reverses anticoagulant-mediated hepatotoxicity"]', 1, 'Acetaminophen overdose depletes glutathione in the liver, leading to toxic metabolite (NAPQI) accumulation and liver necrosis. N-acetylcysteine (Mucomyst, Acetadote) is the antidote — it replenishes glutathione and detoxifies NAPQI. It is most effective within 8-10 hours of ingestion but can be given up to 24-72 hours. Serum acetaminophen level and the Rumack-Matthew nomogram guide treatment decisions.'),
  ('lvn', 'Pharmacology', 'A patient on phenytoin (Dilantin) is at risk for which oral health complication that requires dental referral and hygiene instruction?', '["Oral candidiasis from phenytoin-induced immunosuppression", "Gingival hyperplasia (overgrowth of gum tissue) \u2014 a common side effect requiring rigorous dental hygiene and dental monitoring", "Oral ulcers from phenytoin-induced folate deficiency", "Xerostomia (dry mouth) from anticholinergic effects of phenytoin"]', 1, 'Gingival hyperplasia occurs in up to 50% of patients on phenytoin — fibroblast proliferation causes gum tissue to overgrow, potentially covering teeth and increasing infection risk. Rigorous oral hygiene (brushing, flossing) reduces severity. Dental visits every 3 months are recommended. This side effect may prompt a medication switch to alternative antiepileptics.'),
  ('lvn', 'Pharmacology', 'A patient receiving long-term opioid therapy is complaining of abdominal discomfort and has not had a bowel movement in 4 days. The nurse recommends which preventive approach for opioid-induced constipation?', '["Wait until the patient has not had a bowel movement for 7 days before intervening \u2014 opioid constipation is self-limiting", "Encourage increased fiber intake and water consumption only", "A stimulant laxative (senna) should be prescribed prophylactically when opioids are initiated \u2014 opioid constipation does not resolve on its own and does not develop tolerance", "Administer a Fleet enema every morning to prevent accumulation"]', 2, 'Opioid-induced constipation (OIC) is caused by opioid receptors in the GI tract reducing peristalsis. Unlike most opioid side effects (sedation, nausea), tolerance to constipation does NOT develop. A stimulant laxative should be initiated prophylactically with long-term opioids. Methylnaltrexone (Relistor) is an option for refractory OIC — it reverses GI opioid effects without affecting analgesia.'),
  ('lvn', 'Psychosocial', 'A patient diagnosed with a new chronic illness says, ''I don''t want to talk about it. Can we just check my blood pressure and leave?'' The BEST therapeutic communication approach is:', '["Insist the patient discuss their diagnosis: ''I need to make sure you understand your condition before I can leave.''", "Respect the patient''s communication boundary: ''Of course. We can talk whenever you feel ready. I''m here if you have questions.'' Then proceed with the blood pressure check", "Document the patient as non-compliant and notify the social worker for immediate intervention", "Use closed-ended questions to obtain necessary information while minimizing conversation"]', 1, 'Therapeutic communication respects patient autonomy and readiness. Pushing a patient to discuss topics they are not ready to address is non-therapeutic and damages the nurse-patient relationship. Acknowledging the patient''s stance while leaving the door open for future communication is the correct approach. Silence and withdrawal can be normal coping responses.'),
  ('lvn', 'Psychosocial', 'Under which circumstances may a person be involuntarily admitted to an inpatient psychiatric unit?', '["Any time a provider recommends inpatient treatment, regardless of the patient''s consent", "When the individual poses an imminent danger to themselves or others, is gravely disabled and unable to care for themselves, or is acutely psychotic and lacks capacity to make treatment decisions", "Whenever a family member requests psychiatric hospitalization for an adult relative", "When a person refuses to take prescribed psychiatric medications on an outpatient basis"]', 1, 'Involuntary psychiatric commitment (5150, 302, or equivalent by jurisdiction) requires evidence of imminent danger to self, danger to others, or grave disability (unable to meet basic needs due to mental disorder). A voluntary patient retains the right to refuse hospitalization and leave. Specific criteria, procedures, and duration vary by state law.'),
  ('lvn', 'Psychosocial', 'A patient with a history of depression asks the nurse directly, ''Are you going to ask me if I want to kill myself?'' What is the best response?', '["Deflect the question: ''I''m just here to check your vitals \u2014 we don''t need to discuss that today''", "''I might, yes. Asking about suicide doesn''t put the idea in your head \u2014 it actually gives people permission to talk about something they may be struggling with. Are you having thoughts of suicide?''", "Report the patient''s statement to the charge nurse as a behavioral emergency", "Reassure the patient: ''Of course not \u2014 you seem fine. There''s nothing to worry about.''"]', 1, 'Directly asking about suicide does NOT plant the idea — research consistently shows it provides relief and opens therapeutic dialogue. Nurses have a professional obligation to assess suicide risk in at-risk patients. The therapeutic response acknowledges the patient''s question, corrects the myth about suicide inquiry, and directly asks the screening question in a calm, non-alarmist way.'),
  ('lvn', 'Psychosocial', 'A patient with a terminal diagnosis says to the nurse, ''I''ve been praying every day, and I''ve promised God that if I recover, I''ll finally spend time with my grandchildren and fix all my mistakes.'' The nurse recognizes this statement as an example of which stage of grief?', '["Denial \u2014 refusing to accept the diagnosis", "Anger \u2014 misdirected frustration expressed through bargaining language", "Bargaining \u2014 attempting to negotiate with a higher power in exchange for recovery or more time", "Acceptance \u2014 making peace with the diagnosis and focusing on what matters most"]', 2, 'Bargaining (Kubler-Ross Stage 3) involves negotiating — often with God, fate, or the universe — for more time, recovery, or relief. Statements like ''if only'' or ''if I could just...'' are characteristic. The nurse should listen without judgment, acknowledge the emotional content, and support the patient''s spiritual coping while remaining present and compassionate.'),
  ('lvn', 'Psychosocial', 'A nurse is caring for a patient who communicates using sign language. An interpreter is not immediately available. Which approach BEST supports effective communication?', '["Speak loudly and slowly \u2014 many hearing-impaired individuals can lip-read when the speaker is emphatic", "Use written notes, a whiteboard, or a communication board for immediate needs, and promptly request a qualified ASL interpreter for all clinical discussions", "Ask a family member to interpret the clinical assessment and discharge instructions", "Limit communication to yes/no questions only until an interpreter arrives"]', 1, 'Written communication addresses immediate needs, but for informed consent, clinical history-taking, diagnosis discussion, and discharge teaching, a qualified ASL interpreter (not a family member) is required under the ADA and HIPAA-related language access obligations. Family interpreters introduce bias, privacy concerns, and accuracy risk. The nurse must actively facilitate interpreter access, not defer indefinitely.'),
  ('shrm', 'Employment Law', 'Under the Age Discrimination in Employment Act (ADEA), which employees are protected from age-based discrimination?', '["All employees regardless of age", "Employees aged 40 and older", "Employees aged 65 and older", "Only employees who have been with the company for 5 or more years"]', 1, 'The ADEA protects workers 40 years of age and older from discrimination based on age in hiring, firing, pay, job assignments, promotions, layoffs, training, and any other term or condition of employment. Applies to employers with 20 or more employees.'),
  ('shrm', 'Employment Law', 'The Fair Labor Standards Act (FLSA) establishes which of the following?', '["Mandatory vacation accrual rates for all employees", "Federal minimum wage, overtime pay (1.5x for hours over 40/week for non-exempt employees), and child labor standards", "Required paid sick leave for all private-sector employees", "Mandatory health insurance for companies with 50 or more employees"]', 1, 'The FLSA sets the federal minimum wage, requires overtime pay of 1.5x the regular rate for non-exempt employees who work more than 40 hours in a workweek, and establishes child labor standards. It does NOT require paid vacation, sick leave, or holidays.'),
  ('shrm', 'Employment Law', 'A company is planning to lay off 200 workers at a single facility. Under the Worker Adjustment and Retraining Notification (WARN) Act, what is required?', '["No advance notice is legally required for layoffs", "60 days advance written notice to affected workers, state dislocated worker units, and local government", "30 days advance written notice to the state unemployment agency only", "Severance pay equal to 2 weeks per year of service for each affected employee"]', 1, 'The WARN Act requires employers with 100+ employees to provide 60 calendar days advance written notice before a plant closing or mass layoff (50+ employees at a single site). Notice must go to affected workers, state, and local officials. Violations result in back pay liability.'),
  ('shrm', 'Employment Law', 'Under the Americans with Disabilities Act (ADA), what is an employer required to provide to a qualified employee with a disability?', '["Any accommodation the employee requests, regardless of cost", "Reasonable accommodation unless it creates an undue hardship for the employer", "Full disability benefits equal to their current salary", "Transfer to a different department without considering business needs"]', 1, 'The ADA requires employers to provide reasonable accommodations to qualified individuals with disabilities unless doing so creates an undue hardship (significant difficulty or expense). The interactive process between employer and employee is required to identify effective accommodations.'),
  ('shrm', 'Employment Law', 'Under Title VII of the Civil Rights Act of 1964, which categories are protected from employment discrimination?', '["Race, color, sex, national origin, and religion", "Race, color, sex, national origin, religion, age, and disability", "Race, color, and national origin only", "All forms of discrimination in the workplace including unfair treatment"]', 0, 'Title VII prohibits employment discrimination based on race, color, religion, sex (including pregnancy, sexual orientation, and gender identity), and national origin. Age is covered by the ADEA, and disability by the ADA — separate statutes.'),
  ('shrm', 'Employment Law', 'Which of the following is an example of a bona fide occupational qualification (BFOQ) that can be used as a legal defense for what would otherwise be discriminatory hiring?', '["Requiring all customer-facing employees to speak English", "Requiring female actors to play female roles in a theatrical production", "Refusing to hire applicants over age 50 for all positions because ''young people are more productive''", "Requiring all employees to be of a specific nationality for international assignments"]', 1, 'A BFOQ is a characteristic that is genuinely necessary for the performance of a job. Requiring female actors for female roles is a classic example. BFOQs are narrowly construed — customer preference, productivity stereotypes, or general convenience do NOT qualify as BFOQs.'),
  ('shrm', 'Employment Law', 'An employer''s selection process results in significantly fewer women being hired even though the process appears neutral on its face. This is an example of:', '["Disparate treatment", "Disparate impact", "Hostile work environment", "Quid pro quo harassment"]', 1, 'Disparate impact (also called adverse impact) occurs when a facially neutral employment practice disproportionately affects a protected class. The ''4/5ths rule'' (selection rate for a protected group is less than 80% of the highest group''s rate) is used to measure it. No discriminatory intent is required.'),
  ('shrm', 'Employment Law', 'Under the Family and Medical Leave Act (FMLA), how many weeks of unpaid, job-protected leave is an eligible employee entitled to per year?', '["6 weeks", "12 weeks (or up to 26 weeks for military caregiver leave)", "8 weeks", "Leave under FMLA is paid, not unpaid"]', 1, 'FMLA provides eligible employees (12 months of employment, 1,250 hours worked) at covered employers (50+ employees) up to 12 weeks of unpaid, job-protected leave per year for qualifying reasons (birth, adoption, serious health condition). Military caregiver leave can extend to 26 weeks.'),
  ('shrm', 'Employment Law', 'An OSHA inspection finds that an employer willfully violated a safety standard, causing a worker''s death. What is the maximum penalty per violation?', '["$15,625", "$70,000", "$156,259", "$1,000,000"]', 2, 'OSHA willful violations with a fatality carry criminal penalties up to $156,259 per violation (as of recent adjustments) plus possible imprisonment. Serious violations carry up to $15,625 per violation. Willful violations can also result in criminal prosecution with up to 6 months imprisonment for a first offense.'),
  ('shrm', 'Employment Law', 'A supervisor conditions a promotion on an employee''s agreement to a sexual relationship. This is an example of:', '["Hostile work environment harassment", "Disparate impact", "Quid pro quo sexual harassment", "Constructive discharge"]', 2, 'Quid pro quo (''something for something'') harassment occurs when a person in authority conditions an employment benefit (promotion, raise, continued employment) on an employee''s submission to sexual advances. This is strict liability for the employer regardless of whether the employee acquiesces.'),
  ('shrm', 'Employment Law', 'An employer with 60 employees wants to conduct drug testing. Which statement about drug testing is correct?', '["Pre-employment drug testing is prohibited under the ADA", "Random drug testing of safety-sensitive employees is generally permissible", "Drug tests may only be conducted after a workplace accident", "Employees may refuse drug tests without consequence in all circumstances"]', 1, 'Pre-employment and random drug testing for safety-sensitive positions is generally permissible. The ADA does not protect current illegal drug users. While current illegal drug use is not a disability, employees in recovery are protected. Testing policies must be applied consistently.'),
  ('shrm', 'People & Talent', 'Which recruitment metric measures the quality and retention of new hires from different sourcing channels?', '["Time to fill", "Cost per hire", "Source of hire quality (quality of hire)", "Offer acceptance rate"]', 2, 'Quality of hire measures the value new employees bring, typically tracking performance ratings, time to productivity, and retention rates by sourcing channel. It''s considered the most strategic recruitment metric because it correlates sourcing effectiveness to business outcomes.'),
  ('shrm', 'People & Talent', 'A structured interview uses which approach to ensure consistency and legal defensibility?', '["Asking different questions to each candidate based on their resume", "Allowing interviewers to ask any questions they find interesting", "Asking all candidates the same predetermined, job-related questions with a standardized scoring rubric", "Focusing primarily on personality and cultural fit questions"]', 2, 'Structured interviews require the same questions in the same order for all candidates, scored against a predetermined rubric based on job-related competencies. They significantly reduce bias (halo effect, confirmation bias) and are more legally defensible than unstructured interviews.'),
  ('shrm', 'People & Talent', 'The 360-degree feedback process differs from traditional performance reviews because:', '["It focuses solely on quantitative metrics and KPIs", "It collects performance feedback from multiple sources: supervisors, peers, direct reports, and the employee themselves", "It eliminates the manager''s role in performance assessment", "It is used only for executive-level employees"]', 1, '360-degree feedback (multi-rater feedback) provides a holistic view of employee performance from multiple perspectives, reducing single-rater bias. It''s particularly valuable for assessing leadership competencies and interpersonal behaviors that aren''t visible to a direct supervisor alone.'),
  ('shrm', 'People & Talent', 'Which compensation strategy sets pay at or above market median to attract and retain top talent, accepting higher labor costs?', '["Lag the market strategy", "Lead the market strategy", "Match the market strategy", "Broad-banding strategy"]', 1, 'A lead the market (pay above market) strategy compensates above the market median to attract top candidates and reduce turnover. It''s used in competitive talent markets or for critical skills. The trade-off is higher payroll costs but potentially lower recruiting and turnover costs.'),
  ('shrm', 'People & Talent', 'An organization wants to identify employees with high potential for leadership roles and develop targeted development plans. This is best described as:', '["Performance appraisal", "Succession planning with talent review", "Workforce planning", "Compensation benchmarking"]', 1, 'Succession planning identifies and develops high-potential employees (''HiPos'') for future leadership roles. Talent review processes typically use 9-box grids (performance vs. potential) to segment the workforce and create targeted development plans for successors.'),
  ('shrm', 'People & Talent', 'Which of the following is a characteristic of Generation Z employees in the workforce?', '["Strong preference for face-to-face communication over digital tools", "No expectation of work-life flexibility since they are digital natives accustomed to working anywhere", "Strong prioritization of purpose-driven work, feedback, job security, and mental health support", "Primarily motivated by retirement benefits and long-term job tenure"]', 2, 'Generation Z (born ~1997-2012) entered the workforce during a period of economic uncertainty. Research shows they value purpose, feedback, mental health support, job security, and flexibility. They are digital-first but also value in-person mentorship.'),
  ('shrm', 'People & Talent', 'What is the primary goal of an Employee Assistance Program (EAP)?', '["To monitor employee productivity and attendance", "To provide confidential counseling and referral services for personal and work-related problems that may affect job performance", "To manage workers'' compensation claims", "To administer employee benefits enrollment"]', 1, 'EAPs provide confidential, short-term counseling, assessment, and referral services for employees dealing with mental health, substance abuse, financial, legal, family, or other personal issues. EAPs are confidential and at no cost to the employee — usage cannot be disclosed to the employer.'),
  ('shrm', 'People & Talent', 'Which learning and development method is MOST effective for developing complex decision-making skills in managers?', '["Online self-paced e-learning modules", "Action learning (real projects with coaching and peer learning groups)", "One-time classroom lecture on decision-making frameworks", "Reading assigned business books"]', 1, 'Action learning addresses real business challenges through a small group with a coach, combining project work with structured reflection. It''s most effective for complex competencies like decision-making because participants immediately apply learning to authentic problems with real stakes.'),
  ('shrm', 'People & Talent', 'An employee claims they were forced to resign because the work environment was so intolerable that no reasonable person would continue. This is known as:', '["Voluntary resignation", "Quid pro quo harassment", "Constructive discharge", "Wrongful termination"]', 2, 'Constructive discharge occurs when an employer makes working conditions so intolerable (through discrimination, harassment, etc.) that a reasonable person in the employee''s position would feel compelled to resign. Courts treat constructive discharge as involuntary termination for legal purposes.'),
  ('shrm', 'People & Talent', 'When calculating cost per hire, which formula is correct?', '["(Internal recruiting costs + External recruiting costs) \u00f7 Total number of hires", "Annual salary of all new hires \u00f7 Total number of hires", "Total HR department budget \u00f7 Total headcount", "Recruiter salary \u00d7 Number of positions filled"]', 0, 'Cost per hire = (Total internal recruiting costs + Total external recruiting costs) / Total number of hires in a period. This metric helps organizations evaluate recruiting efficiency and benchmark against industry standards. SHRM/ANSI standard includes both internal and external costs.'),
  ('shrm', 'HR Strategy', 'The SHRM Competency Model''s Business Acumen competency requires HR professionals to:', '["Focus exclusively on HR technical knowledge and compliance", "Understand organizational operations, finances, and industry to create and execute HR strategy that drives business results", "Manage the HR information system and ensure data accuracy", "Maintain expertise only in compensation and benefits administration"]', 1, 'Business Acumen — understanding the organization''s strategy, operations, competitive environment, and financials — is a core SHRM leadership competency. It enables HR to align people strategies to business goals and demonstrate the strategic value of HR investments.'),
  ('shrm', 'HR Strategy', 'An organization is implementing a new HRIS (Human Resource Information System). What is the MOST important factor in ensuring successful adoption?', '["Selecting the most expensive system with the most features", "Ensuring change management: stakeholder engagement, training, and communication throughout implementation", "Implementing the system as quickly as possible to gain ROI", "Having the IT department lead the entire implementation without HR involvement"]', 1, 'Technology implementation fails primarily due to people, not technology. Change management — engaging stakeholders early, communicating the ''why,'' training users adequately, and addressing resistance — is the most critical factor for HRIS adoption and long-term success.'),
  ('shrm', 'HR Strategy', 'An organization''s HR metrics show high turnover in a key business unit. Using an evidence-based HR approach, what should HR do FIRST?', '["Immediately increase salaries in the affected unit", "Launch a company-wide engagement survey", "Conduct exit interviews, stay interviews, and data analysis to identify root causes before intervening", "Implement a blanket retention bonus for all employees"]', 2, 'Evidence-based HR requires diagnosing before prescribing. Root cause analysis (exit/stay interviews, engagement data, compensation benchmarking, manager effectiveness data) identifies whether the driver is compensation, management, career development, or culture — and informs targeted interventions.'),
  ('shrm', 'HR Strategy', 'What is an Employee Value Proposition (EVP)?', '["The monetary value of an employee''s total compensation package", "The unique set of benefits, culture, and opportunities an organization offers in exchange for the skills, capabilities, and experience employees bring", "A legal document outlining employee rights and organizational expectations", "A performance scorecard linking individual goals to company objectives"]', 1, 'The EVP is the ''deal'' between an organization and its employees — what employees receive (compensation, benefits, culture, development, purpose) in exchange for what they contribute. A compelling, differentiated EVP is the foundation of employer branding and talent attraction strategies.'),
  ('shrm', 'HR Strategy', 'Which HR metric directly measures the effectiveness of the onboarding process?', '["Time to fill", "90-day voluntary turnover rate (new hire turnover)", "Employee Net Promoter Score (eNPS)", "Training hours per employee"]', 1, '90-day (or first-year) voluntary turnover is the most direct indicator of onboarding effectiveness. If new hires leave within 90 days, it suggests misalignment in hiring (job fit, culture fit), inadequate onboarding support, or unmet expectations during the candidate experience.'),
  ('shrm', 'HR Operations', 'An HR professional discovers that a manager has been documenting performance issues for an employee but has not shared the feedback directly with the employee. What should the HR professional advise?', '["Continue documenting quietly in case termination is needed later", "The manager must provide direct, documented feedback to the employee so they have the opportunity to improve \u2014 this is required for progressive discipline to be legally defensible", "File the documentation and terminate the employee based on the undisclosed record", "Transfer the employee to another department to resolve the performance issue"]', 1, 'Progressive discipline requires that employees be clearly informed of performance issues and given the opportunity to improve before termination. Documenting problems without disclosure undermines due process, creates legal exposure, and is fundamentally unfair. Employees must receive feedback and a reasonable opportunity to correct behavior.'),
  ('shrm', 'HR Operations', 'Under which circumstance should an HR professional break confidentiality when an employee discloses information during a private conversation?', '["When a manager requests information about the employee''s personal situation", "When the information is interesting and relevant to a team situation", "When the employee discloses credible threats of harm to themselves or others, or reports illegal activity", "Confidentiality should never be broken under any circumstances"]', 2, 'HR professionals maintain confidentiality as a core ethical obligation, but this is not absolute. Credible threats of violence or harm (to self or others), illegal activity, and workplace safety violations override confidentiality obligations. Employees should be informed of these limits at the outset of sensitive conversations.'),
  ('shrm', 'HR Operations', 'What is the primary purpose of conducting an I-9 (Employment Eligibility Verification) form for new hires?', '["To verify the applicant''s educational credentials and certifications", "To confirm the employee''s tax withholding preferences", "To verify that the employee is authorized to work in the United States under the Immigration Reform and Control Act", "To collect emergency contact information for safety purposes"]', 2, 'The I-9 form, required under IRCA, verifies that every employee hired after November 6, 1986 is legally authorized to work in the United States. Employers must examine acceptable documents proving identity and work authorization within 3 business days of hire. Failure to maintain I-9s results in civil penalties.'),
  ('shrm', 'HR Operations', 'An organization wants to ensure pay equity across gender and race. Which approach provides the most rigorous analysis?', '["Comparing average salaries by department without controlling for other factors", "Conducting a regression analysis controlling for legitimate pay factors (job level, experience, performance) to identify unexplained pay gaps", "Ensuring all employees in the same job title receive identical pay", "Asking managers to self-certify that they have not discriminated in pay decisions"]', 1, 'A multiple regression analysis controls for legitimate differentiating factors (tenure, experience, performance, job level) and isolates unexplained variance attributable to protected characteristics. This is the standard methodology for proactive pay equity analysis and is used in OFCCP audits and litigation.'),
  ('shrm', 'Employment Law', 'Under the FLSA, which test must be met for an employee to qualify for the white-collar overtime exemption (executive, administrative, or professional)?', '["The employee must earn above the federal salary threshold AND primarily perform exempt duties as defined for the specific exemption category", "The employee must work more than 40 hours per week and hold a management title", "Any salaried employee earning above minimum wage is automatically exempt", "The employee must complete an exemption certification form filed with the Department of Labor"]', 0, 'FLSA white-collar exemptions require two components: (1) the salary basis test — earning at or above the federal salary threshold — and (2) the duties test — primarily performing exempt executive, administrative, or professional duties. Title alone is irrelevant. Both tests must be met; failing either means the employee is non-exempt and entitled to overtime.'),
  ('shrm', 'Employment Law', 'The IRS and Department of Labor use multiple factors to determine worker classification. Which factor is MOST indicative that a worker is an employee rather than an independent contractor?', '["The worker uses their own tools and equipment for the job", "The company controls not only the result of the work but also how and when the work is performed", "The worker provides services to multiple clients simultaneously", "The worker sets their own hourly rate for the engagement"]', 1, 'Behavioral and economic control are the key factors. If the company controls the method, schedule, tools, and process of work (not just the final product), the relationship resembles employment. Independent contractors operate their own businesses, set their own methods, bear financial risk, and typically serve multiple clients. Misclassification creates significant tax and benefits liability for employers.'),
  ('shrm', 'Employment Law', 'Under the National Labor Relations Act (NLRA), which employee action is considered protected concerted activity that an employer cannot prohibit or retaliate against?', '["An employee publicly criticizing the company''s products on social media for personal reasons unrelated to working conditions", "Two or more employees discussing their wages with each other to compare pay and address fairness concerns", "An employee filing a personal grievance about their own performance review", "A manager organizing other supervisors to resist an HR policy change"]', 1, 'Concerted activity is protected when two or more employees act together to improve wages, hours, or working conditions. Discussing wages is explicitly protected — policies prohibiting employees from sharing salary information violate the NLRA. Note: supervisors and managers are excluded from NLRA protection. Independent contractors are also not covered.'),
  ('shrm', 'Employment Law', 'The Equal Pay Act (EPA) requires that men and women performing substantially equal work in the same establishment receive equal pay. Which of the following is a valid legal defense against an EPA claim?', '["The employees have different job titles", "The employer claims budgetary constraints limited pay increases for one gender", "A seniority system, merit system, production-based pay system, or any factor other than sex that accounts for the pay difference", "The jobs involve different skills even if they require the same effort"]', 2, 'The EPA affirmative defenses allow pay differences justified by: seniority, merit, quantity or quality of production, or any factor other than sex. The employer bears the burden of proving the defense. The EPA is enforced by the EEOC and has a 2-year statute of limitations (3 years for willful violations).'),
  ('shrm', 'Employment Law', 'Which federal law prohibits employment discrimination based on pregnancy, childbirth, or related medical conditions?', '["Title VII of the Civil Rights Act of 1964 \u2014 which originally included pregnancy as a protected category", "The Pregnancy Discrimination Act (PDA) of 1978 \u2014 which amended Title VII to explicitly include pregnancy discrimination as sex discrimination", "The Family and Medical Leave Act (FMLA) \u2014 which provides leave for pregnancy-related conditions", "The Americans with Disabilities Act (ADA) \u2014 which covers pregnancy-related impairments as disabilities"]', 1, 'The PDA amended Title VII to clarify that discrimination based on pregnancy, childbirth, or related conditions is sex discrimination. The Pregnant Workers Fairness Act (PWFA) of 2023 added a separate requirement for reasonable accommodations for pregnant workers — similar to the ADA interactive process. Both laws are now separately important for SHRM candidates.'),
  ('shrm', 'Employment Law', 'GINA (Genetic Information Nondiscrimination Act) prohibits employers from doing which of the following?', '["Asking employees to undergo genetic testing for health insurance underwriting purposes", "Using an employee''s genetic information (family medical history, genetic test results) in making employment decisions such as hiring, promotion, or termination", "Requiring all applicants to complete a health questionnaire during the pre-employment screening process", "Conducting pre-employment physical examinations before a conditional job offer is made"]', 1, 'GINA prohibits acquiring, using, or disclosing genetic information (including family medical history) in employment decisions. Employers cannot request genetic information from employees or applicants. There are narrow exceptions (voluntary wellness programs with strict safeguards). GINA applies to employers with 15 or more employees.'),
  ('shrm', 'Employment Law', 'Under the Uniformed Services Employment and Reemployment Rights Act (USERRA), what reemployment right does an employee returning from military service have after an absence of less than 91 days?', '["No reemployment rights \u2014 military service is treated as a voluntary resignation", "The employee must reapply for their position and compete with other candidates", "The employee must be promptly reemployed in the same position they left (or a comparable one) with the same seniority, benefits, and pay they would have received had they not been absent", "The employer may reduce the returning employee''s pay by up to 20% to account for the disruption caused by the absence"]', 2, 'USERRA guarantees reemployment rights for returning service members. For service under 91 days, the employee returns to the original position. For longer service, the employer must make reasonable efforts to qualify the employee for the position. Reemployment includes the seniority, benefits, and pay the employee would have earned with continued employment.'),
  ('shrm', 'Employment Law', 'Under COBRA, which employees and dependents are entitled to continued health coverage, and for how long?', '["Only employees terminated for misconduct \u2014 voluntary resigners are not eligible", "Employees (and covered dependents) who lose group health coverage due to a qualifying event (termination, hours reduction, divorce, loss of dependent status) may continue coverage for 18-36 months depending on the qualifying event, at their own expense plus up to 2% admin fee", "COBRA provides coverage for unlimited duration as long as the premium is paid", "COBRA only applies to companies with 100 or more employees"]', 1, 'COBRA applies to employers with 20 or more employees and most group health plans. Qualifying events include termination (other than for gross misconduct), reduction in hours, divorce, death of employee, or dependent aging off the plan. Duration: 18 months for job loss/hours reduction; 36 months for other qualifying events. Employee pays full premium plus 2% administrative fee.'),
  ('shrm', 'Employment Law', 'OSHA requires employers to maintain an OSHA Form 300 (Log of Work-Related Injuries and Illnesses). Which injury type must be recorded on the Form 300?', '["Any injury requiring first aid treatment, regardless of severity", "Work-related injuries and illnesses that result in days away from work, restricted work activity, job transfer, loss of consciousness, diagnosis by a healthcare professional, or medical treatment beyond first aid", "Only injuries requiring hospitalization overnight \u2014 minor injuries are exempt from recording", "All employee health complaints, including work-related stress and minor discomfort"]', 1, 'OSHA 300 recordability criteria: the incident must be work-related AND result in one or more of: death, days away from work, restricted work or job transfer, medical treatment beyond first aid (not just OTC medications), loss of consciousness, or diagnosis of a significant injury by a healthcare professional. The 300 Log must be posted every February 1-April 30.'),
  ('shrm', 'Employment Law', 'An employee is terminated for refusing to falsify sales records as instructed by their supervisor. They sue for wrongful termination. Which exception to at-will employment likely applies?', '["Employment contract exception \u2014 the employee had an implicit promise of job security", "Implied covenant of good faith and fair dealing exception", "Public policy exception \u2014 termination for refusing to engage in an illegal act violates public policy", "Promissory estoppel \u2014 the employer made statements the employee relied on"]', 2, 'The public policy exception prohibits termination for reasons that violate a clear public policy: refusing to engage in illegal activity, exercising a legal right (workers'' comp claim, jury duty), or reporting a legal violation (whistleblowing). Most states recognize this exception. The other at-will exceptions include implied contract (handbook language), covenant of good faith, and promissory estoppel.'),
  ('shrm', 'Employment Law', 'Workers'' compensation is described as an exclusive remedy. What does this mean for employers?', '["Employers have the exclusive right to choose which workers'' comp insurer covers claims", "Employees who receive workers'' comp benefits generally cannot also sue the employer in civil court for negligence related to the same workplace injury \u2014 workers'' comp is the exclusive legal remedy", "Workers'' comp exclusively covers injuries that occur in the company parking lot or building, not during travel", "Exclusive remedy means employees can only file one claim per injury \u2014 they cannot file multiple claims with different insurers"]', 1, 'Workers'' compensation provides no-fault coverage for work-related injuries in exchange for the employee''s right to sue the employer in tort. The trade-off: employees receive guaranteed medical coverage and wage replacement regardless of fault; employers are protected from civil negligence suits. Exceptions exist for intentional employer harm or gross negligence in some states.'),
  ('shrm', 'Employment Law', 'When are non-compete agreements most likely to be enforceable?', '["In all states \u2014 federal law requires all non-compete agreements to be honored", "When they are reasonable in scope (limited to specific business activities), geography (limited to relevant trade area), and duration (typically 6 months to 2 years), and protect a legitimate business interest such as trade secrets or specialized training", "Non-competes are automatically enforceable when signed at the time of employment offer", "They are only enforceable for C-suite executives \u2014 non-competes for lower-level employees are categorically unenforceable"]', 1, 'Non-compete enforceability is governed by state law and varies significantly. Most states require reasonableness in scope, geography, and time, plus a legitimate protectable interest (trade secrets, customer relationships, specialized training). California, Minnesota, North Dakota, and Oklahoma generally refuse to enforce non-competes. The FTC issued a rule in 2024 restricting non-competes — SHRM candidates should note this is an evolving area.'),
  ('shrm', 'Employment Law', 'Under the Sarbanes-Oxley Act (SOX), which employees are protected from retaliation for whistleblowing?', '["Only senior financial officers who directly report to the SEC", "Employees of publicly traded companies who report suspected securities fraud, mail/wire fraud, or violations of SEC rules to the SEC, DOL, or internally through the company", "Any private-sector employee who reports any type of fraud to any government agency", "Only employees who file complaints with the OSHA whistleblower protection program"]', 1, 'SOX Section 806 protects employees of publicly traded companies from retaliation for reporting suspected securities fraud, violations of SEC rules, or federal securities laws. Employees must file complaints with OSHA within 180 days of the retaliation. Dodd-Frank expanded protections for SEC whistleblowers including financial awards for original information.'),
  ('shrm', 'Employment Law', 'Under the Fair Credit Reporting Act (FCRA), when an employer intends to take adverse action (decline to hire, terminate) based on information in a background check report, what steps are required?', '["The employer can take adverse action immediately after receiving the report", "The employer must provide the applicant with a pre-adverse action notice, a copy of the report, and a summary of rights BEFORE taking adverse action \u2014 giving the individual time to dispute inaccuracies", "The employer must file the adverse action decision with the FTC within 30 days", "The background check company must notify the applicant directly \u2014 the employer has no notification obligation"]', 1, 'FCRA requires a two-step adverse action process: (1) Pre-adverse action: provide the candidate the report and summary of rights and allow a reasonable time to dispute errors; (2) Final adverse action notice: if proceeding, provide the name of the consumer reporting agency. This process must occur BEFORE the employment decision is finalized.'),
  ('shrm', 'Employment Law', 'Which of the following employee activities is protected from employer retaliation under federal law?', '["Complaining to a coworker about a supervisor''s management style", "Filing a charge of discrimination with the EEOC, participating in an EEOC investigation, or opposing a discriminatory employment practice", "Refusing to work overtime that is not legally required by the employment contract", "Sharing proprietary company information with a competitor while on a protected leave"]', 1, 'Anti-retaliation provisions exist in virtually all employment laws (Title VII, ADA, ADEA, FMLA, FLSA, etc.). Protected activities include filing charges with enforcement agencies, participating as a witness in investigations, and opposing practices reasonably believed to be discriminatory. Retaliation claims now make up the largest category of EEOC charges filed annually.'),
  ('shrm', 'Employment Law', 'What is the primary purpose of ERISA (Employee Retirement Income Security Act) as it applies to employer-sponsored benefit plans?', '["To require all employers to offer pension plans and health insurance to full-time employees", "To set minimum standards for the administration, funding, vesting, and disclosure of employer-sponsored pension and health benefit plans, protecting employee interests", "To regulate Social Security contributions and Medicare eligibility requirements", "To mandate that retirement plan assets be invested exclusively in U.S. Treasury bonds for safety"]', 1, 'ERISA establishes fiduciary standards, minimum vesting schedules, reporting and disclosure requirements, and participant rights for employer-sponsored pension and health benefit plans. It preempts most state laws regulating employee benefit plans. ERISA plan administrators are fiduciaries who must act solely in participants'' best interests.'),
  ('shrm', 'Employment Law', 'The Office of Federal Contract Compliance Programs (OFCCP) requires federal contractors with 50 or more employees and contracts of $50,000 or more to develop which compliance document?', '["A Diversity, Equity, and Inclusion (DEI) strategic plan filed annually with the DOL", "A written Affirmative Action Plan (AAP) including workforce utilization analysis, placement goals for underrepresented groups, and action-oriented programs", "An annual EEOC Form 1 filed with the Equal Employment Opportunity Commission", "A written harassment prevention policy posted in all work locations and filed with OSHA"]', 1, 'OFCCP enforces Executive Order 11246, Section 503 (disability), and VEVRAA (veterans). Federal contractors meeting the threshold must have a written AAP covering women and minorities (EO 11246), individuals with disabilities (Section 503 — 7% utilization goal), and protected veterans (VEVRAA — 7.2% hiring benchmark). AAPs are updated annually and subject to OFCCP audit.'),
  ('shrm', 'Employment Law', 'An employer monitors employee social media and fires an employee for a post criticizing the company''s new overtime policy. Under what law might this termination be challenged?', '["The Electronic Communications Privacy Act \u2014 employees have a right to private social media use", "The National Labor Relations Act \u2014 posts about wages, hours, or working conditions may constitute protected concerted activity even on personal social media", "The Computer Fraud and Abuse Act \u2014 employers cannot access personal social media accounts without consent", "There is no legal protection for social media posts \u2014 at-will employment applies"]', 1, 'The NLRA protects concerted activity — employees acting together to discuss or improve wages, hours, or working conditions. Social media posts criticizing company work policies can constitute protected concerted activity if they are public complaints about working conditions (especially if others engage). Terminating employees for such posts may constitute an unfair labor practice. Individual gripes unrelated to working conditions are not protected.'),
  ('shrm', 'Employment Law', 'What is a right-to-work law and which federal law governs whether states can enact them?', '["A law guaranteeing every citizen employment \u2014 governed by the Equal Employment Opportunity Act", "A state law that prohibits requiring union membership or payment of union dues as a condition of employment \u2014 permitted by Section 14(b) of the National Labor Relations Act", "A federal law requiring employers to provide a written job description for every position before advertising it", "A state minimum wage law that guarantees workers are paid at least the state minimum rate"]', 1, 'Right-to-work laws prohibit union security clauses (mandatory union dues or membership as a condition of employment). The Taft-Hartley Act of 1947 added Section 14(b) to the NLRA, explicitly allowing states to pass right-to-work laws. Approximately 27 states have right-to-work laws. In union states without RTW, employees can be required to pay agency fees (but not be required to join the union after Janus v. AFSCME).'),
  ('shrm', 'Employment Law', 'Under the FLSA, what is the current federal salary threshold an employee must meet (on a salary basis) to be considered for a white-collar overtime exemption?', '["$455 per week ($23,660 annually) \u2014 the rate set in 2004", "$684 per week ($35,568 annually) \u2014 established in 2019", "The FLSA has no salary threshold \u2014 exemption is determined solely by the duties test", "$1,128 per week ($58,656 annually) \u2014 established in January 2025"]', 1, 'The 2019 rule set $684/week ($35,568/year) as the salary threshold. The Biden DOL finalized an increase to $1,128/week ($58,656/year) effective January 1, 2025 — though this rule faced legal challenges. SHRM candidates should know the most recent effective rate. The key principle: employers must satisfy BOTH the salary basis test AND the duties test for the exemption to apply.'),
  ('shrm', 'Employment Law', 'Under the joint employer doctrine, when might a staffing agency client company be held jointly liable for wage and hour violations affecting temporary workers?', '["Never \u2014 the staffing agency is the sole employer and bears all legal responsibility", "When the client company exercises sufficient control over the essential terms and conditions of employment (scheduling, supervision, work location, work methods) \u2014 both the agency and the client may be joint employers liable for FLSA violations", "Only when the client company signs an explicit co-employer agreement with the staffing agency", "When the temporary worker has been on assignment at the client company for more than 12 consecutive months"]', 1, 'Joint employer status under the FLSA is determined by the economic reality of the relationship — primarily whether the putative employer controls wages, hours, or working conditions. If a client company supervises workers, sets schedules, and determines compensation rates, they may share liability for FLSA violations with the staffing agency. This is particularly relevant for wage theft and overtime claims.'),
  ('shrm', 'Employment Law', 'The Pregnant Workers Fairness Act (PWFA), effective June 2023, differs from the Pregnancy Discrimination Act primarily because it:', '["Provides stronger anti-discrimination protections than the PDA \u2014 the PDA is now superseded", "Requires employers to provide reasonable accommodations for known limitations related to pregnancy, childbirth, or related medical conditions \u2014 even if the employee is not disabled under the ADA", "Extends FMLA leave to 18 weeks specifically for pregnancy-related conditions", "Applies only to federal government employers \u2014 private-sector pregnancy protections remain governed by the PDA"]', 1, 'The PDA protects against discrimination. The PWFA adds an affirmative accommodation obligation — similar to the ADA interactive process — for pregnant employees and those with related limitations. Employers must engage in the interactive process and provide reasonable accommodations unless it causes undue hardship. This is a significant new compliance requirement post-2023.'),
  ('shrm', 'Employment Law', 'The ADA requires employers to engage in an interactive process when an employee requests an accommodation. What does this process require?', '["The employer may approve or deny the accommodation request without discussion, based solely on the written documentation provided", "Both the employer and employee must engage in a good-faith, flexible, interactive dialogue to identify the employee''s functional limitations and explore effective reasonable accommodations without undue hardship", "The employer must provide the exact accommodation requested by the employee \u2014 alternatives are only permissible if the requested accommodation is physically impossible", "The employee must obtain a court order before the employer is required to begin the interactive process"]', 1, 'The ADA interactive process is a two-way collaborative dialogue. The employer is not required to provide the specific accommodation requested — only an effective one. Documentation from a healthcare provider regarding functional limitations may be requested. Failure to engage in the interactive process itself can constitute ADA liability, even if the requested accommodation would have been denied as an undue hardship.'),
  ('shrm', 'Employment Law', 'Using the 4/5ths (80%) rule, an organization reviews selection data. 100 White applicants were tested, and 60 were selected (60% selection rate). 50 Hispanic applicants were tested, and 20 were selected. Is there adverse impact on Hispanic applicants?', '["No \u2014 the selection ratio for Hispanic applicants (40%) exceeds the 30% threshold required by the 4/5ths rule", "Yes \u2014 the Hispanic selection rate (40%) is less than 80% of the White selection rate (60%). 80% of 60% = 48%; since 40% is below 48%, adverse impact exists", "No \u2014 absolute numbers must be used, not rates, and 20 is more than 80% of 50 hired overall", "Yes \u2014 any difference in selection rates between groups automatically constitutes illegal discrimination"]', 1, '4/5ths rule calculation: reference group (highest) selection rate = 60%. 80% of 60% = 48%. Hispanic selection rate = 40/50 = 40%. Since 40% is below the 48% threshold, adverse impact on Hispanic applicants IS indicated. This does not prove intentional discrimination — it triggers further investigation. The employer would need to validate the selection instrument or modify the process.'),
  ('shrm', 'Employment Law', 'The WARN Act requires 60 days advance notice before a plant closing or mass layoff. Which of the following is a recognized exception to the notice requirement?', '["The company is undergoing a merger or acquisition \u2014 no notice is ever required in M&A transactions", "The layoff was caused by natural disaster, an unforeseen business circumstance, or a faltering company seeking capital \u2014 allowing reduced notice with employer providing as much notice as is practicable", "Companies with fewer than 500 employees are entirely exempt from WARN Act requirements", "Notice is only required for permanent layoffs \u2014 temporary furloughs of any duration are exempt from WARN"]', 1, 'WARN Act exceptions: (1) Faltering company — employer was seeking capital/business that would have avoided the layoff and notice would have harmed that effort; (2) Unforeseeable business circumstances — sudden, dramatic change (major customer cancellation); (3) Natural disaster — flood, earthquake, etc. Even with exceptions, the employer must give as much notice as practicable and include the reason notice could not be given.'),
  ('shrm', 'Employment Law', 'Under VEVRAA (Vietnam Era Veterans Readjustment Assistance Act), federal contractors must take affirmative action for which veteran categories?', '["Only Vietnam-era veterans who served between 1964-1975", "Disabled veterans, recently separated veterans (within 3 years of discharge), active duty wartime or campaign badge veterans, and Armed Forces service medal veterans \u2014 with a national hiring benchmark of 7.2%", "Any current or former military personnel regardless of veteran status or era", "Veterans with a service-connected disability rating of 70% or higher only"]', 1, 'VEVRAA covers four protected veteran categories and applies to federal contractors with contracts of $150,000 or more. The 7.2% hiring benchmark means contractors should measure whether at least 7.2% of new hires are protected veterans. Unlike the old VETS-100 form, VEVRAA now requires contractors to invite applicants to self-identify as protected veterans before an offer is made.'),
  ('shrm', 'Employment Law', 'Executive Order 11246 requires federal contractors to take affirmative action. What does affirmative action specifically mean in this context?', '["Setting hiring quotas for minority and female applicants and refusing to consider non-protected candidates for open positions", "Conducting a workforce utilization analysis and, where minorities or women are underrepresented relative to their availability in the labor market, establishing placement goals and implementing action-oriented programs to improve diversity", "Publicly announcing a preference for minority candidates in all job advertisements", "Immediately terminating employees in overrepresented groups to achieve demographic balance"]', 1, 'Affirmative action under EO 11246 (enforced by OFCCP) requires self-assessment: compare the percentage of women/minorities in each job group to their availability in the relevant labor market. Where underrepresentation exists, set aspirational placement goals and implement proactive outreach, targeted recruiting, and internal development — not quotas or preferential treatment.'),
  ('shrm', 'People & Talent', 'An organization wants to reduce first-day anxiety and accelerate time-to-productivity for new hires. Which onboarding best practice is MOST effective?', '["Complete all onboarding paperwork on the first day and assign a manager''s welcome meeting at the end of week 1", "Begin preboarding before the start date (equipment setup, welcome communication, introductions) and structure the first 90 days with clear milestones, assigned buddies, and regular manager check-ins", "Conduct a one-day orientation covering policies, then send new hires to their teams to learn by doing", "Have new hires shadow a peer for two weeks before being assigned any independent work"]', 1, 'Structured onboarding starting before day 1 (preboarding) dramatically reduces new hire anxiety and accelerates productivity. Research shows that effective onboarding improves retention by up to 82% (SHRM). A 90-day structured plan with milestones, buddy assignment, and regular feedback touchpoints is the evidence-based standard for onboarding effectiveness.'),
  ('shrm', 'People & Talent', 'A performance improvement plan (PIP) is MOST effective when it includes which elements?', '["Specific performance deficiencies documented, measurable improvement targets with clear deadlines, defined support resources (coaching, training), and regular check-in meetings with documented progress", "A formal threat of termination in the first paragraph to convey the seriousness of the situation", "Broad, general expectations rather than specific metrics to give the employee flexibility in how they improve", "A confidential note in the HR file that the employee has been placed on a PIP without the employee''s knowledge"]', 0, 'An effective PIP: identifies specific, observable performance gaps; sets SMART improvement goals with realistic deadlines; specifies the support the employer will provide (coaching, training, tools); schedules regular check-ins; and documents all meetings. PIPs serve both as a genuine improvement tool and as documentation for progressive discipline. Employees must be clearly informed of the PIP.'),
  ('shrm', 'People & Talent', 'A job analyst uses the critical incident technique to analyze a customer service representative position. What information does this method collect?', '["A list of required educational credentials and certifications for the position", "Descriptions of specific behaviors that distinguish highly effective from ineffective performance \u2014 gathered from supervisors and incumbents who recall actual workplace incidents", "A statistical analysis of the correlation between selection test scores and job performance ratings", "A quantitative comparison of salary ranges for the position across the industry"]', 1, 'The critical incident technique (CIT) asks managers and job holders to describe specific examples of behaviors that led to notably effective or ineffective outcomes. This yields behaviorally anchored performance examples useful for developing BARS (behaviorally anchored rating scales), structured interview questions, and competency frameworks grounded in real job requirements.'),
  ('shrm', 'People & Talent', 'In the context of selection assessments, what is the difference between reliability and validity?', '["Reliability means a test measures what it is supposed to measure; validity means it produces consistent results", "Reliability is the consistency of a measurement across time and conditions; validity is whether the test actually measures what it claims to measure and predicts job performance", "Reliability measures test-taker satisfaction; validity measures test completion rate", "Both terms mean the same thing \u2014 a reliable test is automatically valid and vice versa"]', 1, 'Reliability = consistency: does the test produce the same results under the same conditions? Validity = accuracy: does the test actually measure the construct intended, and does it predict job performance? A reliable test is necessary but not sufficient for validity — you can have a consistently inaccurate measurement. Content validity, criterion validity (predictive and concurrent), and construct validity are the main types relevant to selection.'),
  ('shrm', 'People & Talent', 'An organization is deciding whether to fill a key engineering vacancy through internal promotion or external recruitment. What is a primary advantage of internal recruitment over external?', '["Internal candidates always have stronger technical skills than external candidates", "Internal recruitment eliminates all onboarding time since the employee already knows the company culture", "Internal recruitment boosts employee morale and retention by demonstrating career advancement opportunities, reduces time-to-productivity, and provides known performance data \u2014 though it may create a backfill vacancy", "Internal recruitment is always faster because the hiring process can bypass standard selection procedures"]', 2, 'Internal recruitment advantages: morale and retention (employees see advancement paths), faster ramp-up (culture and processes are known), lower hiring costs, and known performance record. Disadvantages: creates a backfill vacancy, may bring in groupthink, and may not introduce new skills or perspectives that the role requires. The decision should be based on whether the required competencies and fresh thinking exist internally.'),
  ('shrm', 'People & Talent', 'Which element is MOST important in building a compelling employer brand?', '["Listing the highest possible salary range in every job posting", "Ensuring the stated employee value proposition (EVP) is authentic and consistently reflected in the actual employee experience \u2014 what is promised externally must be lived internally", "Winning as many Best Employer awards as possible through third-party survey submissions", "Posting the most attractive company photos on LinkedIn and Glassdoor"]', 1, 'Employer brand is the external reputation of the company as a place to work. Its effectiveness depends entirely on authenticity — if the stated EVP does not match what employees actually experience, reviews on Glassdoor and word-of-mouth will undermine all external marketing. Internal culture must be built first; then it can be accurately and credibly communicated externally.'),
  ('shrm', 'People & Talent', 'A total rewards strategy encompasses which five components?', '["Salary, bonus, commission, overtime, and equity compensation", "Compensation, benefits, work-life balance, recognition, and career development \u2014 combined into a holistic value proposition that attracts, retains, and engages employees", "Base pay, health insurance, retirement plan, paid time off, and performance bonuses only", "Direct pay, indirect pay, employer contributions, perquisites, and relocation assistance"]', 1, 'The WorldatWork total rewards model includes five elements: compensation (base + variable pay), benefits (health, retirement, perks), work-life effectiveness (flexibility, remote options, wellness), recognition (non-monetary acknowledgment), and development and career opportunities (learning, advancement). Together they form the complete deal between the employer and employee.'),
  ('shrm', 'People & Talent', 'An organization wants to restructure its compensation system from narrow pay grades to broadbanding. What is the primary advantage of a broadband structure?', '["Broadbanding creates clearly defined step increases that make compensation fully transparent and predictable for all employees", "Broadbanding dramatically lowers payroll costs by compressing all job levels into a single pay rate", "Broadbanding provides greater flexibility for lateral moves, career development, and rewarding contributions without requiring promotions \u2014 reducing artificial hierarchical barriers", "Broadbanding eliminates the need for market pay surveys since broad ranges cover all roles automatically"]', 2, 'Broadbanding consolidates many narrow pay grades into fewer, wider bands. Benefits: supports lateral development moves, allows more manager discretion in rewarding contributions, aligns with flatter org structures. Challenges: less clear progression, potential compression issues, requires strong manager training on pay decisions. Narrow pay grades provide more structure and equity but less flexibility.'),
  ('shrm', 'People & Talent', 'An HR analyst conducts a market pricing study for engineering roles. Which data source is most authoritative for establishing competitive pay?', '["Publicly available job postings on Indeed and LinkedIn which list salary ranges", "Third-party compensation surveys from organizations like Radford, Mercer, or Willis Towers Watson that collect actual pay data from participating companies, matched to benchmark jobs by scope and level", "Anonymous employee salary reports submitted to Glassdoor", "Asking peer companies informally what they pay their engineers"]', 1, 'Compensation surveys with statistically reliable, benchmarked data from multiple employers are the gold standard for market pricing. Key considerations: use surveys matched to your industry, geography, and company size; match jobs by scope (not title); use multiple surveys; and age data to the current date using standard escalators. Anonymous crowdsourced sites lack job-matching rigor and are insufficient for compensation decisions.'),
  ('shrm', 'People & Talent', 'According to Gallup''s research on employee engagement, which factor most strongly correlates with team engagement and productivity?', '["Total compensation package relative to market median", "The quality of the manager-employee relationship \u2014 specifically whether employees have a manager who cares about them as people, provides feedback, and sets clear expectations", "Company size \u2014 smaller companies consistently show higher engagement than large enterprises", "Remote work availability \u2014 engagement is highest among fully remote teams"]', 1, 'Gallup''s decades of Q12 research consistently finds that the manager relationship — particularly Q1 (knowing what is expected) and Q2 (having the materials and equipment to do the job right) and perceptions of manager care — is the single strongest predictor of team engagement. Great managers are the primary driver; HR programs play a supporting role.'),
  ('shrm', 'People & Talent', 'Stay interviews differ from exit interviews in which critical way?', '["Stay interviews are conducted annually by the HR department; exit interviews happen only when employees voluntarily resign", "Stay interviews are conducted proactively with CURRENT employees to identify what motivates them to stay and what might cause them to leave \u2014 enabling preemptive retention action; exit interviews collect data after the decision to leave has already been made", "Stay interviews are legally required under FMLA; exit interviews are voluntary", "Exit interviews are more actionable because they reveal the actual reason employees leave; stay interviews are only useful for engagement surveys"]', 1, 'Stay interviews happen before flight risk escalates. By asking current high-performers what they love about their work, what frustrates them, and what could lure them away, managers can act proactively to address issues before they become resignation triggers. Exit interview data is valuable for systemic trend analysis but is too late to retain the individual.'),
  ('shrm', 'People & Talent', 'What is the primary purpose of exit interview data from an HR strategy perspective?', '["Determining whether the departing employee is eligible for rehire", "Identifying systemic patterns in voluntary turnover causes \u2014 by aggregating exit data, HR can surface management issues, compensation gaps, career development deficiencies, or cultural problems driving attrition", "Documenting the legal basis for the employee''s departure for EEOC defense purposes", "Calculating the exact replacement cost for budget forecasting only"]', 1, 'Individual exit interviews provide limited value. Aggregated, trended exit data over time reveals systemic patterns: if 40% of departures in a department cite lack of advancement and poor manager feedback, that is an actionable HR priority. Exit data should be segmented by department, manager, tenure, and role to identify root causes — not treated as individual feedback.'),
  ('shrm', 'People & Talent', 'In a 9-box talent grid, where do employees with high performance AND high potential fall, and what is the typical talent strategy for this group?', '["Box 5 (middle of the grid) \u2014 the strategy is performance management", "Box 9 (upper right, high performance/high potential) \u2014 strategy is accelerated development, stretch assignments, succession planning, and robust retention efforts", "Box 1 (lower left, low performance/low potential) \u2014 strategy is performance management or exit", "Box 3 (upper left, high potential/low performance) \u2014 strategy is coaching and support"]', 1, 'Top-right box 9 employees (high performers AND high potentials — HiPos) represent the talent pipeline for critical roles. The strategy: identify them, develop them aggressively (stretch assignments, mentoring, cross-functional exposure), engage them with career conversations, and retain them with competitive rewards and advancement clarity. Losing HiPos is the highest-cost talent failure.'),
  ('shrm', 'People & Talent', 'An HR business partner notices that a high-performing software engineer has been actively updating their LinkedIn profile and increasing external networking. Which evidence-based retention action should be taken?', '["Monitor the employee''s computer usage and contact their manager to increase workload", "Offer an immediate 10% salary increase without context", "Have the manager conduct a stay interview to understand the employee''s career goals, address any dissatisfaction, and explore internal growth opportunities before external departure occurs", "Take no action \u2014 employee behavior is private and HR should not intervene"]', 2, 'Profile updating and external networking are leading indicators of flight risk. Proactive manager outreach through a stay interview allows the organization to understand the root cause — career development gap, compensation concern, management issue — and address it before the employee accepts an external offer. Once an offer is accepted, retention becomes significantly harder.'),
  ('shrm', 'People & Talent', 'What is the purpose of a Training Needs Analysis (TNA) before designing a learning and development program?', '["To determine which training vendors offer the lowest cost per learner hour", "To identify the specific gap between current employee knowledge, skills, and behaviors and the desired performance level \u2014 ensuring training addresses actual root causes rather than assumed deficiencies", "To comply with mandatory training hour requirements under OSHA and state employment laws", "To calculate the total budget required for the L&D department for the upcoming fiscal year"]', 1, 'TNA diagnoses before prescribing. It involves: organizational analysis (strategic priorities), task analysis (what skills are required for the job), and person analysis (where current performance falls short of standard). Training without TNA often addresses the wrong problem — if a performance gap is caused by lack of motivation or tools, training will not fix it.'),
  ('shrm', 'People & Talent', 'Kirkpatrick''s four-level training evaluation model Level 3 measures which aspect of training effectiveness?', '["Participant reactions to the training \u2014 satisfaction ratings and ''smile sheets''", "Knowledge and skill acquisition \u2014 pre and post-test scores showing what was learned", "Behavior change on the job \u2014 whether participants are applying what they learned back in their work environment 30-90 days after training", "Business results \u2014 whether the training produced measurable organizational outcomes such as increased sales, reduced errors, or lower turnover"]', 2, 'Kirkpatrick Level 3 (Behavior) is the hardest to measure but most practically important — did learning transfer to job performance? This is measured 30-90 days post-training through supervisor observation, performance metrics, and behavioral checklists. Most training programs only measure Level 1 (reaction) and stop there, making ROI demonstration difficult.'),
  ('shrm', 'People & Talent', 'A manager recommends rotating a high-potential analyst through three different department assignments over 18 months. What is the primary talent development benefit of job rotation?', '["It reduces payroll costs by eliminating the need to hire external specialists in each function", "Job rotation builds broad organizational knowledge, cross-functional relationships, and versatile skill sets \u2014 developing well-rounded leaders who understand the business holistically rather than through a single functional lens", "It allows the organization to quickly identify which roles the employee should be permanently removed from", "Job rotation is primarily a retention tactic with no direct impact on skill development"]', 1, 'Job rotation is a high-impact development tool for HiPos. Benefits: broadens business acumen, builds cross-functional networks, develops adaptability, reveals different leadership styles, and prepares employees for general management roles. It also helps the organization identify strengths and potential derailment factors across different contexts and demands.'),
  ('shrm', 'People & Talent', 'How does executive coaching differ from mentoring in a talent development context?', '["They are identical \u2014 coaching and mentoring are interchangeable terms", "Coaching is a structured, goal-directed engagement with a professional coach focused on developing specific competencies or addressing behavioral barriers; mentoring is a relationship with a more experienced colleague focused on career guidance, organizational navigation, and knowledge transfer", "Coaching is exclusively for poor performers; mentoring is exclusively for high-potential employees", "Mentoring is a formal HR program; coaching is an informal personal relationship"]', 1, 'Coaching: professional coach (internal or external), structured engagement, specific behavioral goals, typically time-limited, often confidential. Mentoring: relationship-based, experienced colleague guides less experienced one on career, culture, and navigation, less structured, longer-term. Both are valuable — they serve different development purposes and are often used together in leadership development programs.'),
  ('shrm', 'People & Talent', 'What is the primary risk of a defined benefit (DB) pension plan that makes it less common among private-sector employers today compared to defined contribution (DC) plans?', '["DB plans require employees to make higher personal contributions than DC plans", "DB plans expose the employer to significant investment and longevity risk \u2014 the employer must fund the promised benefit regardless of investment returns or how long retirees live, creating unpredictable long-term liabilities on the balance sheet", "DB plans are prohibited for private-sector employers under ERISA \u2014 only public-sector entities can sponsor them", "DC plans (like 401k) offer lower employer costs but are classified differently by the IRS, making DB plans preferable for most employers"]', 1, 'Defined benefit plans promise a specific retirement income (based on salary and years of service) — the employer bears all investment risk and must fund the plan to cover future obligations. Market downturns create underfunding. Longevity increases liability. This unpredictable long-term obligation is why most private employers have shifted to defined contribution (401k) plans where the employee bears investment risk and employer contribution is predictable.'),
  ('shrm', 'People & Talent', 'Under FMLA, what rights does an employer have when an employee takes intermittent leave for a chronic condition?', '["Employers cannot require any documentation or advance notice for intermittent FMLA leave", "Employers may require medical certification from a healthcare provider, request periodic recertification, require employees to give 30 days advance notice when foreseeable, and transfer the employee temporarily to an equivalent position to accommodate the intermittent leave schedule", "Employers may deny intermittent leave if it disrupts business operations \u2014 business necessity is an affirmative defense to FMLA intermittent leave", "Employers can require employees to exhaust all paid time off before taking unpaid intermittent FMLA leave, with no option to run them concurrently"]', 1, 'Employers have specific rights for intermittent FMLA: require 30-day advance notice when foreseeable, require medical certification (and recertification every 6 months or when circumstances change), temporarily transfer the employee to equivalent alternative duties that accommodate the intermittent schedule, and require intermittent leave be taken in the shortest medically necessary increments. PTO can be required to run concurrently.'),
  ('shrm', 'People & Talent', 'Situational Judgment Tests (SJTs) are used in employee selection to measure what?', '["Technical knowledge required for the specific job (coding, accounting, engineering principles)", "How candidates would respond to realistic work scenarios \u2014 assessing judgment, decision-making, and behavioral tendencies in job-relevant situations", "Physical fitness and ability to perform manual labor requirements", "Language proficiency and communication skills through written response scoring"]', 1, 'SJTs present candidates with realistic work scenarios and ask how they would respond (or how they should respond, or how others should respond). They measure judgment, situational reasoning, and competencies (leadership, conflict resolution, customer service) that are difficult to assess with knowledge tests or interviews alone. SJTs have good predictive validity and relatively low adverse impact compared to cognitive ability tests.'),
  ('shrm', 'People & Talent', 'When would a panel interview be most appropriate in a selection process?', '["When the hiring decision needs to be made the same day and a single interviewer is available", "When HR wants to screen quickly through a large volume of applicants with standardized questions", "When stakeholder buy-in is important, when multiple perspectives on candidate competencies are needed, or when a key leadership role requires consensus among the hiring committee", "Panel interviews are only appropriate for external executive-level candidates \u2014 internal promotions should always use individual interviews"]', 2, 'Panel interviews (multiple interviewers simultaneously) reduce individual interviewer bias, expose candidates to key stakeholders, gather diverse perspectives on competencies, and build organizational commitment to the hiring decision. They are efficient (one candidate session vs. multiple individual interviews) and particularly valuable for leadership roles, team-based environments, and cross-functional positions.'),
  ('shrm', 'HR Strategy', 'The Dave Ulrich HR Business Partner model describes four primary HR roles. Which combination represents the strategic and operational dimensions of HR?', '["Recruiter, Trainer, Benefits Manager, and Compliance Officer", "Strategic Partner (aligning HR strategy with business strategy), Change Agent (managing organizational transformation), Administrative Expert (building efficient HR processes), and Employee Champion (advocating for employee needs and engagement)", "Policy Enforcer, Budget Manager, Headcount Planner, and Legal Advisor", "Chief People Officer, HR Director, HR Manager, and HR Generalist \u2014 the four levels of HR hierarchy"]', 1, 'Ulrich''s 1997 model defines HR''s value creation through four roles: Strategic Partner (future/strategic focus, aligning people strategies with business goals), Change Agent (future/people focus, managing transformation), Administrative Expert (operational/process focus, delivering efficient HR services), and Employee Champion (operational/people focus, supporting employee well-being and engagement).'),
  ('shrm', 'HR Strategy', 'An HR director wants to scan the broader environment before developing the 3-year people strategy. Which analytical framework helps identify external factors across political, economic, social, technological, legal, and environmental dimensions?', '["SWOT analysis \u2014 identifies internal strengths, weaknesses and external opportunities, threats", "PESTLE analysis \u2014 examines macro-environmental factors that will shape workforce and talent strategy", "Balanced Scorecard \u2014 translates strategy into measurable objectives across four perspectives", "Porter''s Five Forces \u2014 analyzes competitive intensity and industry attractiveness"]', 1, 'PESTLE (Political, Economic, Social, Technological, Legal, Environmental) is an environmental scanning tool that helps HR anticipate external forces affecting the workforce. Examples: minimum wage legislation (Political/Legal), unemployment rate (Economic), Gen Z workforce entry trends (Social), AI automation of tasks (Technological), ESG and sustainability pressures (Environmental). PESTLE inputs inform the strategic HR plan.'),
  ('shrm', 'HR Strategy', 'A balanced scorecard approach for HR would include metrics in which four perspectives?', '["Headcount, Turnover, Time-to-Fill, and Training Hours", "Financial (HR cost efficiency and ROI), Customer (manager and employee satisfaction with HR), Internal Process (efficiency of HR processes), and Learning and Growth (HR capability development and innovation)", "Compliance, Talent Acquisition, Compensation, and Employee Relations", "Current performance, historical performance, industry benchmark, and regulatory requirements"]', 1, 'Applying Kaplan and Norton''s Balanced Scorecard to HR: Financial perspective (cost-per-hire, HR ROI, turnover cost); Customer perspective (hiring manager satisfaction, employee engagement scores); Internal Process perspective (time-to-fill, HR transaction accuracy, process cycle times); Learning and Growth perspective (HR team development, HR technology capability). Together they provide a holistic view of HR effectiveness beyond just cost metrics.'),
  ('shrm', 'HR Strategy', 'An organization is implementing a major enterprise system change that requires new processes and behaviors from all employees. HR is leading the change management effort using Prosci''s ADKAR model. What does each letter represent?', '["Assess, Design, Knowledge-share, Align, Review", "Awareness of the need to change, Desire to support the change, Knowledge of how to change, Ability to demonstrate new skills and behaviors, Reinforcement to sustain the change", "Analyze the gap, Develop the plan, Keep stakeholders informed, Align incentives, Review outcomes", "Authority granted, Delegation of tasks, Knowledge documented, Accountability assigned, Results tracked"]', 1, 'ADKAR is an individual-focused change model. Change fails when any element is missing: no Awareness means people don''t understand why; no Desire means they don''t want to; no Knowledge means they don''t know how; no Ability means they can''t execute; no Reinforcement means they revert. HR interventions (communication, training, coaching, incentives) are mapped to the specific ADKAR gap that is blocking adoption.'),
  ('shrm', 'HR Strategy', 'What is workforce planning gap analysis and how does it inform HR strategy?', '["A process for identifying and documenting open positions that need to be filled immediately", "A forward-looking analysis that compares future workforce demand (skills and headcount needed to execute business strategy) against future supply (projected internal availability after attrition and development) to identify talent gaps requiring action", "An annual performance review process identifying employees with skill deficiencies that need training", "A compensation audit comparing current pay rates to market benchmarks to identify pay gaps"]', 1, 'Workforce planning gap analysis: project future demand (what roles and skills will the business need in 3-5 years?), project supply (what will remain after retirements, attrition, and current development plans?), identify the delta. Gaps are addressed through hiring, development, reskilling, or restructuring. Surpluses are addressed through redeployment, natural attrition, or workforce reduction. This drives recruiting strategy, L&D investment, and succession planning.'),
  ('shrm', 'HR Strategy', 'In organizational design, what is span of control, and what factors influence whether a wider or narrower span is appropriate?', '["Span of control is the geographic territory an HR business partner covers \u2014 wider spans exist in global organizations", "Span of control is the number of direct reports a manager oversees. Wider spans (8-12+) are appropriate for routine work, experienced teams, and well-defined processes; narrower spans (4-6) are appropriate for complex, variable work requiring close supervision and coaching", "Span of control refers to the range of HR programs a Chief People Officer oversees \u2014 compensation, benefits, recruiting, L&D, and HR operations", "Span of control is a legal term defining how many employees a company can have before being subject to federal employment laws"]', 1, 'Span of control decisions affect organizational layers, management cost, and employee experience. Wide spans flatten the hierarchy (fewer layers, less overhead, faster decisions) but require strong self-sufficient teams. Narrow spans enable close coaching and complex problem-solving but add cost and can slow decisions. Task complexity, team experience, geographic dispersion, and need for development coaching all affect the optimal span.'),
  ('shrm', 'HR Strategy', 'What is HR''s primary role in driving sustainable organizational culture change?', '["Issuing a revised employee handbook that defines the new desired culture and expecting behavior to change within 90 days", "Ensuring leadership models the desired behaviors consistently \u2014 culture change is 70% leadership role-modeling and 30% HR-led programs; HR''s role is to design systems (hiring criteria, performance metrics, recognition programs) that reinforce the new culture", "Requiring all employees to complete a mandatory culture training module within 30 days", "Creating a culture committee of HR professionals to monitor compliance with cultural norms"]', 1, 'Culture is transmitted and sustained primarily through leadership behavior — what leaders do signals what the organization values more powerfully than any stated values. HR''s role is to design organizational systems that align with the desired culture: recruiting for culture-fit, performance criteria that reward desired behaviors, recognition programs that celebrate culture champions, and leadership development that builds culture-consistent behaviors.'),
  ('shrm', 'HR Strategy', 'An organization is evaluating whether to implement a new HRIS. What factors most predict successful technology adoption?', '["Selecting the most feature-rich and expensive system available ensures the highest ROI", "The speed of implementation \u2014 faster rollouts consistently outperform phased approaches in user adoption", "Change management: stakeholder engagement during selection, clear communication of the why, thorough training before go-live, and sustained support during the transition period", "Selecting a system used by the most companies in the same industry regardless of fit with the organization''s specific needs"]', 2, 'HRIS implementations fail primarily due to people factors, not technology. Success predictors: involving end-users and managers in requirements and selection, communicating the business case clearly, training employees adequately before go-live, having a dedicated change champion, and providing robust post-go-live support. Technical capabilities matter, but change management is the primary determinant of adoption success.'),
  ('shrm', 'HR Strategy', 'During a merger or acquisition, what is HR''s primary due diligence responsibility BEFORE the deal closes?', '["Selecting the combined organization''s new HR software and payroll vendor", "Conducting HR due diligence: assessing the target company''s workforce, compensation structures, benefit plans, employment contracts, pending litigation, cultural differences, and key talent retention risks \u2014 informing deal valuation and integration planning", "Announcing the merger to both workforces and managing public relations around the transaction", "Immediately harmonizing both organizations'' compensation and benefit plans to a single standard"]', 1, 'HR due diligence in M&A is critical. It uncovers: hidden liabilities (discrimination lawsuits, WARN Act obligations), compensation and benefit plan integration costs, key talent flight risk (golden parachutes, non-solicitation agreements), cultural misalignment, and union issues. These findings can affect deal valuation and shape integration priorities. Post-close HR integration is driven by pre-close due diligence findings.'),
  ('shrm', 'HR Strategy', 'What is the purpose of HR benchmarking in strategic HR planning?', '["Comparing the organization''s headcount to the industry average to identify whether the company is over or understaffed", "Evaluating HR metrics (cost-per-hire, turnover rate, time-to-fill, HR-to-employee ratio) against industry peers and best-in-class organizations to identify performance gaps and set improvement targets", "Conducting salary surveys to determine whether the HR team itself is paid competitively", "Benchmarking measures only historical performance \u2014 it provides no input for future HR strategy"]', 1, 'Benchmarking provides external reference points for HR performance. SHRM''s HR Benchmarking database and industry-specific surveys enable HR to answer: Are our metrics competitive? Where are we outperforming or lagging? What do top-quartile organizations do differently? Benchmarking drives prioritization of HR investment and enables evidence-based business cases to leadership.'),
  ('shrm', 'HR Strategy', 'What does applying Agile principles to HR mean in practice?', '["HR eliminates all policies and procedures to become more flexible and responsive", "HR adopts software development terminology (sprints, standups) exclusively without changing underlying HR processes", "HR shifts from annual, waterfall cycles (once-a-year performance reviews, annual workforce plans) to iterative, continuous processes with fast feedback loops, cross-functional collaboration, and rapid adjustment to changing business conditions", "Agile HR applies only to recruiting \u2014 other HR functions remain traditional"]', 2, 'Agile HR translates Agile software values to people management: continuous performance conversations (not annual reviews), rolling workforce plans updated quarterly, iterative HR product development with end-user feedback, cross-functional HR delivery teams, and rapid prototyping of people programs before full-scale rollout. It prioritizes responsiveness to business change over adherence to rigid annual HR calendars.'),
  ('shrm', 'HR Strategy', 'Total Cost of Workforce (TCW) is a more comprehensive measure than total payroll. What does TCW include that payroll alone does not?', '["TCW and payroll are identical \u2014 both include only base salary and overtime", "TCW includes all direct compensation (base, bonus, overtime) AND all indirect workforce costs: benefits (healthcare, retirement), employer taxes (FICA, FUTA), recruiting costs, training costs, onboarding costs, and productivity loss from vacancies and turnover \u2014 providing a true picture of workforce investment", "TCW is used only for workforce reduction decisions and does not inform positive workforce investment strategies", "TCW includes executive compensation only \u2014 frontline worker costs are tracked separately under headcount analysis"]', 1, 'TCW is the total investment an organization makes in its workforce, beyond the paycheck. When organizations understand that voluntary turnover can cost 1.5-2x annual salary per departure (recruiting, lost productivity, onboarding), the ROI on retention investments becomes clear. TCW analysis informs decisions about where to invest in total rewards, development, and engagement to optimize workforce productivity relative to total cost.'),
  ('shrm', 'HR Strategy', 'What distinguishes a leading HR metric from a lagging HR metric?', '["Leading metrics are more accurate; lagging metrics contain reporting errors from manual data collection", "Leading metrics predict future outcomes (engagement scores, manager effectiveness ratings, learning participation rates) and allow proactive intervention; lagging metrics report past outcomes (turnover rate, time-to-fill, absenteeism) after the fact", "Lagging metrics are used for compliance reporting; leading metrics are only used for executive dashboards", "There is no meaningful difference \u2014 all HR metrics are equally predictive of future workforce outcomes"]', 1, 'Lagging metrics measure what already happened — turnover rate, cost-per-hire, absenteeism. Useful for trend analysis but not for prevention. Leading metrics predict what is likely to happen — declining engagement scores predict future turnover; declining training participation predicts skill gaps; declining manager effectiveness ratings predict team performance issues. A mature HR analytics program uses both, with leading metrics enabling early intervention.'),
  ('shrm', 'HR Operations', 'How long must employers retain Form I-9 after an employee is hired or separated from employment?', '["For the entire duration of employment plus 1 year after separation", "Three years from the date of hire OR one year after the date of employment ends \u2014 whichever is LATER", "I-9 forms must be maintained permanently \u2014 there is no legal destruction date", "Forms must be transferred to the National Records Center within 30 days of separation"]', 1, 'I-9 retention formula: retain for 3 years from date of hire OR 1 year after the employment ends, WHICHEVER IS LATER. Example: employee hired Jan 1, 2020 and separated June 1, 2022 — three years from hire = Jan 1, 2023; one year after separation = June 1, 2023. Retain until June 1, 2023. I-9s must be stored separately from personnel files and be available for ICE/DHS audit on 3 days'' notice.'),
  ('shrm', 'HR Operations', 'What is role-based access control (RBAC) in an HRIS context, and why is it important for HR data security?', '["RBAC allows all HR team members to access all employee data for cross-functional efficiency", "RBAC assigns system access rights based on the employee''s role \u2014 payroll staff see compensation data, recruiters see applicant data, managers see direct report data only \u2014 ensuring users see only the data necessary for their function, reducing unauthorized access risk", "RBAC is a scheduling tool that rotates which HR staff members have system administrator privileges each week", "RBAC is a compliance framework required by GDPR only for organizations with EU-based employees"]', 1, 'RBAC limits the blast radius of data breaches, prevents unauthorized access to sensitive compensation or medical data, and supports audit trails showing who accessed what. In HRIS, RBAC ensures payroll administrators cannot access recruitment data, managers cannot see peer compensation data, and employees can only see their own records. It is foundational to HR data privacy compliance under GDPR, HIPAA, and state privacy laws.'),
  ('shrm', 'HR Operations', 'Under the FLSA, which statement about pay period requirements is correct?', '["The FLSA mandates that all employees be paid on a weekly basis", "The FLSA does not specify pay frequency \u2014 state law governs pay period requirements (weekly, biweekly, semimonthly, monthly) \u2014 but the FLSA requires that all wages be paid on regularly scheduled paydays", "The FLSA requires employees to receive their first paycheck within 7 days of hire regardless of the established pay period", "The FLSA prohibits paying non-exempt employees on a semimonthly basis because overtime calculations require weekly periods"]', 1, 'The FLSA is silent on pay frequency — states regulate how often employees must be paid (many states require at minimum biweekly or semimonthly pay). The FLSA does require regular, predictable paydays and that all earned wages be paid without unauthorized deductions. Overtime must be calculated on a workweek basis (7 consecutive days) regardless of the pay period length.'),
  ('shrm', 'HR Operations', 'A Section 125 cafeteria plan allows employees to do which of the following?', '["Take unlimited pre-tax deductions for any personal expenses including student loans and gym memberships", "Select among qualified benefit options (health insurance premiums, FSAs, dependent care FSAs) using pre-tax payroll deductions, reducing their federal taxable income", "Contribute unlimited amounts to a health savings account (HSA) without IRS annual limits", "Defer salary into a retirement account with employer matching on a pre-tax basis under ERISA Section 401(k)"]', 1, 'A Section 125 cafeteria plan allows employees to pay for eligible benefits (medical/dental/vision premiums, FSA contributions, dependent care FSAs) with pre-tax dollars, reducing both employee income tax and FICA taxes. The employer also saves FICA on the deducted amounts. Benefits must be IRS-qualified. Non-qualified benefits (gym memberships, personal items) cannot be included in a Section 125 plan.'),
  ('shrm', 'HR Operations', 'When drafting a job description for ADA compliance purposes, why is it critical to distinguish between essential and marginal job functions?', '["ADA compliance requires listing all job duties regardless of how rarely they are performed", "Only essential functions must be listed on the job description \u2014 marginal functions are legally prohibited from appearing in any employment document", "Essential functions are the fundamental duties an employee must be able to perform with or without a reasonable accommodation. Marginal functions cannot be used to disqualify a qualified person with a disability \u2014 the ADA only requires accommodation for inability to perform essential functions", "Marginal functions require higher pay under FLSA \u2014 identifying them separately prevents wage claims from employees who perform them"]', 2, 'If a function is listed as essential and a person with a disability cannot perform it even with accommodation, the employer may lawfully decline to hire or retain them for that role. If a function is marginal, the employer must attempt reasonable accommodation before using inability to perform it as a basis for an employment decision. Factors determining essential: time spent, consequences of not performing, limited workforce to perform the function.'),
  ('shrm', 'HR Operations', 'An employee handbook disclaimer stating that the handbook is not a contract and employment is at will is important for which legal reason?', '["It allows the employer to terminate employees without paying unemployment benefits", "It prevents employees from arguing that handbook language created an implied employment contract that limits the employer''s ability to terminate \u2014 preserving at-will employment status under the implied contract exception", "It provides the employer with sovereign immunity from all employment discrimination claims", "The disclaimer has no legal significance \u2014 handbooks are always contracts under common law"]', 1, 'Several courts have found that handbook language promising progressive discipline or job security can create an implied contract of employment, eroding at-will status. A clear, prominent disclaimer stating the handbook is not a contract, employment is at-will, and policies may change at any time without notice preserves the employer''s ability to make employment decisions consistent with at-will principles.'),
  ('shrm', 'HR Operations', 'An employee in California is terminated without cause on a Friday. Under California state law (one of the strictest), when must the employer provide the final paycheck?', '["Within 72 hours of separation, consistent with federal FLSA requirements", "At the time of termination \u2014 California requires immediate payment of all earned wages including accrued vacation upon involuntary termination", "Within the next regular pay period after separation", "Within 3 business days, allowing time for payroll processing"]', 1, 'California Labor Code Section 201 requires that employees who are involuntarily terminated must receive their final paycheck immediately at the time of discharge, including all accrued, unused vacation pay. Violations trigger waiting time penalties: one day''s wages per day late, up to 30 days. State final paycheck laws vary significantly — some states allow 72 hours, others the next regular payday. SHRM candidates should know state law typically governs timing.'),
  ('shrm', 'HR Operations', 'An employer hires a delivery driver without conducting any background check. The driver later assaults a customer during a delivery. Under which legal theory might the employer be held liable?', '["Respondeat superior \u2014 because the assault occurred during employment, the employer is automatically liable regardless of the hiring process", "Negligent hiring \u2014 employers have a duty to exercise reasonable care in selecting employees for positions where they will have contact with customers, the public, or vulnerable populations; failure to discover a foreseeable risk creates liability", "Strict liability \u2014 employers are always liable for the criminal acts of their employees", "Negligent supervision only \u2014 the employer is only liable if they knew of the risk after hiring and failed to address it"]', 1, 'Negligent hiring holds employers liable when they knew or should have known that an employee posed a foreseeable risk based on information a reasonable background check would have revealed. For positions with customer contact, access to homes, or work with vulnerable populations, a background check that would have uncovered prior relevant criminal history is the standard of care. HR must implement appropriate background check policies matched to the risk level of each position.');
